def _now_iso() -> str:
    return _now_utc().isoformat()


def _now_utc() -> datetime:
    return datetime.now(timezone.utc)


def _future_iso(hours: int) -> str:
    return (_now_utc() + timedelta(hours=hours)).isoformat()


def _future_iso_minutes(minutes: int) -> str:
    return (_now_utc() + timedelta(minutes=minutes)).isoformat()


def _parse_iso_datetime(value: Any) -> datetime | None:
    if not value:
        return None
    try:
        parsed = datetime.fromisoformat(str(value).replace("Z", "+00:00"))
    except ValueError:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed


def _bool_from(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    if isinstance(value, str):
        return value.strip().lower() in {"1", "true", "yes", "on", "enabled"}
    return False


def _time_parts(value: Any, fallback: tuple[int, int]) -> tuple[int, int]:
    raw = _string_from(value)
    if not raw:
        return fallback
    match = re.fullmatch(r"([01]?\d|2[0-3]):([0-5]\d)", raw)
    if not match:
        return fallback
    return int(match.group(1)), int(match.group(2))


def _business_days(value: Any) -> set[int]:
    default = {0, 1, 2, 3, 4}
    if not isinstance(value, list):
        return default
    days: set[int] = set()
    names = {
        "mon": 0,
        "monday": 0,
        "tue": 1,
        "tuesday": 1,
        "wed": 2,
        "wednesday": 2,
        "thu": 3,
        "thursday": 3,
        "fri": 4,
        "friday": 4,
        "sat": 5,
        "saturday": 5,
        "sun": 6,
        "sunday": 6,
    }
    for item in value:
        if isinstance(item, int) and 0 <= item <= 6:
            days.add(item)
            continue
        raw = _string_from(item).lower()
        if raw.isdigit() and 0 <= int(raw) <= 6:
            days.add(int(raw))
        elif raw in names:
            days.add(names[raw])
    return days or default


def _business_timezone(value: Any) -> ZoneInfo:
    raw = _string_from(value) or "UTC"
    try:
        return ZoneInfo(raw)
    except ZoneInfoNotFoundError:
        return ZoneInfo("UTC")


def _business_hours_target_at(minutes: int, business_hours: dict[str, Any]) -> datetime:
    clean_minutes = max(1, int(minutes or 1))
    if not _bool_from(business_hours.get("enabled")):
        return _now_utc() + timedelta(minutes=clean_minutes)

    tz = _business_timezone(business_hours.get("timezone"))
    start_hour, start_minute = _time_parts(
        business_hours.get("start") or business_hours.get("startTime") or business_hours.get("start_time"),
        (9, 0),
    )
    end_hour, end_minute = _time_parts(
        business_hours.get("end") or business_hours.get("endTime") or business_hours.get("end_time"),
        (17, 0),
    )
    if (end_hour, end_minute) <= (start_hour, start_minute):
        return _now_utc() + timedelta(minutes=clean_minutes)

    open_days = _business_days(business_hours.get("days") or business_hours.get("weekdays"))
    cursor = _now_utc().astimezone(tz)
    remaining = timedelta(minutes=clean_minutes)

    for _ in range(370):
        day_start = cursor.replace(hour=start_hour, minute=start_minute, second=0, microsecond=0)
        day_end = cursor.replace(hour=end_hour, minute=end_minute, second=0, microsecond=0)
        if cursor.weekday() not in open_days:
            cursor = (cursor + timedelta(days=1)).replace(hour=0, minute=0, second=0, microsecond=0)
            continue
        if cursor < day_start:
            cursor = day_start
        if cursor >= day_end:
            cursor = (cursor + timedelta(days=1)).replace(hour=0, minute=0, second=0, microsecond=0)
            continue

        available = day_end - cursor
        if remaining <= available:
            return (cursor + remaining).astimezone(timezone.utc)
        remaining -= available
        cursor = (cursor + timedelta(days=1)).replace(hour=0, minute=0, second=0, microsecond=0)

    return _now_utc() + timedelta(minutes=clean_minutes)


def _parse(value: Any, expected_type: type) -> Any:
    if isinstance(value, expected_type):
        return value
    if value and isinstance(value, str):
        try:
            parsed = json.loads(value)
            if isinstance(parsed, expected_type):
                return parsed
        except json.JSONDecodeError:
            pass
    return expected_type()


def _workflow_status(status: str) -> str:
    return WORKFLOW_STATUS_ALIASES.get((status or "").strip().lower(), "open")


def _canonical_status(status: str) -> str:
    return _workflow_status(status)


def _status_filter(status: str) -> str:
    clean = (status or "").strip().lower()
    if not clean or clean == "all":
        return ""
    if clean in OPERATIONAL_ISSUE_FILTERS:
        return ""
    values = WORKFLOW_STATUS_FILTERS.get(clean, (clean,))
    if len(values) == 1:
        return f"status='{_escape_pb(values[0])}'"
    return "(" + " || ".join(f"status='{_escape_pb(value)}'" for value in values) + ")"


def _is_all_filter(value: str, all_values: set[str]) -> bool:
    clean = _string_from(value).strip().lower()
    return not clean or clean in all_values


def _record_custom_field_text(rec: dict[str, Any]) -> list[str]:
    metadata = _parse(rec.get("metadata"), dict)
    custom_fields = _parse(metadata.get("customFields") or metadata.get("custom_fields"), dict)
    parts: list[str] = []
    for key, value in custom_fields.items():
        parts.append(_string_from(key))
        if isinstance(value, (list, tuple, set)):
            parts.extend(_string_from(item) for item in value)
        elif isinstance(value, dict):
            parts.extend(_string_from(item) for item in value.values())
        else:
            parts.append(_string_from(value))
    return [part for part in parts if part]


def _issue_record_search_text(rec: dict[str, Any]) -> str:
    parts = [
        rec.get("subject"),
        rec.get("from_address"),
        rec.get("account_name"),
        rec.get("account_domain"),
        rec.get("contact_email"),
        rec.get("contact_name"),
        rec.get("queue_name"),
        rec.get("queue_key"),
        rec.get("channel"),
        rec.get("source"),
        rec.get("activated_intent"),
        rec.get("ai_summary"),
        *_tags_from(rec.get("tags")),
        *_record_custom_field_text(rec),
    ]
    return " ".join(_string_from(part) for part in parts if _string_from(part)).lower()


def _issue_matches_account_filter(rec: dict[str, Any], account_key: str) -> bool:
    clean = _string_from(account_key).strip().lower()
    if _is_all_filter(clean, {"all", "__all_accounts__"}):
        return True
    account_id = _string_from(rec.get("account") or rec.get("accountId")).lower()
    account_name = _string_from(rec.get("account_name") or rec.get("accountName")).lower()
    account_domain = _string_from(rec.get("account_domain") or rec.get("accountDomain")).lower()
    if clean in {"__no_account__", "none", "no_account"}:
        return not account_id and not account_name and not account_domain
    if clean.startswith("id:"):
        return account_id == clean.removeprefix("id:")
    if clean.startswith("label:"):
        expected = clean.removeprefix("label:")
        return account_name == expected or account_domain == expected
    return clean in {account_id, account_name, account_domain}


def _issue_matches_channel_filter(rec: dict[str, Any], channel: str) -> bool:
    clean = _string_from(channel).strip().lower()
    if _is_all_filter(clean, {"all", "__all_channels__"}):
        return True
    issue_channel = _string_from(rec.get("channel")).lower()
    if clean in {"__no_channel__", "none", "no_channel"}:
        return not issue_channel
    return issue_channel == clean


def _issue_matches_assignee_filter(rec: dict[str, Any], assignee_email: str) -> bool:
    clean = _string_from(assignee_email).strip().lower()
    if _is_all_filter(clean, {"all", "__all_assignees__"}):
        return True
    issue_assignee = _string_from(rec.get("assignee_email") or rec.get("assigneeEmail")).lower()
    if clean in {"__unassigned__", "unassigned", "none", "no_assignee"}:
        return not issue_assignee
    return issue_assignee == clean


def _issue_matches_tag_filter(rec: dict[str, Any], tag: str) -> bool:
    clean = _string_from(tag).strip().lower()
    if _is_all_filter(clean, {"all", "__all_tags__"}):
        return True
    tags = {item.lower() for item in _tags_from(rec.get("tags"))}
    if clean in {"__no_tags__", "none", "no_tags"}:
        return not tags
    return clean in tags


def _issue_matches_inbox_filters(
    rec: dict[str, Any],
    *,
    account_key: str = "",
    channel: str = "",
    assignee_email: str = "",
    tag: str = "",
    query: str = "",
) -> bool:
    clean_query = _string_from(query).strip().lower()
    return (
        _issue_matches_account_filter(rec, account_key)
        and _issue_matches_channel_filter(rec, channel)
        and _issue_matches_assignee_filter(rec, assignee_email)
        and _issue_matches_tag_filter(rec, tag)
        and (not clean_query or clean_query in _issue_record_search_text(rec))
    )


def _issue_matches_operational_filter(issue: dict[str, Any], status: str) -> bool:
    clean = (status or "").strip().lower()
    if clean not in OPERATIONAL_ISSUE_FILTERS:
        return True
    if clean == "needs-response":
        return bool(issue.get("needsResponse"))
    if clean == "approvals":
        return bool(issue.get("hasPendingApproval")) or int(issue.get("pendingApprovalCount") or 0) > 0
    if clean == "reply-approvals":
        return bool(issue.get("hasPendingReplyApproval")) or int(issue.get("pendingReplyApprovalCount") or 0) > 0
    if clean == "action-approvals":
        return bool(issue.get("hasPendingActionApproval")) or int(issue.get("pendingActionApprovalCount") or 0) > 0
    if clean == "unassigned":
        return not _string_from(issue.get("assigneeEmail"))
    if clean == "failed-delivery":
        return bool(issue.get("hasFailedDelivery")) or int(issue.get("failedDeliveryCount") or 0) > 0
    if clean == "low-csat":
        return bool(issue.get("hasLowCsatFeedback")) or int(issue.get("lowCsatFeedbackCount") or 0) > 0
    if clean in {"overdue-sla", "due-soon-sla"} and _canonical_status(_string_from(issue.get("status")) or "open") == "done":
        return False
    if clean == "overdue-sla":
        return bool(issue.get("hasOverdueSla")) or int(issue.get("overdueSlaCount") or 0) > 0
    if clean == "due-soon-sla":
        if _issue_matches_operational_filter(issue, "overdue-sla"):
            return False
        target = _parse_iso_datetime(issue.get("nextSlaTargetAt"))
        if not target:
            return False
        now = _now_utc()
        return now <= target <= now + timedelta(hours=1)
    return True


def _record_from(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


def _string_from(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, str):
        return value.strip()
    if isinstance(value, (int, float, bool)):
        return str(value)
    return ""


def _key_from(value: str) -> str:
    cleaned = " ".join((value or "").strip().lower().split())
    return cleaned[:300]


def _stable_record_id(*parts: str) -> str:
    logical_key = "\x1f".join(_string_from(part) for part in parts)
    return hashlib.sha256(logical_key.encode("utf-8")).hexdigest()[:15]


def _queue_key_from(value: Any) -> str:
    raw = _string_from(value).lower()
    if not raw:
        return ""
    return re.sub(r"[^a-z0-9._:-]+", "-", raw).strip("-")[:120]


def _queue_name_from(queue_key: str, queue_name: Any = "") -> str:
    clean_name = _string_from(queue_name)
    if clean_name:
        return clean_name[:200]
    clean_key = _string_from(queue_key)
    if not clean_key:
        return ""
    return clean_key.replace("-", " ").replace("_", " ").title()[:200]


def _tags_from(value: Any) -> list[str]:
    raw_items = value if isinstance(value, list) else str(value or "").replace("\n", ",").split(",")
    tags: list[str] = []
    seen: set[str] = set()
    for item in raw_items:
        tag = " ".join(_string_from(item).split())[:64]
        key = tag.lower()
        if not tag or key in seen:
            continue
        seen.add(key)
        tags.append(tag)
        if len(tags) >= 20:
            break
    return tags


CUSTOM_FIELD_TYPES = {"text", "number", "select", "boolean", "date", "url"}


def _custom_field_key(value: Any) -> str:
    raw = _string_from(value).lower()
    cleaned: list[str] = []
    previous_dash = False
    for ch in raw:
        if ch.isalnum():
            cleaned.append(ch)
            previous_dash = False
        elif not previous_dash:
            cleaned.append("_")
            previous_dash = True
    return "".join(cleaned).strip("_")[:64]


def _custom_field_options(value: Any) -> list[str]:
    raw_items = value if isinstance(value, list) else str(value or "").replace("\n", ",").split(",")
    options: list[str] = []
    for item in raw_items:
        if isinstance(item, dict):
            option = _string_from(item.get("value") or item.get("label") or item.get("name"))
        else:
            option = _string_from(item)
        if option and option not in options:
            options.append(option[:120])
    return options[:50]


def _custom_field_definitions_from_metadata(metadata: dict[str, Any]) -> list[dict[str, Any]]:
    raw_definitions = metadata.get("customFields") or metadata.get("custom_fields") or []
    if not isinstance(raw_definitions, list):
        return []
    definitions: list[dict[str, Any]] = []
    seen: set[str] = set()
    for raw in raw_definitions:
        if not isinstance(raw, dict):
            continue
        label = _string_from(raw.get("label") or raw.get("name") or raw.get("key"))
        key = _custom_field_key(raw.get("key") or label)
        if not key or key in seen:
            continue
        field_type = _string_from(raw.get("type") or "text").lower()
        if field_type not in CUSTOM_FIELD_TYPES:
            field_type = "text"
        definitions.append({
            "key": key,
            "label": label or key.replace("_", " ").title(),
            "type": field_type,
            "required": bool(raw.get("required")),
            "options": _custom_field_options(raw.get("options")),
        })
        seen.add(key)
    return definitions[:30]


def _custom_field_definitions(
    *,
    tenant_id: str | None,
    project_id: str,
) -> list[dict[str, Any]]:
    policy = get_sla_policy(tenant_id=tenant_id, project_id=project_id)
    return _custom_field_definitions_from_metadata(_parse(policy.get("metadata"), dict))


def _custom_fields_from_issue(issue: dict[str, Any]) -> dict[str, Any]:
    direct = issue.get("customFields") or issue.get("custom_fields")
    if isinstance(direct, dict):
        return direct
    metadata = _parse(issue.get("metadata"), dict)
    return _parse(metadata.get("customFields") or metadata.get("custom_fields"), dict)


def _normalize_custom_field_value(value: Any, definition: dict[str, Any] | None) -> Any:
    field_type = _string_from((definition or {}).get("type") or "text")
    if value is None:
        return None
    if field_type == "boolean":
        if isinstance(value, bool):
            return value
        return _string_from(value).lower() in {"1", "true", "yes", "on"}
    if field_type == "number":
        if isinstance(value, (int, float)) and not isinstance(value, bool):
            return value
        clean = _string_from(value)
        if not clean:
            return None
        try:
            number = float(clean)
        except ValueError as exc:
            raise ValueError(f"Custom field {definition.get('label') if definition else ''} must be a number") from exc
        return int(number) if number.is_integer() else number
    clean_value = _string_from(value)
    if not clean_value:
        return None
    if field_type == "select" and definition:
        options = _custom_field_options(definition.get("options"))
        if options and clean_value not in options:
            raise ValueError(f"Custom field {definition['label']} must be one of: {', '.join(options)}")
    return clean_value[:500]


def _normalize_custom_field_values(
    values: Any,
    *,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    raw_values = values if isinstance(values, dict) else {}
    definitions = _custom_field_definitions(tenant_id=tenant_id, project_id=project_id)
    definitions_by_key = {definition["key"]: definition for definition in definitions}
    normalized: dict[str, Any] = {}
    for raw_key, raw_value in raw_values.items():
        key = _custom_field_key(raw_key)
        if not key:
            continue
        if definitions_by_key and key not in definitions_by_key:
            raise ValueError(f"Unknown custom field: {raw_key}")
        value = _normalize_custom_field_value(raw_value, definitions_by_key.get(key))
        if value is not None:
            normalized[key] = value
    for definition in definitions:
        if definition.get("required") and definition["key"] not in normalized:
            raise ValueError(f"Custom field {definition['label']} is required")
    return normalized


def _normalize_custom_field_patch_values(
    values: Any,
    *,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    raw_values = values if isinstance(values, dict) else {}
    definitions = _custom_field_definitions(tenant_id=tenant_id, project_id=project_id)
    definitions_by_key = {definition["key"]: definition for definition in definitions}
    normalized: dict[str, Any] = {}
    for raw_key, raw_value in raw_values.items():
        key = _custom_field_key(raw_key)
        if not key:
            continue
        if definitions_by_key and key not in definitions_by_key:
            raise ValueError(f"Unknown custom field: {raw_key}")
        value = _normalize_custom_field_value(raw_value, definitions_by_key.get(key))
        if value is not None:
            normalized[key] = value
    return normalized


def _merge_custom_field_values(current: dict[str, Any], patch: Any) -> dict[str, Any]:
    if not isinstance(patch, dict):
        return dict(current)
    merged = dict(current)
    for raw_key, raw_value in patch.items():
        key = _custom_field_key(raw_key)
        if not key:
            continue
        if raw_value is None or _string_from(raw_value) == "":
            merged.pop(key, None)
        else:
            merged[key] = raw_value
    return merged


def _first_string(data: dict[str, Any], keys: tuple[str, ...]) -> str:
    for key in keys:
        value = _string_from(data.get(key))
        if value:
            return value
    for nested_key in ("account", "customer", "company", "contact", "data"):
        nested = data.get(nested_key)
        if isinstance(nested, dict):
            value = _first_string(nested, keys)
            if value:
                return value
    return ""


def _sender_email(from_address: str) -> str:
    parsed = parseaddr(from_address or "")[1]
    return (parsed or from_address or "").strip()


def _sender_domain(from_address: str) -> str:
    sender = _sender_email(from_address)
    if "@" not in sender:
        return ""
    return sender.rsplit("@", 1)[-1].lower()


def _response_content(messages: list[dict[str, Any]]) -> dict[str, Any]:
    for message in reversed(messages):
        if message.get("user") != "response":
            continue
        content = message.get("content")
        if isinstance(content, dict):
            return content
    return {}


def _content_body(content: Any) -> str:
    if isinstance(content, str):
        return content
    if isinstance(content, dict):
        return _string_from(content.get("emailBody") or content.get("email_body") or content.get("responseText"))
    return ""


def _draft_reply(messages: list[dict[str, Any]]) -> str:
    content = _response_content(messages)
    return _content_body(content)


def _email_body(messages: list[dict[str, Any]]) -> str:
    for message in messages:
        if message.get("user") == "email":
            return _string_from(message.get("content"))
    return ""


def _clip(value: str, limit: int = 600) -> str:
    compact = " ".join(value.split())
    if len(compact) <= limit:
        return compact
    return f"{compact[: limit - 3]}..."


def _identity_fields(identity_result: dict[str, Any], from_address: str) -> dict[str, str]:
    data = _record_from(identity_result.get("data"))
    contact_email = (
        _first_string(data, ("email", "contactEmail", "contact_email", "sender_email"))
        or _sender_email(from_address)
    )
    account_name = _first_string(
        data,
        (
            "accountName",
            "account_name",
            "companyName",
            "company_name",
            "company",
            "organization",
            "organisation",
            "customerName",
            "customer_name",
            "name",
        ),
    )
    contact_name = _first_string(data, ("contactName", "contact_name", "fullName", "full_name", "personName", "name"))
    account_domain = (
        _first_string(data, ("domain", "accountDomain", "account_domain", "companyDomain", "website"))
        or _sender_domain(from_address)
    )
    return {
        "account_name": account_name,
        "account_domain": account_domain,
        "contact_email": contact_email,
        "contact_name": contact_name if contact_name != account_name else "",
    }


def _account_key(identity: dict[str, str]) -> str:
    return (
        _key_from(identity["account_domain"])
        or _key_from(identity["account_name"])
        or _key_from(_sender_domain(identity["contact_email"]))
        or _key_from(identity["contact_email"])
    )


def _contact_key(identity: dict[str, str]) -> str:
    return _key_from(identity["contact_email"] or identity["contact_name"])


def _upsert_account(
    *,
    identity: dict[str, str],
    identity_data: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any] | None:
    key = _account_key(identity)
    if not key:
        return None
    filter_str = _issue_filter(
        tenant_id=tenant_id,
        project_id=project_id,
        extra=f"account_key='{_escape_pb(key)}'",
    )
    existing = _first("support_accounts", filter_str)
    data: dict[str, Any] = {
        "account_key": key,
        "name": identity["account_name"],
        "domain": identity["account_domain"],
        "external_id": _first_string(identity_data, ("accountId", "account_id", "customerId", "customer_id", "id")),
        "health_status": "unknown",
        "metadata": identity_data,
        "latest_issue_at": _now_iso(),
    }
    if existing:
        _patch(f"/api/collections/support_accounts/records/{existing['id']}", data)
        return {**existing, **data}

    create_data = {"id": generate_id(), **data, "issue_count": 0}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _post("/api/collections/support_accounts/records", create_data)


def _upsert_contact(
    *,
    identity: dict[str, str],
    identity_data: dict[str, Any],
    account_id: str,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any] | None:
    key = _contact_key(identity)
    if not key:
        return None
    filter_str = _issue_filter(
        tenant_id=tenant_id,
        project_id=project_id,
        extra=f"contact_key='{_escape_pb(key)}'",
    )
    existing = _first("support_contacts", filter_str)
    data: dict[str, Any] = {
        "contact_key": key,
        "account": account_id,
        "email": identity["contact_email"],
        "name": identity["contact_name"],
        "external_id": _first_string(identity_data, ("contactId", "contact_id", "personId", "person_id", "id")),
        "metadata": identity_data,
        "latest_issue_at": _now_iso(),
    }
    if existing:
        _patch(f"/api/collections/support_contacts/records/{existing['id']}", data)
        return {**existing, **data}

    create_data = {"id": generate_id(), **data, "issue_count": 0}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _post("/api/collections/support_contacts/records", create_data)


def _refresh_account_contact_counts(
    *,
    account_id: str | None,
    contact_id: str | None,
    tenant_id: str | None,
    project_id: str,
) -> None:
    for collection, record_id, field_name in (
        ("support_accounts", account_id, "account"),
        ("support_contacts", contact_id, "contact"),
    ):
        if not record_id:
            continue
        records = _list_all(
            "support_issues",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"{field_name}='{_escape_pb(record_id)}'",
            ),
            sort="-latest_message_at",
            per_page=200,
        )
        records = [rec for rec in records if not _merged_into_issue_id(rec)]
        latest = records[0].get("latest_message_at") if records else ""
        _patch(
            f"/api/collections/{collection}/records/{record_id}",
            {
                "issue_count": len(records),
                "latest_issue_at": latest or _now_iso(),
            },
        )


def _priority(
    *,
    requires_human: bool,
    phishing_result: dict[str, Any] | None,
    prompt_injection_result: dict[str, Any] | None,
) -> str:
    risk_levels = {
        _string_from(_record_from(phishing_result).get("riskLevel") or _record_from(phishing_result).get("risk_level")),
        _string_from(
            _record_from(prompt_injection_result).get("riskLevel")
            or _record_from(prompt_injection_result).get("risk_level")
        ),
    }
    if "high" in risk_levels:
        return "urgent"
    if requires_human:
        return "high"
    return "normal"


def _intent_action_groups(intent_result: dict[str, Any] | None) -> list[dict[str, Any]]:
    """Return concern-scoped actions, falling back to the legacy primary list."""
    result = _record_from(intent_result)
    concerns = result.get("concerns")
    groups: list[dict[str, Any]] = []
    if isinstance(concerns, list):
        for index, raw_concern in enumerate(concerns[:10]):
            concern = _record_from(raw_concern)
            outcome = _record_from(
                concern.get("outcome")
                or concern.get("runbookOutcome")
                or concern.get("runbook_outcome")
            )
            actions = outcome.get("actions") or concern.get("actions")
            if not isinstance(actions, list):
                continue
            runbook = _string_from(
                concern.get("intentName")
                or concern.get("intent_name")
                or concern.get("runbook")
                or outcome.get("intentName")
                or outcome.get("intent_name")
                or outcome.get("runbook")
            )
            if not runbook:
                continue
            groups.append(
                {
                    "concernId": _string_from(
                        concern.get("concernId")
                        or concern.get("concern_id")
                        or concern.get("id")
                    )
                    or f"concern-{index + 1}",
                    "runbook": runbook,
                    "actions": actions,
                }
            )
    if groups:
        return groups
    actions = result.get("actions")
    if not isinstance(actions, list):
        return []
    return [
        {
            "concernId": "primary",
            "runbook": _string_from(result.get("intentName") or result.get("intent_name")),
            "actions": actions,
        }
    ]


def _action_log(intent_result: dict[str, Any] | None) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    for group in _intent_action_groups(intent_result):
        for action in group["actions"]:
            if not isinstance(action, dict):
                continue
            label = _string_from(action.get("label") or action.get("name") or action.get("type"))
            if not label:
                continue
            entries.append(
                {
                    "label": label,
                    "type": _string_from(action.get("type") or "button"),
                    "status": "available",
                    "concernId": group["concernId"],
                    "runbook": group["runbook"],
                }
            )
    return entries


def _runbook_action_proposals(intent_result: dict[str, Any] | None) -> list[dict[str, Any]]:
    proposals: list[dict[str, Any]] = []
    for group in _intent_action_groups(intent_result):
        for action in group["actions"]:
            if not isinstance(action, dict):
                continue
            if "enabled" in action and not _bool_from(action.get("enabled")):
                continue
            name = _string_from(action.get("name"))
            label = _string_from(action.get("label") or name)
            action_type = _string_from(action.get("type") or "button").lower()
            separate_call = _bool_from(action.get("separateCall") or action.get("separate_call"))
            if action_type != "button" and not separate_call:
                continue
            webhook = _string_from(action.get("webhook"))
            if not name or not label or not webhook:
                continue
            payload = dict(_record_from(action.get("payload")))
            payload.update(
                {
                    "actionName": name,
                    "actionLabel": label,
                    "concernId": group["concernId"],
                    "runbook": group["runbook"],
                }
            )
            initial_value = _string_from(action.get("initialValue") or action.get("initial_value"))
            if initial_value:
                payload[name] = initial_value
            proposals.append(
                {
                    "type": "runbook_webhook",
                    "name": name,
                    "label": label,
                    "actionType": action_type,
                    "webhook": webhook,
                    "method": _string_from(action.get("method") or "POST").upper(),
                    "payload": payload,
                    "query": _record_from(action.get("query")),
                    "body": _record_from(action.get("body")),
                    "headers": _record_from(action.get("headers")),
                    "concernId": group["concernId"],
                    "runbook": group["runbook"],
                }
            )
    merged: list[dict[str, Any]] = []
    proposal_indexes: dict[str, int] = {}
    for proposal in proposals:
        is_open_ticket = (
            _string_from(proposal.get("name")).lower().replace("-", "_")
            == "open_ticket"
        )
        proposal_payload = _record_from(proposal.get("payload"))
        action_name = _string_from(proposal.get("name"))
        action_payload_keys = {
            action_name,
            action_name.lower().replace("-", "_"),
        }
        static_payload = {
            key: value
            for key, value in proposal_payload.items()
            if key not in {
                *action_payload_keys,
                "actionLabel",
                "actionName",
                "concernId",
                "concernIds",
                "runbook",
            }
        }
        merge_payload = static_payload if is_open_ticket else {
            key: value
            for key, value in proposal_payload.items()
            if key not in {"concernId", "concernIds"}
        }
        merge_key = _runbook_action_proposal_fingerprint(
            proposal,
            payload=merge_payload,
        )
        existing_index = proposal_indexes.get(merge_key)
        if existing_index is None:
            proposal_indexes[merge_key] = len(merged)
            merged.append(proposal)
            continue

        existing = merged[existing_index]
        concern_ids = list(
            dict.fromkeys(
                [
                    *(_parse(existing.get("concernIds"), list) or []),
                    _string_from(existing.get("concernId")),
                    _string_from(proposal.get("concernId")),
                ]
            )
        )
        concern_ids = [_string_from(value) for value in concern_ids if _string_from(value)]
        existing["concernIds"] = concern_ids
        existing_payload = _record_from(existing.get("payload"))
        incoming_payload = _record_from(proposal.get("payload"))
        if is_open_ticket:
            action_name = _string_from(existing.get("name"))
            action_payload_key = action_name.lower().replace("-", "_")
            tasks = list(
                dict.fromkeys(
                    value
                    for value in (
                        _string_from(
                            existing_payload.get(action_name)
                            or existing_payload.get(action_payload_key)
                        ),
                        _string_from(
                            incoming_payload.get(action_name)
                            or incoming_payload.get(action_payload_key)
                        ),
                    )
                    if value
                )
            )
            if tasks:
                existing_payload[action_payload_key] = "\n\n".join(tasks)[:4_000]
        existing_payload["concernIds"] = concern_ids
        existing["payload"] = existing_payload
    return merged


def _runbook_action_proposal_fingerprint(
    proposed_action: dict[str, Any],
    *,
    payload: dict[str, Any] | None = None,
) -> str:
    """Hash one action's executable configuration without message/concern scope."""

    clean_payload = dict(
        _record_from(proposed_action.get("payload"))
        if payload is None
        else payload
    )
    clean_payload.pop("concernId", None)
    clean_payload.pop("concernIds", None)
    canonical = {
        "type": _string_from(proposed_action.get("type")),
        "name": _string_from(proposed_action.get("name")),
        "label": _string_from(proposed_action.get("label")),
        "actionType": _string_from(proposed_action.get("actionType")),
        "webhook": _string_from(proposed_action.get("webhook")),
        "method": _string_from(proposed_action.get("method")).upper(),
        "payload": clean_payload,
        "query": _record_from(proposed_action.get("query")),
        "body": _record_from(proposed_action.get("body")),
        "headers": _record_from(proposed_action.get("headers")),
        "runbook": _string_from(proposed_action.get("runbook")),
    }
    encoded = json.dumps(
        canonical,
        ensure_ascii=False,
        sort_keys=True,
        separators=(",", ":"),
        default=str,
    )
    return hashlib.sha256(encoded.encode("utf-8")).hexdigest()


def _runbook_action_scope_values(
    proposed_action: dict[str, Any],
    metadata: dict[str, Any] | None = None,
) -> list[str]:
    clean_metadata = metadata or {}
    return list(
        dict.fromkeys(
            clean_value
            for raw_value in (
                *(_parse(clean_metadata.get("concernIds"), list) or []),
                _string_from(clean_metadata.get("concernId")),
                *(_parse(proposed_action.get("concernIds"), list) or []),
                _string_from(proposed_action.get("concernId")),
            )
            if (clean_value := _string_from(raw_value))
        )
    )


def _runbook_action_record_matches(
    record: dict[str, Any],
    *,
    proposal_fingerprint: str,
) -> bool:
    metadata = _parse(record.get("metadata"), dict)
    result = _parse(record.get("result"), dict)
    existing_proposal = _record_from(
        result.get("proposedAction") or metadata.get("proposedAction")
    )
    return bool(
        existing_proposal
        and _runbook_action_proposal_fingerprint(existing_proposal)
        == proposal_fingerprint
    )


def _pending_runbook_action_matches(
    record: dict[str, Any],
    *,
    proposal_fingerprint: str,
) -> bool:
    metadata = _parse(record.get("metadata"), dict)
    return bool(
        _string_from(record.get("status")).lower() == "pending"
        and metadata.get("approvalRequired") is True
        and metadata.get("approved") is not True
        and _string_from(metadata.get("reviewStatus")).lower() in {"", "pending"}
        and _runbook_action_record_matches(
            record,
            proposal_fingerprint=proposal_fingerprint,
        )
    )


def _merge_pending_runbook_action_scope(
    record: dict[str, Any],
    *,
    proposed_action: dict[str, Any],
    proposal_fingerprint: str,
    source_message_id: str,
) -> dict[str, Any]:
    """Move an equivalent pending approval to the latest message without duplicating it."""

    metadata = _parse(record.get("metadata"), dict)
    result = _parse(record.get("result"), dict)
    existing_proposal = dict(
        _record_from(result.get("proposedAction") or metadata.get("proposedAction"))
    )
    concern_ids = list(
        dict.fromkeys(
            [
                *_runbook_action_scope_values(existing_proposal, metadata),
                *_runbook_action_scope_values(proposed_action),
            ]
        )
    )
    explicit_concern_ids = bool(
        _parse(metadata.get("concernIds"), list)
        or _parse(existing_proposal.get("concernIds"), list)
        or _parse(proposed_action.get("concernIds"), list)
    )
    merged_concern_ids = concern_ids if explicit_concern_ids or len(concern_ids) > 1 else []
    source_message_ids = list(
        dict.fromkeys(
            clean_value
            for raw_value in (
                *(_parse(metadata.get("sourceMessageIds"), list) or []),
                _string_from(metadata.get("sourceMessageId")),
                source_message_id,
            )
            if (clean_value := _string_from(raw_value))
        )
    )
    latest_concern_id = _string_from(proposed_action.get("concernId")) or _string_from(
        metadata.get("concernId")
    )

    existing_payload = dict(_record_from(existing_proposal.get("payload")))
    if latest_concern_id:
        existing_proposal["concernId"] = latest_concern_id
        existing_payload["concernId"] = latest_concern_id
    if merged_concern_ids:
        existing_proposal["concernIds"] = merged_concern_ids
        existing_payload["concernIds"] = merged_concern_ids
    existing_proposal["payload"] = existing_payload

    merged_metadata = {
        **metadata,
        "sourceMessageId": source_message_id,
        "sourceMessageIds": source_message_ids,
        "concernId": latest_concern_id,
        "concernIds": merged_concern_ids,
        "proposalFingerprint": proposal_fingerprint,
        "proposedAction": existing_proposal,
    }
    merged_result = {**result, "proposedAction": existing_proposal}
    if merged_metadata == metadata and merged_result == result:
        return record
    patched = _patch(
        f"/api/collections/support_action_executions/records/{_string_from(record.get('id'))}",
        {"metadata": merged_metadata, "result": merged_result},
    )
    return {**record, **patched}


def _prepare_runbook_action_approvals(
    *,
    issue_id: str,
    intent_result: dict[str, Any] | None,
    source_message_id: str,
    tenant_id: str | None,
    project_id: str,
) -> list[dict[str, Any]]:
    prepared: list[dict[str, Any]] = []
    proposals = _runbook_action_proposals(intent_result)
    pending_candidates = (
        _list_all(
            "support_action_executions",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=(
                    f"issue='{_escape_pb(issue_id)}' && "
                    "status='pending'"
                ),
            ),
            sort="-created",
        )
        if proposals
        else []
    )
    for proposed_action in proposals:
        concern_id = _string_from(proposed_action.get("concernId")) or "primary"
        runbook = _string_from(proposed_action.get("runbook")) or "runbook"
        proposal_fingerprint = _runbook_action_proposal_fingerprint(proposed_action)
        action_key = _key_from(
            f"runbook:{source_message_id}:{concern_id}:{runbook}:"
            f"{_string_from(proposed_action.get('name'))}"
        )
        existing = _first(
            "support_action_executions",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=(
                    f"issue='{_escape_pb(issue_id)}' && "
                    f"action_key='{_escape_pb(action_key)}'"
                ),
            ),
        )
        if existing and not _runbook_action_record_matches(
            existing,
            proposal_fingerprint=proposal_fingerprint,
        ):
            existing = None
        if not existing and len(proposals) == 1:
            # Resume pre-multi-concern partial runs without preparing the same
            # business action under the newer concern-scoped key.
            legacy_action_key = _key_from(
                f"runbook:{source_message_id}:{_string_from(proposed_action.get('name'))}"
            )
            existing = _first(
                "support_action_executions",
                _issue_filter(
                    tenant_id=tenant_id,
                    project_id=project_id,
                    extra=(
                        f"issue='{_escape_pb(issue_id)}' && "
                        f"action_key='{_escape_pb(legacy_action_key)}'"
                    ),
                ),
            )
            if existing and not _runbook_action_record_matches(
                existing,
                proposal_fingerprint=proposal_fingerprint,
            ):
                existing = None
        if not existing:
            existing = next(
                (
                    record
                    for record in pending_candidates
                    if _pending_runbook_action_matches(
                        record,
                        proposal_fingerprint=proposal_fingerprint,
                    )
                ),
                None,
            )
        if existing:
            if _pending_runbook_action_matches(
                existing,
                proposal_fingerprint=proposal_fingerprint,
            ):
                existing = _merge_pending_runbook_action_scope(
                    existing,
                    proposed_action=proposed_action,
                    proposal_fingerprint=proposal_fingerprint,
                    source_message_id=source_message_id,
                )
            prepared.append(_normalize_action_execution(existing))
            continue
        execution = create_issue_action_execution(
            issue_id,
            tenant_id=tenant_id,
            project_id=project_id,
            requested_by="automation",
            action_key=action_key,
            label=_string_from(proposed_action.get("label")),
            action_type="runbook_webhook",
            status="pending",
            result={
                "summary": "Runbook action ready for approval",
                "proposedAction": proposed_action,
            },
            metadata={
                "source": "runbook",
                "approvalRequired": True,
                "approved": False,
                "reviewStatus": "pending",
                "sourceMessageId": source_message_id,
                "sourceMessageIds": [source_message_id] if source_message_id else [],
                "concernId": concern_id,
                "concernIds": _parse(proposed_action.get("concernIds"), list),
                "runbook": runbook,
                "runbookAction": _string_from(proposed_action.get("name")),
                "proposedAction": proposed_action,
                "proposalFingerprint": proposal_fingerprint,
            },
            idempotency_key=(
                f"runbook:{issue_id}:{source_message_id}:{proposal_fingerprint}"
            ),
        )
        if execution:
            if _pending_runbook_action_matches(
                execution,
                proposal_fingerprint=proposal_fingerprint,
            ):
                execution = _merge_pending_runbook_action_scope(
                    execution,
                    proposed_action=proposed_action,
                    proposal_fingerprint=proposal_fingerprint,
                    source_message_id=source_message_id,
                )
            prepared.append(execution)
    return prepared


def _ai_summary(
    *,
    subject: str,
    from_address: str,
    activated_intent: str,
    requires_human: bool,
    messages: list[dict[str, Any]],
) -> str:
    draft = _draft_reply(messages)
    body = _email_body(messages)
    status = "Human review required." if requires_human else "Draft reply ready."
    intent = activated_intent or "No runbook matched"
    evidence = draft or body
    return _clip(f"{status} {intent}. {subject}. From {from_address}. {evidence}", 700)


def _issue_filter(
    *,
    tenant_id: str | None,
    project_id: str,
    extra: str = "",
) -> str:
    parts = [f"project='{_escape_pb(project_id)}'"]
    if tenant_id:
        parts.append(f"tenant='{_escape_pb(tenant_id)}'")
    if extra:
        parts.append(extra)
    return " && ".join(parts)


def _clean_issue_ids(issue_ids: list[str]) -> list[str]:
    return list(dict.fromkeys(
        clean_id
        for issue_id in issue_ids
        if (clean_id := _string_from(issue_id))
    ))


def _list_all_by_issue_ids(
    collection: str,
    issue_ids: list[str],
    *,
    tenant_id: str | None,
    project_id: str,
    sort: str,
    per_page: int,
    extra: str = "",
) -> list[dict[str, Any]]:
    """List issue-scoped records without exceeding PocketBase filter URL limits."""
    clean_ids = _clean_issue_ids(issue_ids)
    records: list[dict[str, Any]] = []
    for offset in range(0, len(clean_ids), _ISSUE_ID_FILTER_CHUNK_SIZE):
        chunk = clean_ids[offset:offset + _ISSUE_ID_FILTER_CHUNK_SIZE]
        issue_filter = " || ".join(
            f"issue='{_escape_pb(issue_id)}'" for issue_id in chunk
        )
        chunk_extra = f"({issue_filter})"
        if extra:
            chunk_extra = f"{chunk_extra} && ({extra})"
        records.extend(_list_all(
            collection,
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=chunk_extra,
            ),
            sort=sort,
            per_page=per_page,
        ))
    return records


def _issue_by_id(
    issue_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any] | None:
    clean_id = _string_from(issue_id)
    if not clean_id:
        return None
    return _first(
        "support_issues",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"id='{_escape_pb(clean_id)}'",
        ),
    )


def _merged_into_issue_id(rec: dict[str, Any] | None) -> str:
    if not rec:
        return ""
    return _string_from(rec.get("merged_into_issue") or rec.get("mergedIntoIssueId"))


def _issue_is_terminal_or_merged(rec: dict[str, Any] | None) -> bool:
    if not rec:
        return True
    status = _string_from(rec.get("status") or rec.get("workflowStatus")).lower()
    return (
        _canonical_status(status) == "done"
        or status in {"cancelled", "canceled"}
        or bool(_merged_into_issue_id(rec))
    )


def _resolve_merged_issue_record(
    rec: dict[str, Any] | None,
    *,
    tenant_id: str | None,
    project_id: str,
) -> tuple[dict[str, Any] | None, bool]:
    target_id = _merged_into_issue_id(rec)
    if not rec or not target_id or target_id == _string_from(rec.get("id")):
        return rec, False
    target = _issue_by_id(target_id, tenant_id=tenant_id, project_id=project_id)
    return (target, True) if target else (rec, False)


def _normalize_issue(rec: dict[str, Any], *, messages: list[dict[str, Any]] | None = None) -> dict[str, Any]:
    action_log = _parse(rec.get("action_log"), list)
    status = _canonical_status(_string_from(rec.get("status")) or "open")
    metadata = _parse(rec.get("metadata"), dict)
    custom_fields = _parse(metadata.get("customFields") or metadata.get("custom_fields"), dict)
    result = {
        "id": rec.get("id", ""),
        "accountId": rec.get("account", ""),
        "contactId": rec.get("contact", ""),
        "sourceEmailId": rec.get("source_email_id", ""),
        "chatRecordId": rec.get("chat", ""),
        "chatId": rec.get("source_email_id", ""),
        "status": status,
        "workflowStatus": status,
        "priority": rec.get("priority", "normal"),
        "assigneeEmail": rec.get("assignee_email", ""),
        "queueKey": rec.get("queue_key", ""),
        "queueName": rec.get("queue_name", ""),
        "tags": _tags_from(rec.get("tags")),
        "accountName": rec.get("account_name", ""),
        "accountDomain": rec.get("account_domain", ""),
        "contactEmail": rec.get("contact_email", ""),
        "contactName": rec.get("contact_name", ""),
        "subject": rec.get("subject", ""),
        "fromAddress": rec.get("from_address", ""),
        "channel": rec.get("channel", "email"),
        "source": rec.get("source", "addin"),
        "aiSummary": rec.get("ai_summary", ""),
        "activatedIntent": rec.get("activated_intent", ""),
        "requiresHuman": bool(rec.get("requires_human", False)),
        "pendingApprovalCount": 0,
        "hasPendingApproval": False,
        "pendingReplyApprovalCount": 0,
        "hasPendingReplyApproval": False,
        "pendingActionApprovalCount": 0,
        "hasPendingActionApproval": False,
        "failedDeliveryCount": 0,
        "hasFailedDelivery": False,
        "pendingDeliveryCount": 0,
        "hasPendingDelivery": False,
        "csatFeedbackCount": 0,
        "lowCsatFeedbackCount": 0,
        "hasLowCsatFeedback": False,
        "latestCsatRating": 0,
        "latestCsatComment": "",
        "latestCsatReceivedAt": "",
        "overdueSlaCount": 0,
        "hasOverdueSla": False,
        "nextSlaTargetAt": "",
        "nextSlaEventType": "",
        "needsResponse": False,
        "latestMessageDirection": "",
        "latestCustomerMessageAt": "",
        "latestAgentMessageAt": "",
        "duplicateSuggestionCount": 0,
        "topDuplicateScore": 0,
        "topDuplicateIssueId": "",
        "topDuplicateIssueSubject": "",
        "duplicateReasons": [],
        "messageCount": int(rec.get("message_count") or 0),
        "actionLog": action_log,
        "metadata": metadata,
        "customFields": custom_fields,
        "latestMessageAt": rec.get("latest_message_at") or rec.get("updated") or rec.get("created") or "",
        "mergedIntoIssueId": _string_from(rec.get("merged_into_issue")),
        "mergedAt": rec.get("merged_at") or "",
        "mergedBy": rec.get("merged_by") or "",
        "mergeNote": rec.get("merge_note") or "",
        "created": rec.get("created", ""),
        "updated": rec.get("updated", ""),
    }
    if messages is not None:
        result["messages"] = messages
        if messages and "body" in messages[0]:
            result["draftReply"] = next(
                (
                    _string_from(message.get("body"))
                    for message in reversed(messages)
                    if message.get("direction") == "ai"
                ),
                "",
            )
        else:
            result["draftReply"] = _draft_reply(messages)
    return result


def _message_occurred_at(rec: dict[str, Any]) -> str:
    return _string_from(rec.get("occurred_at") or rec.get("occurredAt") or rec.get("created") or rec.get("updated"))


def _message_response_summary_from_records(
    records: list[dict[str, Any]],
    *,
    issue_status: str = "open",
) -> dict[str, Any]:
    latest_message_direction = ""
    latest_message_at: datetime | None = None
    latest_message_at_raw = ""
    latest_customer_at: datetime | None = None
    latest_customer_at_raw = ""
    latest_agent_at: datetime | None = None
    latest_agent_at_raw = ""

    for rec in records:
        direction = _string_from(rec.get("direction"))
        occurred_raw = _message_occurred_at(rec)
        occurred_at = _parse_iso_datetime(occurred_raw)
        if not occurred_at:
            continue
        if latest_message_at is None or occurred_at >= latest_message_at:
            latest_message_at = occurred_at
            latest_message_at_raw = occurred_raw
            latest_message_direction = direction
        if direction in CUSTOMER_MESSAGE_DIRECTIONS and (latest_customer_at is None or occurred_at >= latest_customer_at):
            latest_customer_at = occurred_at
            latest_customer_at_raw = occurred_raw
        if direction in AGENT_MESSAGE_DIRECTIONS and (latest_agent_at is None or occurred_at >= latest_agent_at):
            latest_agent_at = occurred_at
            latest_agent_at_raw = occurred_raw

    status = _canonical_status(issue_status or "open")
    needs_response = (
        status != "done"
        and latest_customer_at is not None
        and (latest_agent_at is None or latest_customer_at > latest_agent_at)
    )
    return {
        "needsResponse": needs_response,
        "latestMessageDirection": latest_message_direction,
        "latestCustomerMessageAt": latest_customer_at_raw,
        "latestAgentMessageAt": latest_agent_at_raw,
        "latestMessageAt": latest_message_at_raw,
    }


def _message_response_summary_by_issue(
    issues: list[dict[str, Any]],
    *,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, dict[str, Any]]:
    issue_ids = _clean_issue_ids([
        _string_from(issue.get("id")) for issue in issues
    ])
    if not issue_ids:
        return {}
    records = _list_all_by_issue_ids(
        "support_messages",
        issue_ids,
        tenant_id=tenant_id,
        project_id=project_id,
        sort="occurred_at",
        per_page=max(200, min(len(issue_ids) * 20, 1000)),
    )
    grouped: dict[str, list[dict[str, Any]]] = {}
    for rec in records:
        grouped.setdefault(_string_from(rec.get("issue")), []).append(rec)
    by_status = {
        _string_from(issue.get("id")): _canonical_status(_string_from(issue.get("status")) or "open")
        for issue in issues
    }
    return {
        issue_id: _message_response_summary_from_records(
            grouped.get(issue_id, []),
            issue_status=by_status.get(issue_id, "open"),
        )
        for issue_id in issue_ids
    }


def _reply_needs_approval(rec: dict[str, Any]) -> bool:
    metadata = _parse(rec.get("metadata"), dict)
    if metadata.get("approvalRequired") is not True or metadata.get("approved") is True:
        return False
    if _string_from(metadata.get("reviewStatus")) == "changes_requested":
        return False
    return _string_from(rec.get("status")) not in {"sent", "failed"}


def _reply_has_requested_changes(rec: dict[str, Any]) -> bool:
    metadata = _parse(rec.get("metadata"), dict)
    return (
        _string_from(rec.get("status")) == "draft"
        and _string_from(metadata.get("reviewStatus")) == "changes_requested"
    )


def _has_no_response_resolution(metadata: dict[str, Any]) -> bool:
    resolution = _record_from(metadata.get("responseResolution"))
    return (
        _string_from(resolution.get("outcome")) == "no_response_required"
        and bool(_string_from(resolution.get("reason")))
        and bool(_string_from(resolution.get("resolvedAt")))
    )


def _reply_has_failed_delivery(rec: dict[str, Any]) -> bool:
    return _string_from(rec.get("status")) in {"failed", "delivery_uncertain"}


def _reply_has_pending_delivery(rec: dict[str, Any]) -> bool:
    return _string_from(rec.get("status")) in {"queued", "sending"}


def _action_execution_needs_approval(rec: dict[str, Any]) -> bool:
    metadata = _parse(rec.get("metadata"), dict)
    if _string_from(rec.get("status")) != "pending":
        return False
    if metadata.get("approvalRequired") is not True:
        return False
    return _string_from(metadata.get("reviewStatus") or "pending") == "pending"


def _approval_summary_from_outbound(
    outbound_messages: list[dict[str, Any]],
    action_executions: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    pending_reply_count = sum(1 for rec in outbound_messages if _reply_needs_approval(rec))
    pending_action_count = sum(1 for rec in action_executions or [] if _action_execution_needs_approval(rec))
    pending_count = pending_reply_count + pending_action_count
    draft_count = sum(1 for rec in outbound_messages if _string_from(rec.get("status")) == "draft")
    queued_count = sum(1 for rec in outbound_messages if _string_from(rec.get("status")) == "queued")
    sent_count = sum(1 for rec in outbound_messages if _string_from(rec.get("status")) == "sent")
    failed_count = sum(1 for rec in outbound_messages if _reply_has_failed_delivery(rec))
    pending_delivery_count = sum(1 for rec in outbound_messages if _reply_has_pending_delivery(rec))
    return {
        "pendingApprovalCount": pending_count,
        "hasPendingApproval": pending_count > 0,
        "pendingReplyApprovalCount": pending_reply_count,
        "hasPendingReplyApproval": pending_reply_count > 0,
        "pendingActionApprovalCount": pending_action_count,
        "hasPendingActionApproval": pending_action_count > 0,
        "failedDeliveryCount": failed_count,
        "hasFailedDelivery": failed_count > 0,
        "pendingDeliveryCount": pending_delivery_count,
        "hasPendingDelivery": pending_delivery_count > 0,
        "draftReplyCount": draft_count,
        "queuedReplyCount": queued_count,
        "sentReplyCount": sent_count,
        "failedReplyCount": failed_count,
    }


