def _issue_ticket_channel_lifecycle(issue: dict[str, Any]) -> dict[str, Any]:
    metadata = _record_from(issue.get("metadata"))
    resolver = _record_from(metadata.get("resolver"))
    context = _reply_channel_context(issue)
    target = _reply_target_context(issue, context)
    channel = (
        _string_from(issue.get("channel"))
        or _string_from(context.get("channel"))
        or "email"
    )
    source = (
        _string_from(issue.get("source"))
        or _string_from(context.get("issueSource"))
        or "unknown"
    )
    provider = (
        _string_from(metadata.get("provider"))
        or _string_from(metadata.get("externalProvider"))
        or _string_from(resolver.get("provider"))
        or channel
    )
    channel_key = (
        _string_from(context.get("channelKey"))
        or _string_from(metadata.get("channelKey"))
        or _string_from(resolver.get("channelKey"))
        or source
    )
    ticket_mode = (
        _string_from(metadata.get("ticketCreationMode"))
        or _string_from(resolver.get("ticketCreationMode"))
        or "per_thread"
    )
    resolver_action = (
        _string_from(metadata.get("resolverAction"))
        or _string_from(resolver.get("resolverAction"))
        or "linked"
    )
    source_issue_id = (
        _string_from(context.get("sourceIssueId"))
        or _string_from(metadata.get("sourceIssueId"))
        or _string_from(resolver.get("sourceIssueId"))
    )
    source_message_id = (
        _string_from(context.get("sourceMessageId"))
        or _string_from(metadata.get("sourceMessageId"))
        or _string_from(resolver.get("sourceMessageId"))
        or _string_from(metadata.get("providerMessageId"))
        or _string_from(metadata.get("messageId"))
    )
    external_ticket_key = (
        _string_from(metadata.get("externalTicketKey"))
        or _string_from(resolver.get("externalTicketKey"))
    )
    external_message_key = (
        _string_from(metadata.get("externalMessageKey"))
        or _string_from(resolver.get("externalMessageKey"))
    )
    inbound_linked = bool(channel_key or source_issue_id or source_message_id or external_ticket_key or external_message_key)
    target_key = _string_from(target.get("key"))
    target_label = _string_from(target.get("label"))
    reply_targeted = bool(_string_from(target.get("value")))
    blocked_keys = []
    if not inbound_linked:
        blocked_keys.append("missing_source")
    if not reply_targeted:
        blocked_keys.append("missing_reply_target")
    detail_parts = [
        f"{provider} via {channel_key or source}",
        f"{ticket_mode} {resolver_action}",
    ]
    if target_label:
        detail_parts.append(f"reply to {target_label}")
    return {
        "kind": "support_ticket_channel_lifecycle",
        "label": f"{channel} ticket",
        "detail": "; ".join(detail_parts) + ".",
        "channel": channel,
        "source": source,
        "provider": provider,
        "channelKey": channel_key,
        "ticketMode": ticket_mode,
        "resolverAction": resolver_action,
        "inboundLinked": inbound_linked,
        "replyTargeted": reply_targeted,
        "ready": inbound_linked and reply_targeted,
        "blockedKeys": blocked_keys,
        "sourceProof": {
            "sourceIssueId": source_issue_id,
            "sourceMessageId": source_message_id,
            "externalTicketKey": external_ticket_key,
            "externalMessageKey": external_message_key,
        },
        "replyTarget": {
            "key": target_key,
            "label": target_label,
            "channelKey": _string_from(target.get("channelKey")),
        },
    }


def _issue_ticket_state(issue: dict[str, Any]) -> dict[str, Any]:
    pending_approvals = int(issue.get("pendingApprovalCount") or 0)
    pending_actions = int(issue.get("pendingActionApprovalCount") or 0)
    draft_replies = int(issue.get("draftReplyCount") or issue.get("pendingReplyApprovalCount") or 0)
    queued_replies = int(issue.get("queuedReplyCount") or issue.get("pendingDeliveryCount") or 0)
    sent_replies = int(issue.get("sentReplyCount") or 0)
    failed_replies = int(issue.get("failedReplyCount") or issue.get("failedDeliveryCount") or 0)
    agent_runs = int(issue.get("agentRunCount") or 0)
    open_gaps = int(issue.get("openKnowledgeGapCount") or 0)
    next_action = _issue_answer_workspace_next_action(issue)
    agent_prepared = agent_runs > 0 or draft_replies > 0 or sent_replies > 0
    human_loop_required = pending_approvals > 0 or pending_actions > 0
    knowledge_covered = open_gaps == 0
    if failed_replies > 0:
        label = "Delivery blocked"
    elif human_loop_required:
        label = "Review ready"
    elif agent_prepared:
        label = "Agent prepared"
    elif bool(issue.get("needsResponse")):
        label = "Needs reply"
    elif _canonical_status(_string_from(issue.get("workflowStatus") or issue.get("status")) or "open") == "done":
        label = "Closed"
    else:
        label = "Clear"
    def count_label(count: int, singular: str, plural: str) -> str:
        return f"{count} {singular if count == 1 else plural}"

    detail = ", ".join([
        count_label(agent_runs, "agent run", "agent runs"),
        count_label(draft_replies, "draft", "drafts"),
        count_label(pending_approvals, "approval", "approvals"),
        count_label(open_gaps, "gap", "gaps"),
    ]) + "."
    return {
        "kind": "support_ticket_list_state",
        "label": label,
        "detail": detail,
        "nextActionKind": _string_from(next_action.get("kind")),
        "nextActionPhase": _string_from(next_action.get("phase")),
        "agentPrepared": agent_prepared,
        "humanLoopRequired": human_loop_required,
        "knowledgeCovered": knowledge_covered,
        "canClose": _string_from(next_action.get("kind")) in {"ready_to_close", "done", "clear"},
        "channelLifecycle": _issue_ticket_channel_lifecycle(issue),
        "counts": {
            "agentRuns": agent_runs,
            "replyDrafts": draft_replies,
            "queuedReplies": queued_replies,
            "sentReplies": sent_replies,
            "failedReplies": failed_replies,
            "pendingApprovals": pending_approvals,
            "pendingActions": pending_actions,
            "openKnowledgeGaps": open_gaps,
        },
    }


def _csat_summary_from_feedback(feedback: list[dict[str, Any]]) -> dict[str, Any]:
    normalized = [_normalize_csat_feedback(item) for item in feedback]
    low_count = sum(1 for item in normalized if 0 < int(item.get("rating") or 0) <= 2)
    latest = normalized[0] if normalized else {}
    return {
        "csatFeedbackCount": len(normalized),
        "lowCsatFeedbackCount": low_count,
        "hasLowCsatFeedback": low_count > 0,
        "latestCsatRating": int(latest.get("rating") or 0),
        "latestCsatComment": _string_from(latest.get("comment")),
        "latestCsatReceivedAt": _string_from(latest.get("receivedAt")),
    }


