def _issue_done_blockers(
    issue_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    allow_no_response_resolution: bool = False,
) -> list[str]:
    outbound_messages = _list_all(
        "support_outbound_messages",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"issue='{_escape_pb(issue_id)}'",
        ),
        sort="-created",
        per_page=200,
    )
    blockers: list[str] = []
    if any(_reply_needs_approval(rec) for rec in outbound_messages):
        blockers.append(WORKFLOW_DONE_BLOCKERS[0])
    action_executions = _list_all(
        "support_action_executions",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"issue='{_escape_pb(issue_id)}' && status='pending'",
        ),
        sort="-created",
        per_page=200,
    )
    if any(_action_execution_needs_approval(rec) for rec in action_executions):
        blockers.append(WORKFLOW_DONE_BLOCKERS[1])
    if any(_reply_has_pending_delivery(rec) for rec in outbound_messages):
        blockers.append(WORKFLOW_DONE_BLOCKERS[2])
    if any(_reply_has_failed_delivery(rec) for rec in outbound_messages):
        blockers.append(WORKFLOW_DONE_BLOCKERS[3])
    if not allow_no_response_resolution:
        message_records = _list_all(
            "support_messages",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"issue='{_escape_pb(issue_id)}'",
            ),
            sort="-occurred_at",
            per_page=200,
        )
        response_summary = _message_response_summary_from_records(
            message_records,
            issue_status="ongoing",
        )
        if bool(response_summary.get("needsResponse")):
            blockers.append(WORKFLOW_DONE_BLOCKERS[4])
        if any(_reply_has_requested_changes(rec) for rec in outbound_messages):
            blockers.append(WORKFLOW_DONE_BLOCKERS[5])
    return blockers


def _sla_summary_from_events(events: list[dict[str, Any]], now: datetime | None = None) -> dict[str, Any]:
    reference = now or datetime.now(timezone.utc)
    pending_events: list[tuple[datetime, dict[str, Any]]] = []
    overdue = 0
    for event in events:
        if _string_from(event.get("status")) != "pending":
            continue
        target = _parse_iso_datetime(event.get("target_at") or event.get("targetAt"))
        if not target:
            continue
        pending_events.append((target, event))
        if target < reference:
            overdue += 1
    if not pending_events:
        return {
            "overdueSlaCount": 0,
            "hasOverdueSla": False,
            "nextSlaTargetAt": "",
            "nextSlaEventType": "",
        }
    next_target, next_event = min(pending_events, key=lambda item: item[0])
    return {
        "overdueSlaCount": overdue,
        "hasOverdueSla": overdue > 0,
        "nextSlaTargetAt": next_target.isoformat(),
        "nextSlaEventType": _string_from(next_event.get("event_type") or next_event.get("eventType")),
    }


