ARTICLE_REVISION_FIELDS = (
    "title",
    "body",
    "status",
    "tags",
    "sourceIssueId",
    "sourceUrl",
    "visibility",
    "public",
    "automationAllowed",
)
KNOWLEDGE_REVIEW_STATUSES = {"draft", "needs_review", "reviewed", "stale"}
KNOWLEDGE_DEFAULT_REVIEW_DAYS = 90
KNOWLEDGE_HUMAN_ROLES = {"root", "admin", "editor", "viewer"}


def _article_visibility(metadata: dict[str, Any]) -> str:
    return _string_from(metadata.get("visibility") or metadata.get("access") or "internal") or "internal"


def _article_public(metadata: dict[str, Any], visibility: str) -> bool:
    return not (
        metadata.get("public") is False
        or _string_from(metadata.get("public")).lower() in {"false", "0", "no"}
        or visibility.lower() in {"private", "internal"}
    )


def _article_revisions(metadata: dict[str, Any]) -> list[dict[str, Any]]:
    revisions = metadata.get("revisions")
    if not isinstance(revisions, list):
        return []
    return [item for item in revisions if isinstance(item, dict)]


def _knowledge_article_access_visibility(article: dict[str, Any]) -> str:
    """Resolve access conservatively; restrictive metadata always wins."""
    metadata = _parse(article.get("metadata"), dict)
    raw_visibility = _string_from(
        metadata.get("visibility")
        or metadata.get("access")
        or article.get("visibility")
    ).lower()
    if raw_visibility and raw_visibility not in {"public", "internal", "private"}:
        return "unconfigured"
    public_flag = metadata.get("public") if "public" in metadata else article.get("public")
    if raw_visibility:
        visibility = raw_visibility
    elif public_flag is True:
        visibility = "public"
    else:
        # Legacy records remain company-internal, never public help content.
        visibility = "internal"
    if visibility == "public" and (
        public_flag is False
        or _string_from(public_flag).lower() in {"false", "0", "no"}
    ):
        visibility = "internal"
    return visibility


def _knowledge_article_owner_email(article: dict[str, Any]) -> str:
    metadata = _parse(article.get("metadata"), dict)
    owner = _string_from(
        metadata.get("ownerEmail")
        or metadata.get("owner_email")
        or metadata.get("createdBy")
        or metadata.get("created_by")
    ).lower()
    if owner:
        return owner
    for revision in _article_revisions(metadata):
        actor = _string_from(
            revision.get("actorEmail") or revision.get("actor_email")
        ).lower()
        if actor and actor not in {"system", "automation"}:
            return actor
    return ""


def _knowledge_article_automation_allowed(article: dict[str, Any]) -> bool:
    """Resolve the company automation identity permission, fail-closed for restricted data."""
    metadata = _parse(article.get("metadata"), dict)
    keys = (
        "automationAllowed",
        "automation_allowed",
        "allowAutomation",
        "allow_automation",
    )
    if "automationAllowed" in article:
        return article.get("automationAllowed") is True
    if "automation_allowed" in article:
        return article.get("automation_allowed") is True
    if any(key in metadata for key in keys):
        return _metadata_flag(metadata, *keys)
    # Public help content remains automation-ready by default. Company-only
    # sources require an explicit grant, including legacy records.
    return _knowledge_article_access_visibility(article) == "public"


def _knowledge_article_visible_to_principal(
    article: dict[str, Any],
    *,
    actor_email: str = "",
    actor_role: str = "automation",
) -> bool:
    """Authorize one article before it can enter a response or agent corpus."""
    visibility = _knowledge_article_access_visibility(article)
    if visibility not in {"public", "internal", "private"}:
        return False
    role = _string_from(actor_role).lower()
    if role == "automation":
        return _knowledge_article_automation_allowed(article)
    if role not in KNOWLEDGE_HUMAN_ROLES:
        return False
    if visibility in {"public", "internal"}:
        return True
    return role in {"root", "admin"}


def _article_revision_number(metadata: dict[str, Any]) -> int:
    try:
        revision = int(metadata.get("revision") or 0)
    except (TypeError, ValueError):
        revision = 0
    return max(revision, len(_article_revisions(metadata)))


def _article_snapshot(rec: dict[str, Any], metadata: dict[str, Any]) -> dict[str, Any]:
    visibility = _article_visibility(metadata)
    return {
        "sourceIssueId": rec.get("source_issue", ""),
        "title": rec.get("title", ""),
        "body": rec.get("body", ""),
        "status": rec.get("status", "draft"),
        "tags": _parse(rec.get("tags"), list),
        "sourceUrl": _string_from(metadata.get("sourceUrl") or metadata.get("source_url") or metadata.get("url")),
        "visibility": visibility,
        "public": _article_public(metadata, visibility),
        "automationAllowed": _knowledge_article_automation_allowed(
            {**rec, "metadata": metadata}
        ),
    }


def _article_review_signal(rec: dict[str, Any], metadata: dict[str, Any]) -> dict[str, Any]:
    status = _string_from(rec.get("status")).lower() or "draft"
    explicit_review_status = _string_from(
        metadata.get("reviewStatus") or metadata.get("review_status")
    ).lower()
    last_reviewed_at = _string_from(
        metadata.get("lastReviewedAt") or metadata.get("last_reviewed_at")
    )
    reviewed_by = _string_from(metadata.get("reviewedBy") or metadata.get("reviewed_by"))
    review_due_at = _string_from(metadata.get("reviewDueAt") or metadata.get("review_due_at"))
    review_due = _parse_iso_datetime(review_due_at)
    now = _now_utc()

    if status != "published":
        default_review_status = "draft"
    elif review_due and review_due <= now:
        default_review_status = "stale"
    elif last_reviewed_at:
        default_review_status = "reviewed"
    else:
        default_review_status = "needs_review"

    review_status = explicit_review_status if explicit_review_status in KNOWLEDGE_REVIEW_STATUSES else default_review_status
    if review_status == "reviewed" and review_due and review_due <= now:
        review_status = "stale"

    if review_status == "stale":
        freshness_status = "stale"
        reason = "Review due date has passed."
    elif review_status == "reviewed":
        freshness_status = "fresh"
        reason = "Article has been reviewed for agent and reply use."
    elif review_status == "draft":
        freshness_status = "draft"
        reason = "Draft articles are not ready for customer-facing answers."
    else:
        freshness_status = "needs_review"
        reason = "Article needs human review before agents can trust it."

    return {
        "reviewStatus": review_status,
        "lastReviewedAt": last_reviewed_at,
        "reviewedBy": reviewed_by,
        "reviewDueAt": review_due_at,
        "freshnessStatus": freshness_status,
        "freshnessReason": reason,
        "needsReview": review_status in {"needs_review", "stale"},
    }


def _article_revision_action(
    *,
    before: dict[str, Any] | None,
    after: dict[str, Any],
    changed_fields: list[str],
    created: bool = False,
) -> str:
    if created:
        return "created"
    if before and before.get("status") != "published" and after.get("status") == "published":
        return "published"
    if before and before.get("status") == "published" and after.get("status") != "published":
        return "unpublished"
    if "automationAllowed" in changed_fields:
        return "automation_access_changed"
    if "visibility" in changed_fields or "public" in changed_fields:
        return "visibility_changed"
    if any(field in changed_fields for field in ("title", "body", "tags")):
        return "content_updated"
    return "updated"


def _article_revision_entry(
    *,
    revision: int,
    before: dict[str, Any] | None,
    after: dict[str, Any],
    changed_fields: list[str],
    actor_email: str,
    created: bool = False,
) -> dict[str, Any]:
    body = _string_from(after.get("body"))
    action = _article_revision_action(
        before=before,
        after=after,
        changed_fields=changed_fields,
        created=created,
    )
    entry: dict[str, Any] = {
        "revision": revision,
        "action": action,
        "actorEmail": actor_email or "system",
        "at": _now_iso(),
        "changedFields": changed_fields,
        "title": _string_from(after.get("title")),
        "status": _string_from(after.get("status")) or "draft",
        "visibility": _string_from(after.get("visibility")) or "public",
        "public": bool(after.get("public")),
        "automationAllowed": bool(after.get("automationAllowed")),
        "tags": after.get("tags") if isinstance(after.get("tags"), list) else [],
        "sourceIssueId": _string_from(after.get("sourceIssueId")),
        "sourceUrl": _string_from(after.get("sourceUrl")),
        "bodySha256": hashlib.sha256(body.encode("utf-8")).hexdigest(),
        "bodyPreview": _clip(body, 240),
    }
    if before:
        entry["fromStatus"] = _string_from(before.get("status")) or "draft"
        entry["fromVisibility"] = _string_from(before.get("visibility")) or "public"
    return entry


def _normalize_article(rec: dict[str, Any]) -> dict[str, Any]:
    metadata = _parse(rec.get("metadata"), dict)
    snapshot = _article_snapshot(rec, metadata)
    return {
        "id": rec.get("id", ""),
        **snapshot,
        **_article_review_signal(rec, metadata),
        "metadata": metadata,
        "revision": _article_revision_number(metadata),
        "revisions": _article_revisions(metadata),
        "created": rec.get("created", ""),
        "updated": rec.get("updated", ""),
    }


def _normalize_article_for_principal(
    rec: dict[str, Any],
    *,
    actor_email: str,
    actor_role: str,
) -> dict[str, Any]:
    normalized = _normalize_article(rec)
    visible_revisions = [
        revision
        for revision in _article_revisions(_parse(rec.get("metadata"), dict))
        if _knowledge_article_visible_to_principal(
            {
                "visibility": revision.get("visibility"),
                "public": revision.get("public"),
                "automationAllowed": revision.get("automationAllowed"),
            },
            actor_email=actor_email,
            actor_role=actor_role,
        )
    ]
    normalized["revisions"] = visible_revisions
    normalized["metadata"] = {
        **_record_from(normalized.get("metadata")),
        "revisions": visible_revisions,
    }
    return normalized


def _normalize_account_insight(rec: dict[str, Any]) -> dict[str, Any]:
    return {
        "id": rec.get("id", ""),
        "accountId": rec.get("account", ""),
        "sourceIssueId": rec.get("source_issue", ""),
        "insightKey": rec.get("insight_key", ""),
        "type": rec.get("type", ""),
        "title": rec.get("title", ""),
        "body": rec.get("body", ""),
        "severity": rec.get("severity", "info"),
        "status": rec.get("status", "open"),
        "metadata": _parse(rec.get("metadata"), dict),
        "firstSeenAt": rec.get("first_seen_at") or "",
        "lastSeenAt": rec.get("last_seen_at") or "",
        "created": rec.get("created", ""),
        "updated": rec.get("updated", ""),
    }


def _account_insight_summary(insights: list[dict[str, Any]]) -> dict[str, Any]:
    unresolved_statuses = {"open", "active", "acknowledged", "needs_attention", ""}
    unresolved = [
        insight for insight in insights
        if _string_from(insight.get("status")).lower() in unresolved_statuses
    ]
    risks = [insight for insight in insights if _string_from(insight.get("type")) == "risk"]
    feature_requests = [insight for insight in insights if _string_from(insight.get("type")) == "feature_request"]
    summaries = [insight for insight in insights if _string_from(insight.get("type")) == "summary"]
    return {
        "total": len(insights),
        "unresolved": len(unresolved),
        "risks": len(risks),
        "openRisks": sum(1 for insight in risks if _string_from(insight.get("status")).lower() in unresolved_statuses),
        "featureRequests": len(feature_requests),
        "openFeatureRequests": sum(
            1 for insight in feature_requests
            if _string_from(insight.get("status")).lower() in unresolved_statuses
        ),
        "summaries": len(summaries),
        "lastInsightAt": max(
            (_string_from(insight.get("lastSeenAt") or insight.get("last_seen_at") or insight.get("updated")) for insight in insights),
            default="",
        ),
    }


def _account_insight_unresolved(insight: dict[str, Any]) -> bool:
    return _string_from(insight.get("status")).lower() in {"open", "active", "acknowledged", "needs_attention", ""}


def _account_issue_is_open(issue: dict[str, Any]) -> bool:
    return _canonical_status(_string_from(issue.get("status")) or "open") != "done"


def _account_health_rollup(
    *,
    account: dict[str, Any],
    insights: list[dict[str, Any]],
    issues: list[dict[str, Any]],
    external_sync_runs: list[dict[str, Any]],
) -> dict[str, Any]:
    summary = _account_insight_summary(insights)
    unresolved_risks = [
        insight for insight in insights
        if _string_from(insight.get("type")) == "risk" and _account_insight_unresolved(insight)
    ]
    high_risks = [
        insight for insight in unresolved_risks
        if _string_from(insight.get("severity")).lower() in {"urgent", "high", "at_risk", "blocked"}
    ]
    open_issues = [issue for issue in issues if _account_issue_is_open(issue)]
    urgent_issues = [
        issue for issue in open_issues
        if _string_from(issue.get("priority")).lower() == "urgent"
    ]
    high_priority_issues = [
        issue for issue in open_issues
        if _string_from(issue.get("priority")).lower() in {"urgent", "high"}
    ]
    failed_sync_runs = [
        run for run in external_sync_runs
        if _string_from(run.get("status")).lower() in {"failed", "partial", "error"}
    ]
    base_status = _string_from(account.get("healthStatus") or account.get("health_status")) or "unknown"

    if urgent_issues or high_risks:
        status = "at_risk"
        reason = "Urgent support signal or high-severity account risk is open."
        next_action = "Assign an owner, confirm the customer update, and close the risk loop."
    elif unresolved_risks or high_priority_issues or failed_sync_runs:
        status = "needs_attention"
        reason = "Open risk, high-priority ticket, or CRM sync issue needs review."
        if failed_sync_runs:
            next_action = "Fix CRM sync before relying on this account context."
        elif unresolved_risks:
            next_action = "Review the open risk and decide the next customer-facing step."
        else:
            next_action = "Review the high-priority ticket and confirm customer follow-up."
    elif open_issues or summary["openFeatureRequests"]:
        status = "active"
        reason = "Account has open support work or tracked feature demand."
        next_action = "Keep ticket owner and feature-request follow-up current."
    elif issues or insights:
        status = "healthy"
        reason = "No unresolved account risks or open support tickets."
        next_action = "No immediate support action."
    else:
        status = base_status
        reason = "No support account signals yet."
        next_action = "Wait for first ticket, CRM record, or manual insight."

    return {
        "status": status,
        "reason": reason,
        "nextAction": next_action,
        "openIssues": len(open_issues),
        "urgentIssues": len(urgent_issues),
        "highPriorityIssues": len(high_priority_issues),
        "openRisks": summary["openRisks"],
        "openFeatureRequests": summary["openFeatureRequests"],
        "unresolvedSignals": summary["unresolved"],
        "failedExternalSyncRuns": len(failed_sync_runs),
        "lastSignalAt": summary["lastInsightAt"],
    }


def _account_action_metadata(
    *,
    account: dict[str, Any],
    health: dict[str, Any],
    insights: list[dict[str, Any]],
    issues: list[dict[str, Any]],
    external_sync_runs: list[dict[str, Any]],
) -> dict[str, Any]:
    status = _string_from(health.get("status")).lower()
    status_score = 100 if status in {"at_risk", "blocked"} else 70 if status == "needs_attention" else 30 if status == "active" else 0
    failed_sync_runs = int(health.get("failedExternalSyncRuns") or 0)
    open_risks = int(health.get("openRisks") or 0)
    open_features = int(health.get("openFeatureRequests") or 0)
    open_issues = int(health.get("openIssues") or 0)
    urgent_issues = int(health.get("urgentIssues") or 0)
    high_priority_issues = int(health.get("highPriorityIssues") or 0)
    unresolved_signals = int(health.get("unresolvedSignals") or 0)
    score = (
        status_score
        + urgent_issues * 20
        + high_priority_issues * 12
        + open_risks * 10
        + failed_sync_runs * 8
        + open_features * 3
        + min(open_issues, 20)
    )
    if score <= 0:
        return {
            "score": 0,
            "kind": "none",
            "label": "No immediate action",
            "detail": _string_from(health.get("nextAction")) or "No immediate support action.",
            "route": "accounts",
            "reasonCodes": [],
        }

    if urgent_issues:
        kind = "review_urgent_tickets"
        label = "Review urgent tickets"
        detail = f"{urgent_issues} urgent ticket{'s' if urgent_issues != 1 else ''} need owner follow-up."
        route = "inbox"
    elif open_risks:
        risk = next(
            (
                insight for insight in insights
                if _string_from(insight.get("type")) == "risk" and _account_insight_unresolved(insight)
            ),
            {},
        )
        risk_metadata = _parse(risk.get("metadata"), dict)
        kind = _string_from(risk_metadata.get("actionKind")) or "review_account_risk"
        label = {
            "protect_renewal": "Protect renewal",
            "recover_production_incident": "Recover production incident",
            "handle_security_risk": "Handle security risk",
            "recover_sla": "Recover SLA",
        }.get(kind, "Review account risk")
        detail = (
            _string_from(risk_metadata.get("recommendedAction"))
            or _string_from(risk.get("title"))
            or _string_from(health.get("nextAction"))
            or "Open account risk needs review."
        )
        route = "accounts"
    elif high_priority_issues:
        kind = "review_high_priority_tickets"
        label = "Review high-priority tickets"
        detail = f"{high_priority_issues} high-priority ticket{'s' if high_priority_issues != 1 else ''} need customer follow-up."
        route = "inbox"
    elif failed_sync_runs:
        kind = "fix_crm_sync"
        label = "Fix CRM sync"
        detail = f"{failed_sync_runs} failed CRM sync run{'s' if failed_sync_runs != 1 else ''} need review before account context is trusted."
        route = "channels"
    elif open_features:
        kind = "review_feature_demand"
        label = "Review feature demand"
        detail = f"{open_features} open feature request signal{'s' if open_features != 1 else ''} need product follow-up."
        route = "accounts"
    else:
        kind = "review_open_work"
        label = "Review open support work"
        detail = _string_from(health.get("nextAction")) or f"{open_issues} open ticket{'s' if open_issues != 1 else ''} need review."
        route = "inbox"

    reason_codes: list[str] = []
    if status in {"at_risk", "blocked", "needs_attention", "active"}:
        reason_codes.append(f"health:{status}")
    if urgent_issues:
        reason_codes.append("urgent_tickets")
    if high_priority_issues:
        reason_codes.append("high_priority_tickets")
    if open_risks:
        reason_codes.append("open_risks")
    if open_features:
        reason_codes.append("feature_demand")
    if failed_sync_runs:
        reason_codes.append("failed_crm_sync")
    if unresolved_signals:
        reason_codes.append("unresolved_signals")
    if open_issues:
        reason_codes.append("open_tickets")

    return {
        "score": score,
        "kind": kind,
        "label": label,
        "detail": detail,
        "route": route,
        "reasonCodes": reason_codes,
        "openIssues": open_issues,
        "urgentIssues": urgent_issues,
        "highPriorityIssues": high_priority_issues,
        "openRisks": open_risks,
        "openFeatureRequests": open_features,
        "failedExternalSyncRuns": failed_sync_runs,
        "unresolvedSignals": unresolved_signals,
        "latestIssueAt": _string_from(account.get("latestIssueAt") or account.get("latest_issue_at")),
        "lastSignalAt": _string_from(health.get("lastSignalAt")),
        "insightCount": len(insights),
        "issueCount": len(issues),
        "externalSyncRunCount": len(external_sync_runs),
    }


def _account_action_queue_items(
    *,
    accounts: list[dict[str, Any]],
    insights: list[dict[str, Any]],
    issues: list[dict[str, Any]],
    external_sync_runs: list[dict[str, Any]],
    limit: int = 5,
) -> list[dict[str, Any]]:
    insights_by_account: dict[str, list[dict[str, Any]]] = {}
    for insight in insights:
        account_id = _string_from(insight.get("account") or insight.get("accountId"))
        if account_id:
            insights_by_account.setdefault(account_id, []).append(_normalize_account_insight(insight))
    issues_by_account: dict[str, list[dict[str, Any]]] = {}
    for issue in issues:
        account_id = _string_from(issue.get("account") or issue.get("accountId"))
        if account_id:
            issues_by_account.setdefault(account_id, []).append(issue)
    sync_runs_by_account: dict[str, list[dict[str, Any]]] = {}
    for run in external_sync_runs:
        account_id = _string_from(run.get("account") or run.get("accountId"))
        if account_id:
            sync_runs_by_account.setdefault(account_id, []).append(_normalize_external_sync_run(run))

    items: list[dict[str, Any]] = []
    for rec in accounts:
        account = _normalize_account(rec)
        account_id = _string_from(account.get("id"))
        account_insights = insights_by_account.get(account_id, [])
        account_issues = issues_by_account.get(account_id, [])
        account_sync_runs = sync_runs_by_account.get(account_id, [])
        health = _account_health_rollup(
            account=account,
            insights=account_insights,
            issues=account_issues,
            external_sync_runs=account_sync_runs,
        )
        action = _account_action_metadata(
            account=account,
            health=health,
            insights=account_insights,
            issues=account_issues,
            external_sync_runs=account_sync_runs,
        )
        if int(action.get("score") or 0) <= 0:
            continue
        items.append({
            "accountId": account_id,
            "accountKey": _string_from(account.get("accountKey")),
            "name": _string_from(account.get("name")),
            "domain": _string_from(account.get("domain")),
            "healthStatus": _string_from(health.get("status")),
            "nextAction": _string_from(health.get("nextAction")),
            "action": action,
        })
    return sorted(
        items,
        key=lambda item: (
            -int(_record_from(item.get("action")).get("score") or 0),
            _string_from(item.get("name") or item.get("domain") or item.get("accountKey")).lower(),
        ),
    )[:limit]


