def _channel_webhook_event_issue_ids(rec: dict[str, Any]) -> set[str]:
    result = _parse(rec.get("result"), dict)
    payload = _parse(rec.get("payload"), dict)
    issue_ids: set[str] = set()

    def add_from(value: Any) -> None:
        clean = _string_from(value)
        if clean:
            issue_ids.add(clean)

    def scan(record: dict[str, Any]) -> None:
        for key in ("issueId", "issue_id", "sourceIssueId", "source_issue_id"):
            add_from(record.get(key))
        nested_issue = _parse(record.get("issue"), dict)
        add_from(nested_issue.get("id"))
        for nested_key in ("inbound", "delivery", "message", "item", "result"):
            nested = _parse(record.get(nested_key), dict)
            if nested:
                scan(nested)
        for nested_key in ("items", "events"):
            for item in _parse(record.get(nested_key), list):
                if isinstance(item, dict):
                    scan(item)

    scan(result)
    scan(payload)
    return issue_ids


