def _ensure_channel(
    *,
    tenant_id: str | None,
    project_id: str,
    channel_type: str,
    source: str,
) -> dict[str, Any] | None:
    if source.startswith("channel:"):
        configured = get_channel_by_key(
            source.removeprefix("channel:"),
            tenant_id=tenant_id,
            project_id=project_id,
        )
        if configured and (_string_from(configured.get("type")) or channel_type) == channel_type:
            patched = _patch(
                f"/api/collections/support_channels/records/{configured['id']}",
                {"last_sync_at": _now_iso()},
            )
            return {
                **configured,
                "lastSyncAt": patched.get("last_sync_at") or configured.get("lastSyncAt", ""),
            }
    channel_key = _key_from(f"{channel_type}:{source or 'default'}")
    if not channel_key:
        return None
    filter_str = _issue_filter(
        tenant_id=tenant_id,
        project_id=project_id,
        extra=f"channel_key='{_escape_pb(channel_key)}'",
    )
    existing = _first("support_channels", filter_str)
    existing_config = _parse(existing.get("config"), dict) if existing else {}
    data = {
        "channel_key": channel_key,
        "type": channel_type,
        "name": f"{channel_type.title()} ({source or 'default'})",
        "status": "active",
        "config": {
            **existing_config,
            "source": source,
            "ticketCreationMode": _string_from(
                existing_config.get("ticketCreationMode") or existing_config.get("ticket_creation_mode")
            ) or "per_message",
        },
        "last_sync_at": _now_iso(),
    }
    if existing:
        _patch(f"/api/collections/support_channels/records/{existing['id']}", data)
        return {**existing, **data}
    create_data = {"id": generate_id(), **data}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _post("/api/collections/support_channels/records", create_data)


def _default_issue_assignee(
    *,
    tenant_id: str | None,
    project_id: str,
    channel: dict[str, Any] | None = None,
    queue_key: str = "",
) -> str:
    channel_config = channel.get("config") if isinstance(channel, dict) and isinstance(channel.get("config"), dict) else {}
    for key in ("defaultAssigneeEmail", "default_assignee_email", "assigneeEmail", "assignee_email"):
        value = _string_from(channel_config.get(key))
        if value:
            return value
    clean_queue_key = _queue_key_from(queue_key)
    if clean_queue_key:
        try:
            queue = _first(
                "support_queues",
                _issue_filter(
                    tenant_id=tenant_id,
                    project_id=project_id,
                    extra=f"queue_key='{_escape_pb(clean_queue_key)}' && status='active'",
                ),
            )
        except Exception:
            queue = None
        queue_assignee = _least_open_queue_assignee(
            queue,
            tenant_id=tenant_id,
            project_id=project_id,
        ) if queue else ""
        if not queue_assignee and not (_queue_assignment_mode(queue) == "least_open" and _queue_owner_capacity(queue)):
            queue_assignee = _string_from(queue.get("default_assignee_email")) if queue else ""
        if queue_assignee:
            return queue_assignee
        if queue and _queue_assignment_mode(queue) == "least_open" and _queue_owner_capacity(queue):
            return ""
    try:
        policy = get_sla_policy(tenant_id=tenant_id, project_id=project_id)
    except Exception:
        return ""
    metadata = policy.get("metadata") if isinstance(policy.get("metadata"), dict) else {}
    for key in ("defaultAssigneeEmail", "default_assignee_email", "assigneeEmail", "assignee_email"):
        value = _string_from(metadata.get(key))
        if value:
            return value
    return ""


def _email_list_from(value: Any) -> list[str]:
    raw_items = value if isinstance(value, list) else str(value or "").replace("\n", ",").split(",")
    emails: list[str] = []
    seen: set[str] = set()
    for item in raw_items:
        email = _string_from(item).lower()
        if not email or email in seen:
            continue
        seen.add(email)
        emails.append(email)
    return emails


def _queue_allowed_assignee_emails(queue: dict[str, Any] | None) -> list[str]:
    if not queue:
        return []
    metadata = _parse(queue.get("metadata"), dict)
    for key in (
        "allowedAssigneeEmails",
        "allowed_assignee_emails",
        "assigneeEmails",
        "assignee_emails",
        "ownerEmails",
        "owner_emails",
        "owners",
    ):
        emails = _email_list_from(metadata.get(key))
        if emails:
            return emails
    return []


def _queue_assignment_mode(queue: dict[str, Any] | None) -> str:
    metadata = _parse((queue or {}).get("metadata"), dict)
    for key in ("assignmentMode", "assignment_mode", "routingMode", "routing_mode"):
        raw = _string_from(metadata.get(key)).lower()
        clean = re.sub(r"[^a-z0-9]+", "_", raw).strip("_")
        if clean in {"least_open", "least_active", "least_loaded", "load_balanced"}:
            return "least_open"
    return "static"


def _positive_int_from(value: Any) -> int:
    try:
        number = int(float(str(value).strip()))
    except (TypeError, ValueError):
        return 0
    return number if number > 0 else 0


def _queue_owner_capacity(queue: dict[str, Any] | None) -> int:
    metadata = _parse((queue or {}).get("metadata"), dict)
    for key in (
        "ownerCapacity",
        "owner_capacity",
        "maxOpenTicketsPerOwner",
        "max_open_tickets_per_owner",
        "maxActiveTicketsPerOwner",
        "max_active_tickets_per_owner",
        "maxActiveTickets",
        "max_active_tickets",
        "capacity",
    ):
        value = _positive_int_from(metadata.get(key))
        if value:
            return value
    return 0


def _queue_capacity_items(
    *,
    support_queues: list[dict[str, Any]],
    issues: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    active_ticket_counts: dict[tuple[str, str], int] = {}
    for issue in issues:
        if _merged_into_issue_id(issue):
            continue
        status = _canonical_status(_string_from(issue.get("status")) or "open")
        if status == "done":
            continue
        queue_key = _queue_key_from(issue.get("queue_key") or issue.get("queueKey"))
        assignee_email = _string_from(issue.get("assignee_email") or issue.get("assigneeEmail")).lower()
        if not queue_key or not assignee_email:
            continue
        key = (queue_key, assignee_email)
        active_ticket_counts[key] = active_ticket_counts.get(key, 0) + 1

    items: list[dict[str, Any]] = []
    for queue in support_queues:
        if (_string_from(queue.get("status") or "active").lower() or "active") != "active":
            continue
        if _queue_assignment_mode(queue) != "least_open":
            continue
        capacity = _queue_owner_capacity(queue)
        if not capacity:
            continue
        queue_key = _queue_key_from(queue.get("queue_key") or queue.get("queueKey"))
        if not queue_key:
            continue
        queue_name = _queue_name_from(queue_key, queue.get("name") or queue.get("queueName"))
        for assignee_email in _queue_allowed_assignee_emails(queue):
            active_tickets = active_ticket_counts.get((queue_key, assignee_email), 0)
            if active_tickets < capacity:
                continue
            items.append({
                "queueKey": queue_key,
                "queueName": queue_name,
                "assigneeEmail": assignee_email,
                "activeTickets": active_tickets,
                "capacity": capacity,
                "overBy": max(0, active_tickets - capacity),
            })
    return sorted(
        items,
        key=lambda item: (
            -int(item.get("overBy") or 0),
            -int(item.get("activeTickets") or 0),
            _string_from(item.get("queueName")).lower(),
            _string_from(item.get("assigneeEmail")).lower(),
        ),
    )


def _queue_owner_workloads(
    *,
    support_queues: list[dict[str, Any]],
    issues: list[dict[str, Any]],
) -> dict[str, list[dict[str, Any]]]:
    active_ticket_counts: dict[tuple[str, str], int] = {}
    for issue in issues:
        if _merged_into_issue_id(issue):
            continue
        status = _canonical_status(_string_from(issue.get("status")) or "open")
        if status == "done":
            continue
        queue_key = _queue_key_from(issue.get("queue_key") or issue.get("queueKey"))
        assignee_email = _string_from(issue.get("assignee_email") or issue.get("assigneeEmail")).lower()
        if not queue_key or not assignee_email:
            continue
        key = (queue_key, assignee_email)
        active_ticket_counts[key] = active_ticket_counts.get(key, 0) + 1

    workloads: dict[str, list[dict[str, Any]]] = {}
    for queue in support_queues:
        queue_key = _queue_key_from(queue.get("queue_key") or queue.get("queueKey"))
        if not queue_key:
            continue
        capacity = _queue_owner_capacity(queue)
        items: list[dict[str, Any]] = []
        for assignee_email in _queue_allowed_assignee_emails(queue):
            active_tickets = active_ticket_counts.get((queue_key, assignee_email), 0)
            items.append({
                "assigneeEmail": assignee_email,
                "activeTickets": active_tickets,
                "capacity": capacity,
                "atCapacity": bool(capacity and active_tickets >= capacity),
                "overBy": max(0, active_tickets - capacity) if capacity else 0,
            })
        workloads[queue_key] = sorted(
            items,
            key=lambda item: (
                -int(item.get("overBy") or 0),
                -int(item.get("activeTickets") or 0),
                _string_from(item.get("assigneeEmail")).lower(),
            ),
        )
    return workloads


def _least_open_queue_assignee(
    queue: dict[str, Any],
    *,
    tenant_id: str | None,
    project_id: str,
) -> str:
    allowed = _queue_allowed_assignee_emails(queue)
    if not allowed or _queue_assignment_mode(queue) != "least_open":
        return ""
    queue_key = _queue_key_from(queue.get("queue_key") or queue.get("queueKey"))
    if not queue_key:
        return ""
    try:
        records = _list_all(
            "support_issues",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"queue_key='{_escape_pb(queue_key)}'",
            ),
            per_page=500,
        )
    except Exception:
        records = []
    counts = {email: 0 for email in allowed}
    for record in records:
        assignee = _string_from(record.get("assignee_email") or record.get("assigneeEmail")).lower()
        if assignee not in counts:
            continue
        if _workflow_status(_string_from(record.get("status"))) == "done":
            continue
        if _merged_into_issue_id(record):
            continue
        counts[assignee] += 1
    capacity = _queue_owner_capacity(queue)
    candidates = [email for email in allowed if not capacity or counts[email] < capacity]
    if not candidates:
        return ""
    return min(candidates, key=lambda email: (counts[email], allowed.index(email)))


def _queue_metadata_with_allowed_assignees(metadata: dict[str, Any] | None) -> tuple[dict[str, Any], list[str]]:
    clean = dict(_record_from(metadata))
    raw_allowed: Any = None
    seen_key = False
    for key in (
        "allowedAssigneeEmails",
        "allowed_assignee_emails",
        "assigneeEmails",
        "assignee_emails",
        "ownerEmails",
        "owner_emails",
        "owners",
    ):
        if key in clean and raw_allowed is None:
            raw_allowed = clean.get(key)
            seen_key = True
        clean.pop(key, None)
    raw_capacity: Any = None
    for key in (
        "ownerCapacity",
        "owner_capacity",
        "maxOpenTicketsPerOwner",
        "max_open_tickets_per_owner",
        "maxActiveTicketsPerOwner",
        "max_active_tickets_per_owner",
        "maxActiveTickets",
        "max_active_tickets",
        "capacity",
    ):
        if key in clean and raw_capacity is None:
            raw_capacity = clean.get(key)
        clean.pop(key, None)
    allowed = _email_list_from(raw_allowed)
    if seen_key:
        clean["allowedAssigneeEmails"] = allowed
    owner_capacity = _positive_int_from(raw_capacity)
    if owner_capacity:
        clean["ownerCapacity"] = owner_capacity
    return clean, allowed


def _queue_for_key(
    *,
    tenant_id: str | None,
    project_id: str,
    queue_key: str,
) -> dict[str, Any] | None:
    clean_queue_key = _queue_key_from(queue_key)
    if not clean_queue_key:
        return None
    return _first(
        "support_queues",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"queue_key='{_escape_pb(clean_queue_key)}'",
        ),
    )


def _ensure_queue_allows_assignee(
    *,
    tenant_id: str | None,
    project_id: str,
    queue_key: str,
    assignee_email: str,
) -> None:
    clean_assignee = _string_from(assignee_email).lower()
    if not clean_assignee:
        return
    queue = _queue_for_key(tenant_id=tenant_id, project_id=project_id, queue_key=queue_key)
    allowed = _queue_allowed_assignee_emails(queue)
    if allowed and clean_assignee not in allowed:
        queue_name = _string_from(queue.get("name")) if queue else _queue_name_from(queue_key)
        raise ValueError(f"{clean_assignee} is not allowed for queue {queue_name}")


def _queue_capacity_assignment_override(
    *,
    tenant_id: str | None,
    project_id: str,
    queue_key: str,
    assignee_email: str,
    issue_id: str,
    effective_status: str,
) -> dict[str, Any]:
    clean_assignee = _string_from(assignee_email).lower()
    clean_queue_key = _queue_key_from(queue_key)
    if not clean_queue_key or not clean_assignee or _workflow_status(effective_status) == "done":
        return {}
    queue = _queue_for_key(tenant_id=tenant_id, project_id=project_id, queue_key=clean_queue_key)
    if not queue or _queue_assignment_mode(queue) != "least_open":
        return {}
    capacity = _queue_owner_capacity(queue)
    if not capacity:
        return {}
    allowed = _queue_allowed_assignee_emails(queue)
    if allowed and clean_assignee not in allowed:
        return {}
    try:
        records = _list_all(
            "support_issues",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"queue_key='{_escape_pb(clean_queue_key)}'",
            ),
            per_page=500,
        )
    except Exception:
        return {}
    active_before = 0
    for record in records:
        if _string_from(record.get("id")) == issue_id:
            continue
        if _merged_into_issue_id(record):
            continue
        if _workflow_status(_string_from(record.get("status"))) == "done":
            continue
        if _string_from(record.get("assignee_email") or record.get("assigneeEmail")).lower() == clean_assignee:
            active_before += 1
    if active_before < capacity:
        return {}
    active_after = active_before + 1
    return {
        "queueKey": clean_queue_key,
        "queueName": _queue_name_from(clean_queue_key, queue.get("name") or queue.get("queueName")),
        "assigneeEmail": clean_assignee,
        "activeTicketsBefore": active_before,
        "activeTicketsAfter": active_after,
        "capacity": capacity,
        "overBy": max(0, active_after - capacity),
    }


def _queue_from_config(config: dict[str, Any]) -> tuple[str, str]:
    queue_key = ""
    for key in ("defaultQueueKey", "default_queue_key", "queueKey", "queue_key"):
        queue_key = _queue_key_from(config.get(key))
        if queue_key:
            break
    queue_name = ""
    for key in ("defaultQueueName", "default_queue_name", "queueName", "queue_name"):
        queue_name = _string_from(config.get(key))
        if queue_name:
            break
    if not queue_key and queue_name:
        queue_key = _queue_key_from(queue_name)
    if not queue_key:
        return "", ""
    return queue_key, _queue_name_from(queue_key, queue_name)


def _default_issue_queue(
    *,
    tenant_id: str | None,
    project_id: str,
    channel: dict[str, Any] | None = None,
) -> tuple[str, str]:
    channel_config = channel.get("config") if isinstance(channel, dict) and isinstance(channel.get("config"), dict) else {}
    queue_key, queue_name = _queue_from_config(channel_config)
    if queue_key:
        return queue_key, queue_name
    try:
        policy = get_sla_policy(tenant_id=tenant_id, project_id=project_id)
    except Exception:
        return DEFAULT_QUEUE_KEY, DEFAULT_QUEUE_NAME
    metadata = policy.get("metadata") if isinstance(policy.get("metadata"), dict) else {}
    queue_key, queue_name = _queue_from_config(metadata)
    if queue_key:
        return queue_key, queue_name
    return DEFAULT_QUEUE_KEY, DEFAULT_QUEUE_NAME


def _apply_default_queue(
    issue_data: dict[str, Any],
    *,
    tenant_id: str | None,
    project_id: str,
    channel: dict[str, Any] | None = None,
) -> tuple[str, str]:
    existing_key = _queue_key_from(issue_data.get("queue_key"))
    existing_name = _string_from(issue_data.get("queue_name"))
    if existing_key:
        issue_data["queue_key"] = existing_key
        issue_data["queue_name"] = _queue_name_from(existing_key, existing_name)
        return existing_key, issue_data["queue_name"]
    queue_key, queue_name = _default_issue_queue(tenant_id=tenant_id, project_id=project_id, channel=channel)
    if queue_key:
        issue_data["queue_key"] = queue_key
        issue_data["queue_name"] = queue_name
    return queue_key, queue_name


def _apply_default_assignee(
    issue_data: dict[str, Any],
    *,
    tenant_id: str | None,
    project_id: str,
    channel: dict[str, Any] | None = None,
) -> str:
    if _string_from(issue_data.get("assignee_email")):
        return _string_from(issue_data.get("assignee_email"))
    assignee = _default_issue_assignee(
        tenant_id=tenant_id,
        project_id=project_id,
        channel=channel,
        queue_key=_queue_key_from(issue_data.get("queue_key")),
    )
    if assignee:
        _ensure_queue_allows_assignee(
            tenant_id=tenant_id,
            project_id=project_id,
            queue_key=_queue_key_from(issue_data.get("queue_key")),
            assignee_email=assignee,
        )
        issue_data["assignee_email"] = assignee
    return assignee


def _mark_assignment_required(
    issue_data: dict[str, Any],
    *,
    source: str,
    channel: dict[str, Any] | None = None,
    context: dict[str, Any] | None = None,
) -> bool:
    if _string_from(issue_data.get("assignee_email")):
        return False
    metadata = _parse(issue_data.get("metadata"), dict)
    channel_key = _string_from((channel or {}).get("channelKey"))
    metadata.update({
        "assignmentRequired": True,
        "assignmentReason": "no_default_assignee",
        "assignmentSource": _string_from(source),
        "assignmentQueueKey": _queue_key_from(issue_data.get("queue_key")),
        "assignmentQueueName": _string_from(issue_data.get("queue_name")),
        "assignmentChannelKey": channel_key,
        "assignmentHint": "Configure a channel or queue default assignee, or approve an automation assignment.",
    })
    if context:
        metadata["assignmentContext"] = {
            key: value
            for key, value in context.items()
            if isinstance(value, (str, int, float, bool)) and _string_from(value)
        }
    issue_data["metadata"] = metadata
    return True


def _record_default_assignment(
    *,
    issue_id: str,
    assignee_email: str,
    tenant_id: str | None,
    project_id: str,
    idempotent: bool = False,
) -> None:
    if not assignee_email:
        return
    if idempotent:
        existing = _first(
            "support_issue_assignments",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=(
                    f"issue='{_escape_pb(issue_id)}' && "
                    f"assignee_email='{_escape_pb(assignee_email)}' && "
                    "assigned_by='routing' && status='assigned'"
                ),
            ),
        )
        if existing:
            return
    _record_assignment(
        issue_id=issue_id,
        assignee_email=assignee_email,
        assigned_by="routing",
        tenant_id=tenant_id,
        project_id=project_id,
        operation_key="default_assignment" if idempotent else "",
    )


def _ensure_issue_sla_events(
    *,
    issue_id: str,
    tenant_id: str | None,
    project_id: str,
) -> None:
    policy = get_sla_policy(tenant_id=tenant_id, project_id=project_id)
    targets = (
        ("first_response_due", max(1, int(policy["firstResponseMinutes"]))),
        ("resolution_due", max(1, int(policy["resolutionMinutes"]))),
    )
    business_hours = _parse(policy.get("businessHours"), dict)
    business_hours_enabled = _bool_from(business_hours.get("enabled"))
    for event_type, minutes in targets:
        existing = _first(
            "support_sla_events",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"issue='{_escape_pb(issue_id)}' && event_type='{_escape_pb(event_type)}'",
            ),
        )
        if existing:
            continue
        target_at = _business_hours_target_at(minutes, business_hours)
        data: dict[str, Any] = {
            "id": generate_id(),
            "issue": issue_id,
            "event_type": event_type,
            "status": "pending",
            "target_at": target_at.isoformat(),
            "metadata": {
                "minutes": minutes,
                "policyId": policy.get("id", ""),
                "policyName": policy.get("name", "Default"),
                "businessHoursApplied": business_hours_enabled,
            },
        }
        if business_hours_enabled:
            data["metadata"]["businessHours"] = business_hours
        if tenant_id:
            data["tenant"] = tenant_id
        data["project"] = project_id
        _post("/api/collections/support_sla_events/records", data)


def _mark_issue_sla_met(
    *,
    issue_id: str,
    event_type: str,
    tenant_id: str | None,
    project_id: str,
) -> None:
    existing = _first(
        "support_sla_events",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"issue='{_escape_pb(issue_id)}' && event_type='{_escape_pb(event_type)}'",
        ),
    )
    if not existing:
        return
    if existing.get("status") == "met":
        return
    _patch(
        f"/api/collections/support_sla_events/records/{existing['id']}",
        {"status": "met", "occurred_at": _now_iso()},
    )


def _record_assignment(
    *,
    issue_id: str,
    assignee_email: str,
    assigned_by: str,
    tenant_id: str | None,
    project_id: str,
    operation_key: str = "",
) -> None:
    assignment_id = (
        _stable_record_id(
            "support_issue_assignment",
            project_id,
            issue_id,
            operation_key,
            assignee_email,
        )
        if operation_key
        else generate_id()
    )
    data: dict[str, Any] = {
        "id": assignment_id,
        "issue": issue_id,
        "assignee_email": assignee_email,
        "assigned_by": assigned_by,
        "status": "assigned" if assignee_email else "unassigned",
    }
    if tenant_id:
        data["tenant"] = tenant_id
    data["project"] = project_id
    try:
        assignment = _post("/api/collections/support_issue_assignments/records", data)
    except httpx.HTTPStatusError as exc:
        if not operation_key or exc.response.status_code not in {400, 409}:
            raise
        winner = _first(
            "support_issue_assignments",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"id='{_escape_pb(assignment_id)}'",
            ),
        )
        if not winner:
            raise
        assignment = winner
    _notify_issue_assigned(
        issue_id=issue_id,
        assignee_email=assignee_email,
        assigned_by=assigned_by,
        assignment_id=_string_from(assignment.get("id")),
        tenant_id=tenant_id,
        project_id=project_id,
        dedupe=bool(operation_key),
    )


def _record_issue_event(
    *,
    issue_id: str,
    event_type: str,
    tenant_id: str | None,
    project_id: str,
    actor_email: str = "",
    title: str = "",
    body: str = "",
    from_status: str = "",
    to_status: str = "",
    from_priority: str = "",
    to_priority: str = "",
    metadata: dict[str, Any] | None = None,
    record_id: str = "",
) -> dict[str, Any] | None:
    if not issue_id:
        return
    data: dict[str, Any] = {
        "issue": issue_id,
        "event_type": event_type,
        "actor_email": actor_email,
        "title": title or event_type.replace("_", " ").title(),
        "body": body,
        "from_status": from_status,
        "to_status": to_status,
        "from_priority": from_priority,
        "to_priority": to_priority,
        "metadata": metadata or {},
        "occurred_at": _now_iso(),
    }
    if record_id:
        data["id"] = record_id
    if tenant_id:
        data["tenant"] = tenant_id
    data["project"] = project_id
    try:
        return _post("/api/collections/support_issue_events/records", data)
    except httpx.HTTPStatusError as exc:
        if not record_id or exc.response.status_code not in {400, 409}:
            raise
        winner = _first(
            "support_issue_events",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"id='{_escape_pb(record_id)}'",
            ),
        )
        if not winner:
            raise
        return winner


def _create_issue_notification(
    *,
    issue_id: str,
    recipient_email: str,
    notification_type: str,
    title: str,
    body: str,
    tenant_id: str | None,
    project_id: str,
    actor_email: str = "",
    metadata: dict[str, Any] | None = None,
    dedupe_metadata_key: str = "",
) -> dict[str, Any] | None:
    recipient = _string_from(recipient_email).lower()
    if not issue_id or not recipient:
        return None
    actor = _string_from(actor_email).lower()
    if actor and actor == recipient:
        return None
    notification_metadata = metadata or {}
    dedupe_value = _string_from(notification_metadata.get(dedupe_metadata_key))
    deterministic_id = ""
    if dedupe_metadata_key and dedupe_value:
        existing_records = _list_all(
            "support_notifications",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=(
                    f"issue='{_escape_pb(issue_id)}' && "
                    f"recipient_email='{_escape_pb(recipient)}' && "
                    f"type='{_escape_pb(notification_type)}'"
                ),
            ),
            sort="-created",
            per_page=200,
        )
        for existing in existing_records:
            existing_metadata = _parse(existing.get("metadata"), dict)
            if _string_from(existing_metadata.get(dedupe_metadata_key)) == dedupe_value:
                return _normalize_notification(existing)
        deterministic_id = _stable_record_id(
            "support_notification",
            project_id,
            issue_id,
            notification_type,
            recipient,
            dedupe_metadata_key,
            dedupe_value,
        )
    data: dict[str, Any] = {
        "id": deterministic_id or generate_id(),
        "project": project_id,
        "issue": issue_id,
        "recipient_email": recipient,
        "type": notification_type,
        "title": title,
        "body": body,
        "status": "unread",
        "metadata": notification_metadata,
    }
    if tenant_id:
        data["tenant"] = tenant_id
    try:
        created = _post("/api/collections/support_notifications/records", data)
    except httpx.HTTPStatusError as exc:
        if not deterministic_id or exc.response.status_code not in {400, 409}:
            raise
        winner = _first(
            "support_notifications",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"id='{_escape_pb(deterministic_id)}'",
            ),
        )
        if not winner:
            raise
        created = winner
    return _normalize_notification(created)


def _notification_issue_summary(
    *,
    issue_id: str,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, str]:
    issue = _first(
        "support_issues",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"id='{_escape_pb(issue_id)}'",
        ),
    )
    if not issue:
        return {"subject": "Ticket", "contact": "", "account": "", "priority": ""}
    return {
        "subject": _string_from(issue.get("subject")) or "Ticket",
        "contact": _string_from(issue.get("contact_email") or issue.get("from_address")),
        "account": _string_from(issue.get("account_name")),
        "priority": _string_from(issue.get("priority")),
    }


