def _notify_customer_message_subscribers(
    *,
    issue: dict[str, Any],
    issue_id: str,
    source: str,
    message_id: str,
    body: str,
    actor_email: str,
    tenant_id: str | None,
    project_id: str,
    metadata: dict[str, Any] | None = None,
) -> None:
    assignee = _string_from(issue.get("assigneeEmail") or issue.get("assignee_email")).lower()
    subject = _string_from(issue.get("subject")) or "Ticket"
    preview = _clip(body, 180) or subject
    source_label = _string_from(source).replace("_", " ").title() or "Customer"
    notification_metadata = {
        **(metadata or {}),
        "source": source,
        "messageId": message_id,
        "subject": subject,
        "preview": preview,
    }
    notified: set[str] = set()
    if assignee:
        assignee_notification = _create_issue_notification(
            issue_id=issue_id,
            recipient_email=assignee,
            notification_type="customer_message",
            title=f"{source_label} reply",
            body=preview,
            actor_email=actor_email,
            tenant_id=tenant_id,
            project_id=project_id,
            metadata=notification_metadata,
        )
        if assignee_notification:
            notified.add(assignee)
    actor = _string_from(actor_email).lower()
    if actor:
        notified.add(actor)
    _notify_issue_watchers(
        issue_id=issue_id,
        event_type="customer_message",
        title=f"{source_label} reply",
        body=preview,
        actor_email=actor_email,
        tenant_id=tenant_id,
        project_id=project_id,
        exclude_emails=notified,
        metadata=notification_metadata,
    )


def _notify_reply_approval_required(
    *,
    issue: dict[str, Any],
    reply: dict[str, Any],
    actor_email: str,
    tenant_id: str | None,
    project_id: str,
    dedupe: bool = False,
) -> None:
    issue_id = _string_from(issue.get("id"))
    reply_id = _string_from(reply.get("id"))
    if not issue_id or not reply_id:
        return
    assignee = _string_from(issue.get("assigneeEmail") or issue.get("assignee_email")).lower()
    subject = _string_from(issue.get("subject")) or "Ticket"
    reply_metadata = _parse(reply.get("metadata"), dict)
    citations = [
        citation
        for citation in _parse(reply_metadata.get("citations"), list)
        if isinstance(citation, dict)
    ]
    access_policy = _record_from(reply_metadata.get("knowledgeAccessPolicy"))
    admin_only_output = access_policy.get("outputAdminOnly") is True or any(
        _string_from(citation.get("visibility")).lower() == "private"
        and citation.get("automationAllowed") is not True
        for citation in citations
    )
    body = (
        "Restricted knowledge answer. Project admin review required."
        if admin_only_output
        else _clip(_string_from(reply.get("body")), 180) or subject
    )
    metadata = {
        "replyId": reply_id,
        "replyStatus": _string_from(reply.get("status")),
        "source": _string_from(reply_metadata.get("source")),
        "subject": subject,
        "preview": body,
    }
    if admin_only_output:
        metadata["knowledgeOutputRestricted"] = True
    notified: set[str] = set()
    if assignee:
        notification = _create_issue_notification(
            issue_id=issue_id,
            recipient_email=assignee,
            notification_type="approval_required",
            title="Reply needs approval",
            body=body,
            actor_email=actor_email,
            tenant_id=tenant_id,
            project_id=project_id,
            metadata=metadata,
            dedupe_metadata_key="replyId" if dedupe else "",
        )
        if notification:
            notified.add(assignee)
    actor = _string_from(actor_email).lower()
    if actor:
        notified.add(actor)
    _notify_issue_watchers(
        issue_id=issue_id,
        event_type="approval_required",
        title="Reply needs approval",
        body=body,
        actor_email=actor_email,
        tenant_id=tenant_id,
        project_id=project_id,
        exclude_emails=notified,
        metadata=metadata,
        dedupe_metadata_key="replyId" if dedupe else "",
    )


def _notify_reply_delivery_failed(
    *,
    issue_id: str,
    reply: dict[str, Any],
    error: str,
    tenant_id: str | None,
    project_id: str,
) -> None:
    clean_issue_id = _string_from(issue_id)
    reply_id = _string_from(reply.get("id"))
    if not clean_issue_id or not reply_id:
        return
    issue = _first(
        "support_issues",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"id='{_escape_pb(clean_issue_id)}'",
        ),
    ) or {}
    subject = _string_from(issue.get("subject")) or _string_from(reply.get("subject")) or "Ticket"
    body = _clip(error, 180) or _clip(_string_from(reply.get("body")), 180) or subject
    metadata = {
        "replyId": reply_id,
        "replyStatus": _string_from(reply.get("status")),
        "provider": _string_from(reply.get("provider")),
        "providerMessageId": _string_from(reply.get("provider_message_id") or reply.get("providerMessageId")),
        "subject": subject,
        "error": error,
    }
    recipients = [
        _string_from(issue.get("assignee_email") or issue.get("assigneeEmail")).lower(),
        _string_from(reply.get("created_by") or reply.get("createdBy") or reply.get("from_address") or reply.get("fromAddress")).lower(),
    ]
    notified: set[str] = set()
    for recipient in recipients:
        if not recipient or recipient in notified:
            continue
        notification = _create_issue_notification(
            issue_id=clean_issue_id,
            recipient_email=recipient,
            notification_type="delivery_failed",
            title="Reply delivery failed",
            body=body,
            actor_email="",
            tenant_id=tenant_id,
            project_id=project_id,
            metadata=metadata,
        )
        if notification:
            notified.add(recipient)
    _notify_issue_watchers(
        issue_id=clean_issue_id,
        event_type="delivery_failed",
        title="Reply delivery failed",
        body=body,
        actor_email="",
        tenant_id=tenant_id,
        project_id=project_id,
        exclude_emails=notified,
        metadata=metadata,
    )


_MENTION_RE = re.compile(r"(?<![\w.+-])@([A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,})")


def _mentioned_emails(text: str) -> list[str]:
    seen: set[str] = set()
    emails: list[str] = []
    for match in _MENTION_RE.findall(text or ""):
        email = match.lower().strip()
        if email and email not in seen:
            seen.add(email)
            emails.append(email)
    return emails


def _upsert_issue_watcher(
    *,
    issue_id: str,
    watcher_email: str,
    added_by: str,
    source: str,
    tenant_id: str | None,
    project_id: str,
    metadata: dict[str, Any] | None = None,
) -> dict[str, Any] | None:
    watcher = _string_from(watcher_email).lower()
    if not issue_id or not watcher:
        return None
    existing = _first(
        "support_issue_watchers",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"issue='{_escape_pb(issue_id)}' && watcher_email='{_escape_pb(watcher)}'",
        ),
    )
    data: dict[str, Any] = {
        "watcher_email": watcher,
        "added_by": added_by,
        "source": source,
        "status": "active",
        "metadata": metadata or {},
    }
    if existing:
        patched = _patch(f"/api/collections/support_issue_watchers/records/{existing['id']}", data)
        return _normalize_watcher({**existing, **patched, **data})
    create_data = {
        "id": generate_id(),
        "issue": issue_id,
        **data,
    }
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _normalize_watcher(_post("/api/collections/support_issue_watchers/records", create_data))


def _remove_issue_watcher(
    *,
    issue_id: str,
    watcher_email: str,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any] | None:
    watcher = _string_from(watcher_email).lower()
    if not issue_id or not watcher:
        return None
    existing = _first(
        "support_issue_watchers",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"issue='{_escape_pb(issue_id)}' && watcher_email='{_escape_pb(watcher)}'",
        ),
    )
    if not existing:
        return None
    data = {"status": "removed"}
    patched = _patch(f"/api/collections/support_issue_watchers/records/{existing['id']}", data)
    return _normalize_watcher({**existing, **patched, **data})


def _notify_issue_watchers(
    *,
    issue_id: str,
    event_type: str,
    title: str,
    body: str,
    actor_email: str,
    tenant_id: str | None,
    project_id: str,
    exclude_emails: set[str] | None = None,
    metadata: dict[str, Any] | None = None,
    dedupe_metadata_key: str = "",
) -> None:
    excluded = {email.lower() for email in (exclude_emails or set())}
    for watcher in _list_issue_watchers(issue_id=issue_id, tenant_id=tenant_id, project_id=project_id):
        recipient = _string_from(watcher.get("watcherEmail")).lower()
        if not recipient or recipient in excluded:
            continue
        _create_issue_notification(
            issue_id=issue_id,
            recipient_email=recipient,
            notification_type=event_type,
            title=title,
            body=body,
            actor_email=actor_email,
            tenant_id=tenant_id,
            project_id=project_id,
            metadata={
                **(metadata or {}),
                "watcherId": watcher.get("id", ""),
                "watcherSource": watcher.get("source", ""),
            },
            dedupe_metadata_key=dedupe_metadata_key,
        )


def _external_provider(identity_data: dict[str, Any]) -> str:
    return (
        _first_string(identity_data, ("provider", "source", "crm", "crmProvider", "crm_provider", "system"))
        or "identity"
    )


def _external_url(identity_data: dict[str, Any], keys: tuple[str, ...]) -> str:
    return _first_string(identity_data, keys)


def _crm_signal_key(value: Any) -> str:
    raw = _string_from(value)
    if not raw:
        return ""
    camel_split = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", raw)
    return re.sub(r"[^a-z0-9]+", "_", camel_split.lower()).strip("_")[:120]


def _crm_signal_value(value: Any) -> str:
    if isinstance(value, dict):
        direct = _first_string(value, ("label", "name", "value", "status", "health", "risk", "title", "description"))
        if direct:
            return direct
        parts = [_crm_signal_value(item) for item in list(value.values())[:5]]
        return ", ".join(part for part in parts if part)[:600]
    if isinstance(value, list):
        parts = [_crm_signal_value(item) for item in value[:8]]
        return ", ".join(part for part in parts if part)[:600]
    return _string_from(value)[:600]


def _crm_signal_fields(raw: dict[str, Any], *, depth: int = 0) -> list[tuple[str, Any]]:
    if depth > 3:
        return []
    fields: list[tuple[str, Any]] = []
    for key, value in raw.items():
        field_key = _crm_signal_key(key)
        if not field_key:
            continue
        if (
            field_key in CRM_RISK_FIELD_KEYS
            or field_key in CRM_FEATURE_FIELD_KEYS
            or field_key.endswith("_risk")
            or field_key.endswith("_health")
            or field_key.endswith("_features")
        ):
            fields.append((field_key, value))
            continue
        if isinstance(value, dict) and field_key in CRM_SIGNAL_WRAPPER_KEYS:
            fields.extend(_crm_signal_fields(value, depth=depth + 1))
    return fields


def _crm_value_key(value: str) -> str:
    return re.sub(r"[^a-z0-9.]+", "_", value.lower()).strip("_")


def _crm_numeric_risk(value_key: str) -> float | None:
    try:
        raw = value_key.removesuffix("percent").strip("_")
        score = float(raw)
    except ValueError:
        return None
    if score > 1:
        score = score / 100
    return score


def _crm_risk_severity(field_key: str, value_text: str) -> str:
    value_key = _crm_value_key(value_text)
    if not value_key or value_key in {"0", "false", "green", "good", "healthy", "low", "low_risk", "none", "no", "ok"}:
        return ""
    if field_key in {"at_risk", "blocked"} and value_key in {"1", "true", "yes"}:
        return "high"
    numeric = _crm_numeric_risk(value_key)
    if numeric is not None:
        if numeric >= 0.7:
            return "high"
        if numeric >= 0.4:
            return "needs_attention"
        return ""
    if any(hint in value_key for hint in ("at_risk", "blocked", "churn", "critical", "high", "red", "unhealthy")):
        return "high"
    if any(hint in value_key for hint in ("amber", "delayed", "medium", "needs_attention", "risk", "warning", "watch", "yellow")):
        return "needs_attention"
    if "risk" in field_key or "health" in field_key or field_key in {"sentiment", "status", "support_status"}:
        return "needs_attention"
    return ""


def _crm_feature_requested(value_text: str) -> bool:
    value_key = _crm_value_key(value_text)
    return bool(value_key and value_key not in {"0", "false", "none", "no", "n_a", "na"})


def _crm_signal_body(
    *,
    provider: str,
    object_type: str,
    display_name: str,
    field_key: str,
    value_text: str,
    external_url: str,
) -> str:
    label = field_key.replace("_", " ")
    parts = [f"{provider} {object_type} field '{label}' is {_clip(value_text, 220)}."]
    if display_name:
        parts.append(f"Object: {display_name}.")
    if external_url:
        parts.append(f"Source: {external_url}")
    return " ".join(parts)


def _sync_crm_account_insights(
    *,
    account_id: str,
    provider: str,
    object_type: str,
    external_id: str,
    external_url: str,
    display_name: str,
    raw: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
) -> None:
    if not account_id or not raw:
        return
    clean_provider = _key_from(provider) or "identity"
    clean_type = _key_from(object_type) or "object"
    stable_id = _string_from(external_id) or _string_from(raw.get("id")) or display_name or account_id
    seen_keys: set[str] = set()
    for field_key, value in _crm_signal_fields(raw):
        value_text = _crm_signal_value(value)
        if not value_text:
            continue
        base_key = f"crm:{clean_provider}:{clean_type}:{stable_id}:{field_key}"
        if base_key in seen_keys:
            continue
        seen_keys.add(base_key)
        if (
            field_key in CRM_RISK_FIELD_KEYS
            or field_key.endswith("_risk")
            or field_key.endswith("_health")
        ):
            severity = _crm_risk_severity(field_key, value_text)
            if not severity:
                continue
            _upsert_account_insight(
                account_id=account_id,
                insight_key=f"{base_key}:risk",
                insight_type="risk",
                title=f"CRM risk: {field_key.replace('_', ' ')}",
                body=_crm_signal_body(
                    provider=clean_provider,
                    object_type=clean_type,
                    display_name=display_name,
                    field_key=field_key,
                    value_text=value_text,
                    external_url=external_url,
                ),
                severity=severity,
                status="open",
                source_issue_id="",
                metadata={
                    "source": "crm_sync",
                    "provider": clean_provider,
                    "objectType": clean_type,
                    "externalId": stable_id,
                    "externalUrl": external_url,
                    "field": field_key,
                    "value": value_text,
                },
                tenant_id=tenant_id,
                project_id=project_id,
            )
        if field_key in CRM_FEATURE_FIELD_KEYS or field_key.endswith("_features"):
            if not _crm_feature_requested(value_text):
                continue
            _upsert_account_insight(
                account_id=account_id,
                insight_key=f"{base_key}:feature",
                insight_type="feature_request",
                title=f"CRM feature request: {_clip(value_text, 80)}",
                body=_crm_signal_body(
                    provider=clean_provider,
                    object_type=clean_type,
                    display_name=display_name,
                    field_key=field_key,
                    value_text=value_text,
                    external_url=external_url,
                ),
                severity="info",
                status="open",
                source_issue_id="",
                metadata={
                    "source": "crm_sync",
                    "provider": clean_provider,
                    "objectType": clean_type,
                    "externalId": stable_id,
                    "externalUrl": external_url,
                    "field": field_key,
                    "value": value_text,
                },
                tenant_id=tenant_id,
                project_id=project_id,
            )


def _upsert_external_object(
    *,
    account_id: str,
    contact_id: str,
    provider: str,
    object_type: str,
    external_id: str,
    external_url: str,
    display_name: str,
    raw: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any] | None:
    clean_provider = _key_from(provider) or "identity"
    clean_type = _key_from(object_type)
    clean_external_id = external_id.strip()
    if not clean_type or not clean_external_id:
        return None
    existing = _first(
        "support_external_objects",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=(
                f"provider='{_escape_pb(clean_provider)}' && "
                f"object_type='{_escape_pb(clean_type)}' && "
                f"external_id='{_escape_pb(clean_external_id)}'"
            ),
        ),
    )
    data: dict[str, Any] = {
        "provider": clean_provider,
        "object_type": clean_type,
        "external_id": clean_external_id,
        "external_url": external_url.strip(),
        "display_name": display_name.strip(),
        "raw": raw,
        "last_seen_at": _now_iso(),
    }
    if account_id:
        data["account"] = account_id
    if contact_id:
        data["contact"] = contact_id
    if existing:
        _patch(f"/api/collections/support_external_objects/records/{existing['id']}", data)
        external_object = _normalize_external_object({**existing, **data})
        _sync_crm_account_insights(
            account_id=account_id,
            provider=clean_provider,
            object_type=clean_type,
            external_id=clean_external_id,
            external_url=data["external_url"],
            display_name=data["display_name"],
            raw=raw,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        return external_object
    create_data = {"id": generate_id(), **data}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    external_object = _normalize_external_object(_post("/api/collections/support_external_objects/records", create_data))
    _sync_crm_account_insights(
        account_id=account_id,
        provider=clean_provider,
        object_type=clean_type,
        external_id=clean_external_id,
        external_url=data["external_url"],
        display_name=data["display_name"],
        raw=raw,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    return external_object


def _record_external_sync_run(
    *,
    account_id: str,
    source_issue_id: str,
    provider: str,
    status: str,
    objects_seen: int,
    result: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
) -> None:
    record_external_sync_run(
        account_id=account_id,
        source_issue_id=source_issue_id,
        provider=provider,
        status=status,
        objects_seen=objects_seen,
        error="",
        result=result,
        tenant_id=tenant_id,
        project_id=project_id,
    )


