def record_external_sync_run(
    *,
    account_id: str,
    provider: str,
    status: str,
    objects_seen: int,
    source_issue_id: str = "",
    error: str = "",
    result: dict[str, Any] | None = None,
    started_at: str = "",
    completed_at: str = "",
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    data: dict[str, Any] = {
        "id": generate_id(),
        "provider": _key_from(provider) or "identity",
        "status": status,
        "objects_seen": objects_seen,
        "error": error,
        "result": result or {},
        "started_at": started_at or _now_iso(),
        "completed_at": completed_at or _now_iso(),
    }
    if account_id:
        data["account"] = account_id
    if source_issue_id:
        data["source_issue"] = source_issue_id
    if tenant_id:
        data["tenant"] = tenant_id
    data["project"] = project_id
    return _normalize_external_sync_run(_post("/api/collections/support_external_sync_runs/records", data))


def _sync_external_objects(
    *,
    account_id: str,
    contact_id: str,
    issue_id: str,
    identity: dict[str, str],
    identity_data: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
) -> None:
    if not account_id or not identity_data:
        return
    provider = _external_provider(identity_data)
    synced: list[dict[str, Any]] = []
    account_external_id = _first_string(
        identity_data,
        ("accountId", "account_id", "customerId", "customer_id", "companyId", "company_id", "organisationId", "organizationId", "id"),
    )
    if account_external_id:
        account_object = _upsert_external_object(
            account_id=account_id,
            contact_id="",
            provider=provider,
            object_type="account",
            external_id=account_external_id,
            external_url=_external_url(identity_data, ("accountUrl", "account_url", "customerUrl", "customer_url", "url")),
            display_name=identity["account_name"],
            raw=identity_data,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        if account_object:
            synced.append(account_object)
    contact_external_id = _first_string(
        identity_data,
        ("contactId", "contact_id", "personId", "person_id", "userId", "user_id"),
    )
    if contact_external_id and contact_id:
        contact_object = _upsert_external_object(
            account_id=account_id,
            contact_id=contact_id,
            provider=provider,
            object_type="contact",
            external_id=contact_external_id,
            external_url=_external_url(identity_data, ("contactUrl", "contact_url", "profileUrl", "profile_url")),
            display_name=identity["contact_name"] or identity["contact_email"],
            raw=identity_data,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        if contact_object:
            synced.append(contact_object)
    if synced:
        _record_external_sync_run(
            account_id=account_id,
            source_issue_id=issue_id,
            provider=provider,
            status="success",
            objects_seen=len(synced),
            result={"objects": synced},
            tenant_id=tenant_id,
            project_id=project_id,
        )


