def _upsert_account_insight(
    *,
    account_id: str,
    insight_key: str,
    insight_type: str,
    title: str,
    body: str,
    severity: str,
    status: str,
    source_issue_id: str,
    metadata: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    key = _key_from(insight_key)
    if not key:
        raise ValueError("Insight key is required")
    now = _now_iso()
    filter_str = _issue_filter(
        tenant_id=tenant_id,
        project_id=project_id,
        extra=f"account='{_escape_pb(account_id)}' && insight_key='{_escape_pb(key)}'",
    )
    existing = _first("support_account_insights", filter_str)
    data: dict[str, Any] = {
        "account": account_id,
        "insight_key": key,
        "type": insight_type,
        "title": title.strip(),
        "body": body.strip(),
        "severity": severity,
        "status": status,
        "metadata": metadata,
        "last_seen_at": now,
    }
    if source_issue_id:
        data["source_issue"] = source_issue_id
    if existing:
        _patch(f"/api/collections/support_account_insights/records/{existing['id']}", data)
        return _normalize_account_insight({**existing, **data})
    create_data = {"id": generate_id(), **data, "first_seen_at": now}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _normalize_account_insight(_post("/api/collections/support_account_insights/records", create_data))


def _issue_status_counts(issues: list[dict[str, Any]]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for issue in issues:
        status = _canonical_status(_string_from(issue.get("status")) or "open")
        counts[status] = counts.get(status, 0) + 1
    return counts


def _issue_priority_counts(issues: list[dict[str, Any]]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for issue in issues:
        priority = _string_from(issue.get("priority")) or "normal"
        counts[priority] = counts.get(priority, 0) + 1
    return counts


def _account_health_from_counts(status_counts: dict[str, int], priority_counts: dict[str, int]) -> str:
    if priority_counts.get("urgent", 0) > 0:
        return "at_risk"
    if priority_counts.get("high", 0) > 0 or status_counts.get("ongoing", 0) > 0:
        return "needs_attention"
    if status_counts.get("open", 0) > 0:
        return "active"
    return "healthy"


def _feature_request_signal(
    *,
    subject: str,
    activated_intent: str,
    messages: list[dict[str, Any]],
) -> bool:
    return bool(_support_signal_keywords(
        subject=subject,
        activated_intent=activated_intent,
        messages=messages,
        keywords=FEATURE_REQUEST_KEYWORDS,
    ))


def _support_signal_text_parts(
    *,
    subject: str,
    activated_intent: str,
    messages: list[dict[str, Any]],
) -> list[str]:
    text_parts: list[str] = []
    for message in messages:
        text_parts.append(_content_body(message.get("content") if "content" in message else message.get("body")))
    text_parts.extend([subject, activated_intent])
    return [part.strip() for part in text_parts if part and part.strip()]


def _support_signal_keywords(
    *,
    subject: str,
    activated_intent: str,
    messages: list[dict[str, Any]],
    keywords: tuple[str, ...],
) -> list[str]:
    haystack = " ".join(
        part.lower()
        for part in _support_signal_text_parts(
            subject=subject,
            activated_intent=activated_intent,
            messages=messages,
        )
    )
    return [keyword for keyword in keywords if keyword in haystack]


def _support_signal_evidence(
    *,
    subject: str,
    activated_intent: str,
    messages: list[dict[str, Any]],
    keywords: tuple[str, ...],
) -> str:
    matched = _support_signal_keywords(
        subject=subject,
        activated_intent=activated_intent,
        messages=messages,
        keywords=keywords,
    )
    if not matched:
        return ""
    for part in _support_signal_text_parts(
        subject=subject,
        activated_intent=activated_intent,
        messages=messages,
    ):
        lower = part.lower()
        if any(keyword in lower for keyword in matched):
            return _clip(part, 500)
    return ""


def _signal_category(
    matched_keywords: list[str],
    categories: tuple[dict[str, Any], ...],
) -> dict[str, Any]:
    if not matched_keywords:
        return {}
    matched = {keyword.lower() for keyword in matched_keywords}
    for category in categories:
        category_keywords = {
            _string_from(keyword).lower()
            for keyword in category.get("keywords", ())
            if _string_from(keyword)
        }
        if matched.intersection(category_keywords):
            return category
    return {}


def _risk_signal_category(matched_keywords: list[str]) -> dict[str, Any]:
    return _signal_category(matched_keywords, ACCOUNT_RISK_SIGNAL_CATEGORIES)


def _feature_signal_category(matched_keywords: list[str]) -> dict[str, Any]:
    return _signal_category(matched_keywords, FEATURE_SIGNAL_CATEGORIES)


def _risk_insight_title(category: dict[str, Any]) -> str:
    label = _string_from(category.get("label"))
    return f"{label} detected" if label else "Account risk detected"


def _feature_insight_title(category: dict[str, Any], matched_keywords: list[str]) -> str:
    label = _string_from(category.get("label"))
    if label:
        return label
    matched_feature = matched_keywords[0].replace("_", " ") if matched_keywords else "feature"
    title = f"Feature request: {matched_feature}"
    return "Feature request detected" if title == "Feature request: feature request" else title


def _risk_signal_severity(category: dict[str, Any], priority: str) -> str:
    if priority == "urgent":
        return "urgent"
    category_severity = _string_from(category.get("severity"))
    if category_severity:
        return category_severity
    return "high"


def _sync_account_insights(
    *,
    account_id: str | None,
    issue: dict[str, Any],
    messages: list[dict[str, Any]],
    tenant_id: str | None,
    project_id: str,
) -> None:
    if not account_id:
        return
    issue_id = _string_from(issue.get("id"))
    if not issue_id:
        return
    account_issues = _list_all(
        "support_issues",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"account='{_escape_pb(account_id)}'",
        ),
        sort="-latest_message_at",
        per_page=100,
    )
    if not account_issues:
        account_issues = [issue]
    status_counts = _issue_status_counts(account_issues)
    priority_counts = _issue_priority_counts(account_issues)
    health_status = _account_health_from_counts(status_counts, priority_counts)
    open_count = status_counts.get("open", 0) + status_counts.get("ongoing", 0)
    high_count = priority_counts.get("high", 0) + priority_counts.get("urgent", 0)
    latest_subject = _string_from(issue.get("subject")) or "Latest support issue"
    _patch(
        f"/api/collections/support_accounts/records/{account_id}",
        {"health_status": health_status},
    )
    _upsert_account_insight(
        account_id=account_id,
        insight_key="account_summary",
        insight_type="summary",
        title="Account support summary",
        body=(
            f"{len(account_issues)} total issues. {open_count} open or waiting. "
            f"{high_count} high or urgent. Latest: {latest_subject}."
        ),
        severity=health_status,
        status="active",
        source_issue_id=issue_id,
        metadata={"statusCounts": status_counts, "priorityCounts": priority_counts},
        tenant_id=tenant_id,
        project_id=project_id,
    )
    subject = _string_from(issue.get("subject"))
    activated_intent = _string_from(issue.get("activated_intent"))
    risk_keywords = _support_signal_keywords(
        subject=subject,
        activated_intent=activated_intent,
        messages=messages,
        keywords=ACCOUNT_RISK_KEYWORDS,
    )
    risk_evidence = _support_signal_evidence(
        subject=subject,
        activated_intent=activated_intent,
        messages=messages,
        keywords=ACCOUNT_RISK_KEYWORDS,
    )
    priority = _string_from(issue.get("priority")) or "normal"
    requires_human = bool(issue.get("requires_human"))
    if priority in {"high", "urgent"} or requires_human or risk_keywords:
        risk_category = _risk_signal_category(risk_keywords)
        _upsert_account_insight(
            account_id=account_id,
            insight_key=f"risk:{issue_id}",
            insight_type="risk",
            title=_risk_insight_title(risk_category) if risk_keywords else "Support risk needs attention",
            body=_clip(risk_evidence or _string_from(issue.get("ai_summary")) or latest_subject, 500),
            severity=_risk_signal_severity(risk_category, priority),
            status="open",
            source_issue_id=issue_id,
            metadata={
                "source": "issue_signal" if risk_keywords else "issue_priority",
                "priority": priority,
                "requiresHuman": requires_human,
                "matchedKeywords": risk_keywords,
                "evidence": risk_evidence,
                **({
                    "signalCategory": risk_category.get("key"),
                    "recommendedAction": risk_category.get("nextAction"),
                    "actionKind": risk_category.get("kind"),
                } if risk_category else {}),
            },
            tenant_id=tenant_id,
            project_id=project_id,
        )
    feature_keywords = _support_signal_keywords(
        subject=subject,
        activated_intent=activated_intent,
        messages=messages,
        keywords=FEATURE_REQUEST_KEYWORDS,
    )
    if feature_keywords:
        feature_evidence = _support_signal_evidence(
            subject=subject,
            activated_intent=activated_intent,
            messages=messages,
            keywords=FEATURE_REQUEST_KEYWORDS,
        )
        feature_category = _feature_signal_category(feature_keywords)
        _upsert_account_insight(
            account_id=account_id,
            insight_key=f"feature_request:{issue_id}",
            insight_type="feature_request",
            title=_feature_insight_title(feature_category, feature_keywords),
            body=_clip(feature_evidence or latest_subject, 500),
            severity="info",
            status="open",
            source_issue_id=issue_id,
            metadata={
                "source": "issue_keyword",
                "matchedKeywords": feature_keywords,
                "evidence": feature_evidence,
                **({"signalCategory": feature_category.get("key")} if feature_category else {}),
            },
            tenant_id=tenant_id,
            project_id=project_id,
        )


def _sync_channel_account_insights(
    *,
    account_id: str | None,
    issue: dict[str, Any],
    body: str,
    tenant_id: str | None,
    project_id: str,
) -> None:
    if not account_id:
        return
    try:
        _sync_account_insights(
            account_id=account_id,
            issue=issue,
            messages=[{"body": body}],
            tenant_id=tenant_id,
            project_id=project_id,
        )
    except Exception:
        # Optional account intelligence must never block inbound channel ingestion.
        return


def _knowledge_gap_article_match(
    *,
    subject: str,
    activated_intent: str,
    tenant_id: str | None,
    project_id: str,
) -> bool:
    tokens = {
        token
        for token in " ".join((subject, activated_intent)).lower().replace("/", " ").split()
        if len(token) >= 5
    }
    if not tokens:
        return False
    articles = _list_all(
        "knowledge_articles",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra="status='published'"),
        sort="-updated",
        per_page=100,
    )
    for article in articles:
        article_text = " ".join(
            (
                _string_from(article.get("title")),
                _string_from(article.get("body")),
                " ".join(str(tag) for tag in _parse(article.get("tags"), list)),
            )
        ).lower()
        if any(token in article_text for token in tokens):
            return True
    return False


def _knowledge_gap_needed(
    *,
    issue: dict[str, Any],
    messages: list[dict[str, Any]],
    tenant_id: str | None,
    project_id: str,
) -> bool:
    if _workflow_status(_string_from(issue.get("status"))) == "done":
        return False
    subject = _string_from(issue.get("subject"))
    activated_intent = _string_from(issue.get("activated_intent"))
    missing_runbook = not activated_intent
    missing_reply = not _draft_reply(messages)
    needs_human = bool(issue.get("requires_human"))
    high_priority = _string_from(issue.get("priority")) in {"high", "urgent"}
    if not (missing_runbook or missing_reply or needs_human or high_priority):
        return False
    return not _knowledge_gap_article_match(
        subject=subject,
        activated_intent=activated_intent,
        tenant_id=tenant_id,
        project_id=project_id,
    )


def _upsert_knowledge_gap(
    *,
    issue: dict[str, Any],
    messages: list[dict[str, Any]],
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    issue_id = _string_from(issue.get("id"))
    subject = _string_from(issue.get("subject")) or "Unresolved support issue"
    gap_key = _key_from(f"issue:{issue_id}:missing_knowledge")
    now = _now_iso()
    filter_str = _issue_filter(
        tenant_id=tenant_id,
        project_id=project_id,
        extra=f"gap_key='{_escape_pb(gap_key)}'",
    )
    existing = _first("support_knowledge_gaps", filter_str)
    priority = _string_from(issue.get("priority")) or "normal"
    severity = "high" if priority in {"high", "urgent"} else "normal"
    evidence = _clip(_string_from(issue.get("ai_summary")) or _email_body(messages) or subject, 900)
    data: dict[str, Any] = {
        "issue": issue_id,
        "gap_key": gap_key,
        "title": f"Knowledge gap: {subject}",
        "evidence": evidence,
        "status": "open",
        "severity": severity,
        "suggested_article_title": subject,
        "metadata": {
            "priority": priority,
            "activatedIntent": _string_from(issue.get("activated_intent")),
            "requiresHuman": bool(issue.get("requires_human")),
        },
        "last_seen_at": now,
    }
    if existing:
        _patch(f"/api/collections/support_knowledge_gaps/records/{existing['id']}", data)
        return _normalize_knowledge_gap({**existing, **data})
    create_data = {"id": generate_id(), **data, "first_seen_at": now}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _normalize_knowledge_gap(_post("/api/collections/support_knowledge_gaps/records", create_data))


def _sync_knowledge_gap(
    *,
    issue: dict[str, Any],
    messages: list[dict[str, Any]],
    tenant_id: str | None,
    project_id: str,
) -> None:
    if _knowledge_gap_needed(issue=issue, messages=messages, tenant_id=tenant_id, project_id=project_id):
        _upsert_knowledge_gap(issue=issue, messages=messages, tenant_id=tenant_id, project_id=project_id)


def _agent_answer_weak_knowledge_signals(
    *,
    articles: list[dict[str, Any]],
    confidence: str,
    generation_error: str,
) -> list[str]:
    signals: list[str] = []
    if not articles:
        signals.append("no_citations")
    if confidence.strip().lower() == "low":
        signals.append("low_confidence")
    if generation_error.strip():
        signals.append("generation_error")
    return signals


def _upsert_agent_answer_knowledge_gap(
    *,
    issue: dict[str, Any],
    messages: list[dict[str, Any]],
    tenant_id: str | None,
    project_id: str,
    author_email: str,
    question: str,
    answer: str,
    confidence: str,
    articles: list[dict[str, Any]],
    run: dict[str, Any],
    reply: dict[str, Any] | None,
    generation_mode: str,
    generation_error: str,
    knowledge_accessed_article_ids: set[str] | None = None,
    knowledge_context_article_ids: set[str] | None = None,
    knowledge_lineage: list[dict[str, Any]] | None = None,
    knowledge_access_policy: dict[str, Any] | None = None,
    automation_context: dict[str, Any] | None = None,
) -> dict[str, Any] | None:
    signals = _agent_answer_weak_knowledge_signals(
        articles=articles,
        confidence=confidence,
        generation_error=generation_error,
    )
    if not signals:
        return None

    issue_id = _string_from(issue.get("id"))
    if not issue_id:
        return None

    subject = _string_from(issue.get("subject")) or "Support ticket"
    clean_question = question.strip()
    question_or_subject = clean_question or subject
    gap_key = _key_from(f"issue:{issue_id}:agent_answer:{_key_from(question_or_subject) or 'default'}")
    now = _now_iso()
    filter_str = _issue_filter(
        tenant_id=tenant_id,
        project_id=project_id,
        extra=f"gap_key='{_escape_pb(gap_key)}'",
    )
    existing_records = _list_all("support_knowledge_gaps", filter_str, sort="-updated", per_page=1)
    existing = existing_records[0] if existing_records else None
    priority = _string_from(issue.get("priority")) or "normal"
    severity = "high" if priority in {"high", "urgent"} or confidence.strip().lower() == "low" or generation_error else "normal"
    latest_customer_message = next(
        (_string_from(message.get("body")) for message in reversed(messages) if message.get("direction") == "customer"),
        "",
    )
    evidence_lines = [
        f"Agent question: {clean_question or 'Draft approval-ready support answer.'}",
        f"Weak signal: {', '.join(signals)}",
        f"Confidence: {confidence or 'unknown'}",
        f"Citation count: {len(articles)}",
    ]
    if generation_error:
        evidence_lines.append(f"Generation error: {_clip(generation_error, 240)}")
    if latest_customer_message:
        evidence_lines.append(f"Customer context: {_clip(latest_customer_message, 360)}")
    if answer:
        evidence_lines.append(f"Agent answer preview: {_clip(answer, 360)}")
    metadata: dict[str, Any] = {
        "source": "agent_answer",
        "weakSignals": signals,
        "question": clean_question,
        "confidence": confidence,
        "citationCount": len(articles),
        "knowledgeArticleIds": [_string_from(article.get("id")) for article in articles],
        "knowledgeAccessedArticleIds": sorted(knowledge_accessed_article_ids or set()),
        "knowledgeContextArticleIds": sorted(knowledge_context_article_ids or set()),
        "knowledgeLineage": _knowledge_access_snapshots(knowledge_lineage or [])[:100],
        "knowledgeAccessPolicy": _record_from(knowledge_access_policy),
        "aiRunId": _string_from(run.get("id")),
        "replyId": _string_from(reply.get("id")) if reply else "",
        "authorEmail": author_email,
        "generationMode": generation_mode,
        "generationError": generation_error,
        "priority": priority,
    }
    clean_automation_context = _compact_metadata_context(automation_context)
    if clean_automation_context:
        metadata["automationContext"] = clean_automation_context

    data: dict[str, Any] = {
        "issue": issue_id,
        "gap_key": gap_key,
        "title": f"Knowledge gap: {_clip(question_or_subject, 140)}",
        "evidence": _clip("\n".join(evidence_lines), 1200),
        "status": "open",
        "severity": severity,
        "suggested_article_title": _clip(question_or_subject, 160),
        "metadata": metadata,
        "last_seen_at": now,
    }
    if existing:
        _patch(f"/api/collections/support_knowledge_gaps/records/{existing['id']}", data)
        return _normalize_knowledge_gap({**existing, **data})

    create_data = {"id": generate_id(), **data, "first_seen_at": now}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _normalize_knowledge_gap(_post("/api/collections/support_knowledge_gaps/records", create_data))


def _mark_issue_knowledge_gaps_resolved(
    *,
    issue_id: str,
    tenant_id: str | None,
    project_id: str,
) -> None:
    gaps = _list_all(
        "support_knowledge_gaps",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"issue='{_escape_pb(issue_id)}'",
        ),
        sort="-updated",
        per_page=50,
    )
    for gap in gaps:
        if gap.get("status") == "resolved":
            continue
        _patch(
            f"/api/collections/support_knowledge_gaps/records/{gap['id']}",
            {"status": "resolved", "last_seen_at": _now_iso()},
        )


def _mark_knowledge_gap_resolved(
    gap_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
) -> None:
    rec = _first(
        "support_knowledge_gaps",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"id='{_escape_pb(gap_id)}'",
        ),
    )
    if not rec or rec.get("status") == "resolved":
        return
    _patch(
        f"/api/collections/support_knowledge_gaps/records/{rec['id']}",
        {"status": "resolved", "last_seen_at": _now_iso()},
    )


def _tool_calls_from_chat(
    *,
    identity_result: dict[str, Any],
    chat: dict[str, Any],
) -> list[dict[str, Any]]:
    collected: list[dict[str, Any]] = []
    for name in identity_result.get("toolCallsMade") or identity_result.get("tool_calls_made") or []:
        if isinstance(name, str) and name.strip():
            collected.append({"name": name.strip(), "stage": "identity", "status": "called"})
    chat_metadata = _record_from(chat.get("metadata"))
    raw_tools = (
        chat.get("tools_used")
        or chat.get("toolsUsed")
        or chat_metadata.get("toolsUsed")
        or chat_metadata.get("tools_used")
        or []
    )
    if isinstance(raw_tools, list):
        for item in raw_tools:
            if isinstance(item, dict):
                collected.append(item)
    return collected


def _email_pipeline_run_key(*, source: str, email_id: str) -> str:
    return _key_from(f"{source}:{email_id}:pipeline")


def _completed_email_pipeline_run(
    *,
    issue_id: str,
    email_id: str,
    source: str,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any] | None:
    run_key = _email_pipeline_run_key(source=source, email_id=email_id)
    existing = _first(
        "support_ai_runs",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"issue='{_escape_pb(issue_id)}' && run_key='{_escape_pb(run_key)}'",
        ),
    )
    if not existing:
        return None
    metadata = _parse(existing.get("metadata"), dict)
    completion = _record_from(metadata.get("issueSync"))
    return (
        existing
        if completion.get("version") == 1 and bool(_string_from(completion.get("completedAt")))
        else None
    )


def _mark_email_pipeline_run_completed(run: dict[str, Any] | None) -> None:
    run_id = _string_from((run or {}).get("id"))
    if not run_id:
        return
    metadata = {
        **_parse((run or {}).get("metadata"), dict),
        "issueSync": {"version": 1, "completedAt": _now_iso()},
    }
    _patch(
        f"/api/collections/support_ai_runs/records/{run_id}",
        {"metadata": metadata},
    )


def _upsert_ai_run_from_chat(
    *,
    issue_id: str,
    issue: dict[str, Any],
    chat: dict[str, Any],
    identity_result: dict[str, Any],
    intent_result: dict[str, Any],
    phishing_result: dict[str, Any],
    prompt_injection_result: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
    source: str,
) -> dict[str, Any] | None:
    email_id = _string_from(chat.get("email_id") or chat.get("id") or issue.get("source_email_id"))
    if not email_id:
        return
    run_key = _email_pipeline_run_key(source=source, email_id=email_id)
    existing = _first(
        "support_ai_runs",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"issue='{_escape_pb(issue_id)}' && run_key='{_escape_pb(run_key)}'",
        ),
    )
    now = _now_iso()
    requires_human = bool(issue.get("requires_human"))
    data: dict[str, Any] = {
        "issue": issue_id,
        "run_key": run_key,
        "source": source,
        "status": "needs_human" if requires_human else "success",
        "activated_intent": _string_from(issue.get("activated_intent")),
        "requires_human": requires_human,
        "summary": _string_from(issue.get("ai_summary")),
        "identity_result": identity_result,
        "intent_result": intent_result,
        "security_result": {
            "phishing": phishing_result,
            "promptInjection": prompt_injection_result,
        },
        "token_usage": _record_from(chat.get("token_usage")),
        "tool_calls": _tool_calls_from_chat(identity_result=identity_result, chat=chat),
        "metadata": {
            **_parse((existing or {}).get("metadata"), dict),
            "chatRecordId": _string_from(chat.get("record_id")),
            "emailId": email_id,
            "messageCount": int(issue.get("message_count") or 0),
        },
        "completed_at": now,
    }
    if existing:
        patched = _patch(f"/api/collections/support_ai_runs/records/{existing['id']}", data)
        return {**existing, **data, **patched}
    create_data = {"id": generate_id(), **data, "started_at": now}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    created = _post("/api/collections/support_ai_runs/records", create_data)
    return {**create_data, **created}


def _direct_channel_run_key(*, source: str, source_message_id: str) -> str:
    return _key_from(f"{source}:{source_message_id}:runbooks")


def _direct_channel_processing_run(
    *,
    issue_id: str,
    source: str,
    source_message_id: str,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any] | None:
    """Return the durable package run for one channel message, if any."""
    run_key = _direct_channel_run_key(
        source=source,
        source_message_id=source_message_id,
    )
    return _first(
        "support_ai_runs",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=(
                f"issue='{_escape_pb(issue_id)}' && "
                f"run_key='{_escape_pb(run_key)}'"
            ),
        ),
    )


def _direct_channel_run_can_resume_package(run: dict[str, Any]) -> bool:
    """Only resume after the runbook result has crossed its durable boundary."""
    if _string_from(run.get("status")).lower() != "processing":
        return False
    metadata = _parse(run.get("metadata"), dict)
    progress = _parse(metadata.get("processingProgress"), dict)
    stage = _string_from(progress.get("stage")).lower()
    return stage in {
        "automation",
        "triage",
        "ticket_fields",
        "composer",
        "finalizing",
    }


class DirectChannelProcessingInProgress(RuntimeError):
    """A live source-message worker still owns the direct-channel run."""


def _direct_processing_is_stale(
    run: dict[str, Any],
    *,
    now: datetime | None = None,
    lease_seconds: int = DIRECT_CHANNEL_PROCESSING_LEASE_SECONDS,
) -> bool:
    metadata = _parse(run.get("metadata"), dict)
    progress = _parse(metadata.get("processingProgress"), dict)
    last_update = _parse_iso_datetime(
        progress.get("updatedAt")
        or progress.get("updated_at")
        or run.get("updated")
        or run.get("started_at")
        or run.get("created")
    )
    if last_update is None:
        return True
    return ((now or _now_utc()) - last_update).total_seconds() >= max(1, lease_seconds)


def expire_stale_direct_channel_processing_runs_for_scope(
    *,
    tenant_id: str | None = None,
    project_id: str | None = None,
    limit: int = 200,
    lease_seconds: int = DIRECT_CHANNEL_PROCESSING_LEASE_SECONDS,
    source: str = "scheduler",
) -> dict[str, Any]:
    """Terminalize abandoned durable ticket processing without replaying it."""
    clean_limit = max(1, min(int(limit or 200), 500))
    now = _now_utc()
    now_iso = now.isoformat()
    scope_filters = ["status='processing'"]
    if project_id:
        scope_filters.append(f"project='{_escape_pb(project_id)}'")
    if tenant_id:
        scope_filters.append(f"tenant='{_escape_pb(tenant_id)}'")
    records = _list_all(
        "support_ai_runs",
        " && ".join(scope_filters),
        sort="started_at",
        per_page=clean_limit,
    )
    inspected = 0
    expired = 0
    skipped = 0
    failed = 0
    items: list[dict[str, Any]] = []
    for candidate in records:
        metadata = _parse(candidate.get("metadata"), dict)
        processing_kind = _string_from(metadata.get("kind"))
        if processing_kind not in DURABLE_PROCESSING_RUN_KINDS:
            continue
        if inspected >= clean_limit:
            break
        inspected += 1
        run_id = _string_from(candidate.get("id"))
        if not run_id or not _direct_processing_is_stale(
            candidate,
            now=now,
            lease_seconds=lease_seconds,
        ):
            skipped += 1
            continue
        run_tenant_id = _string_from(candidate.get("tenant")) or tenant_id
        run_project_id = _string_from(candidate.get("project")) or project_id or ""
        try:
            latest = _first(
                "support_ai_runs",
                _issue_filter(
                    tenant_id=run_tenant_id,
                    project_id=run_project_id,
                    extra=f"id='{_escape_pb(run_id)}'",
                ),
            )
            latest_metadata = _parse((latest or {}).get("metadata"), dict)
            if (
                not latest
                or _string_from(latest.get("status")).lower() != "processing"
                or _string_from(latest_metadata.get("kind")) != processing_kind
                or not _direct_processing_is_stale(
                    latest,
                    now=now,
                    lease_seconds=lease_seconds,
                )
            ):
                skipped += 1
                continue
            expired_metadata = _processing_progress_metadata(
                latest,
                stage="failed",
                label="Processing lease expired",
                status="failed",
                detail="Automatic processing stopped and requires manual review.",
                terminal_status="failed",
            )
            claim = _parse(expired_metadata.get("processingClaim"), dict)
            if claim:
                expired_metadata["processingClaim"] = {
                    **claim,
                    "expiredAt": now_iso,
                }
            processing_expiry = {
                "version": 1,
                "expiredAt": now_iso,
                "leaseSeconds": max(1, int(lease_seconds)),
                "source": _string_from(source) or "scheduler",
                "replayed": False,
            }
            email_package = processing_kind == "email_channel_ticket_package"
            if email_package:
                processing_expiry["kind"] = processing_kind
            expired_metadata["processingExpiry"] = processing_expiry
            expired_summary = (
                "Email ticket processing expired; manual review required"
                if email_package
                else "Processing lease expired; manual review required"
            )
            _patch(
                f"/api/collections/support_ai_runs/records/{run_id}",
                {
                    "status": "failed",
                    "requires_human": True,
                    "summary": expired_summary,
                    "metadata": expired_metadata,
                    "completed_at": now_iso,
                },
            )
            issue_id = _string_from(latest.get("issue"))
            if issue_id:
                _patch(
                    f"/api/collections/support_issues/records/{issue_id}",
                    {"requires_human": True},
                )
                event_type = (
                    "email_channel_processing_expired"
                    if email_package
                    else "direct_processing_expired"
                )
                event_metadata = {
                    "aiRunId": run_id,
                    "leaseSeconds": max(1, int(lease_seconds)),
                    "source": _string_from(source) or "scheduler",
                    "replayed": False,
                }
                if email_package:
                    event_metadata["processingKind"] = processing_kind
                _record_issue_event(
                    issue_id=issue_id,
                    event_type=event_type,
                    tenant_id=run_tenant_id,
                    project_id=run_project_id,
                    actor_email="processing-sweeper",
                    title=(
                        "Email ticket processing expired"
                        if email_package
                        else "Automatic processing expired"
                    ),
                    body=(
                        "Ticket package processing stopped. No processing was replayed. "
                        "Manual review is required."
                        if email_package
                        else "No tools were replayed. Manual review is required."
                    ),
                    metadata=event_metadata,
                    record_id=_stable_record_id(
                        "support_issue_event",
                        run_project_id,
                        issue_id,
                        run_id,
                        event_type,
                    ),
                )
            expired += 1
            item = {
                "runId": run_id,
                "issueId": issue_id,
                "status": "failed",
            }
            if email_package:
                item["kind"] = processing_kind
            items.append(item)
        except Exception as exc:
            failed += 1
            items.append({"runId": run_id, "issueId": "", "status": "failed", "error": str(exc)})
            logger.warning("Could not expire stale processing run %s", run_id, exc_info=True)
    return {
        "inspected": inspected,
        "expired": expired,
        "skipped": skipped,
        "failed": failed,
        "items": items,
        "leaseSeconds": max(1, int(lease_seconds)),
    }


def _processing_run_from_issue(issue: dict[str, Any] | None) -> dict[str, Any] | None:
    run = (issue or {}).get("_processingRun")
    return run if isinstance(run, dict) and _string_from(run.get("id")) else None


def _apply_direct_channel_runbooks(
    *,
    issue: dict[str, Any],
    source: str,
    source_message_id: str,
    subject: str,
    body: str,
    identity: dict[str, str],
    identity_data: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
    resume_processing_run: bool = False,
) -> dict[str, Any]:
    """Persist one direct message's runbook result before ticket automation."""
    from automail.integrations.http_tool import fence_http_tool_execution
    from automail.pipeline.drafts import get_live_source
    from automail.support.channel_runbooks import run_direct_channel_runbooks

    issue_id = _string_from(issue.get("id"))
    if not issue_id:
        return issue
    run_key = _direct_channel_run_key(source=source, source_message_id=source_message_id)
    existing = _direct_channel_processing_run(
        issue_id=issue_id,
        source=source,
        source_message_id=source_message_id,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    now = _now_iso()
    if existing and _string_from(existing.get("status")).lower() == "processing":
        if not resume_processing_run or not _direct_channel_run_can_resume_package(existing):
            raise DirectChannelProcessingInProgress(
                "Direct-channel runbook processing is already in progress"
            )
        intent_result = _parse(existing.get("intent_result"), dict)
        issue_updates = {
            "activated_intent": _string_from(existing.get("activated_intent")),
            "requires_human": bool(existing.get("requires_human", True)),
            "action_log": _action_log(intent_result),
        }
        _require_processing_claim(existing)
        _patch(f"/api/collections/support_issues/records/{issue_id}", issue_updates)
        if intent_result.get("matched"):
            _prepare_runbook_action_approvals(
                issue_id=issue_id,
                intent_result=intent_result,
                source_message_id=source_message_id,
                tenant_id=tenant_id,
                project_id=project_id,
            )
        return {**issue, **issue_updates, "_processingRun": existing}
    if existing:
        intent_result = _parse(existing.get("intent_result"), dict)
        issue_updates = {
            "activated_intent": _string_from(existing.get("activated_intent")),
            "requires_human": bool(existing.get("requires_human", True)),
            "action_log": _action_log(intent_result),
        }
        try:
            _patch(f"/api/collections/support_issues/records/{issue_id}", issue_updates)
            if intent_result.get("matched"):
                _prepare_runbook_action_approvals(
                    issue_id=issue_id,
                    intent_result=intent_result,
                    source_message_id=source_message_id,
                    tenant_id=tenant_id,
                    project_id=project_id,
                )
        except Exception:
            issue_updates["requires_human"] = True
            logger.error(
                "Could not resume direct-channel runbook state: source=%s message=%s",
                source,
                source_message_id,
                exc_info=True,
            )
            try:
                _patch(
                    f"/api/collections/support_issues/records/{issue_id}",
                    {"requires_human": True},
                )
            except Exception:
                logger.error("Could not persist direct-channel resume fallback", exc_info=True)
        return {**issue, **issue_updates}

    processing_claim_token = secrets.token_hex(16)
    processing_run = _start_processing_run(
        issue_id=issue_id,
        tenant_id=tenant_id,
        project_id=project_id,
        run_key=run_key,
        source=source,
        kind="direct_channel_runbooks",
        stage="runbooks",
        label="Matching concerns and runbooks",
        metadata={
            "channel": source,
            "messageId": source_message_id,
            "sourceMessageId": source_message_id,
            "processingClaim": {
                "version": 1,
                "token": processing_claim_token,
                "claimedAt": now,
            },
        },
    )
    if processing_run is None:
        try:
            competing_run = _first(
                "support_ai_runs",
                _issue_filter(
                    tenant_id=tenant_id,
                    project_id=project_id,
                    extra=(
                        f"issue='{_escape_pb(issue_id)}' && "
                        f"run_key='{_escape_pb(run_key)}'"
                    ),
                ),
            )
        except Exception:
            competing_run = None
        if competing_run:
            raise DirectChannelProcessingInProgress(
                "Direct-channel runbook processing was claimed by another worker"
            )
        raise DirectChannelProcessingInProgress(
            "Direct-channel runbook processing could not acquire a durable claim"
        )
    result = None
    error = ""
    try:
        with fence_http_tool_execution(
            lambda: _processing_claim_is_active(processing_run)
        ):
            result = run_direct_channel_runbooks(
                source_message_id=source_message_id,
                subject=subject,
                body=body,
                from_address=identity.get("contact_email", ""),
                identity=identity,
                identity_data=identity_data,
                config_source=get_live_source(project_id, tenant_id=tenant_id),
                tenant_id=tenant_id,
                project_id=project_id,
            )
    except Exception as exc:
        error = _clip(str(exc) or exc.__class__.__name__, 1_000)
        logger.error(
            "Direct-channel runbooks failed: source=%s message=%s error=%s",
            source,
            source_message_id,
            error,
            exc_info=True,
        )

    # The expiry sweeper never replays runbooks. If it fenced this owner while
    # the LLM was still returning, refuse every subsequent durable write.
    _require_processing_claim(processing_run)

    requires_human = bool(error or result is None or result.requires_human)
    intent_result = result.intent_result if result else {"concerns": [], "error": error}
    activated_intent = result.activated_intent if result else ""
    summary = result.summary if result else error
    metadata: dict[str, Any] = {
        "kind": "direct_channel_runbooks",
        "channel": source,
        "messageId": source_message_id,
        "sourceMessageId": source_message_id,
    }
    if result and result.generated_attachments:
        metadata["generatedAttachments"] = result.generated_attachments
    terminal_status = "failed" if error else "needs_human" if requires_human else "success"
    progress_metadata = _processing_progress_metadata(
        processing_run or {"metadata": metadata, "started_at": now},
        stage="automation",
        label="Applying ticket automation",
        detail=summary,
        terminal_status=terminal_status,
    )
    metadata = {**metadata, **progress_metadata}
    run_data: dict[str, Any] = {
        "id": _string_from((processing_run or {}).get("id")) or generate_id(),
        "issue": issue_id,
        "run_key": run_key,
        "source": source,
        "status": "processing" if processing_run else terminal_status,
        "activated_intent": activated_intent,
        "requires_human": requires_human,
        "summary": summary,
        "identity_result": result.identity_result if result else {},
        "intent_result": intent_result,
        "security_result": {},
        "token_usage": result.token_usage if result else {},
        "tool_calls": result.tool_calls if result else [],
        "metadata": metadata,
        "started_at": now,
        "completed_at": "" if processing_run else now,
    }
    if tenant_id:
        run_data["tenant"] = tenant_id
    run_data["project"] = project_id
    run_persisted = processing_run is not None
    persisted_run = processing_run or {}
    try:
        _require_processing_claim(processing_run)
        if processing_run:
            patched_run = _patch(
                f"/api/collections/support_ai_runs/records/{run_data['id']}",
                {
                    key: value
                    for key, value in run_data.items()
                    if key not in {"id", "issue", "run_key", "source", "started_at", "tenant", "project"}
                },
            )
            processing_run.update({**run_data, **patched_run})
            persisted_run = processing_run
        else:
            persisted_run = _post("/api/collections/support_ai_runs/records", run_data)
            run_persisted = True
        if run_persisted:
            usage_calls = _parse(run_data.get("token_usage"), dict).get("calls")
            if isinstance(usage_calls, list) and usage_calls:
                try:
                    from automail.db.pocketbase.client import store_llm_usage_events

                    store_llm_usage_events(
                        usage_calls,
                        tenant_id=tenant_id,
                        project_id=project_id,
                        run_id=_string_from(persisted_run.get("id")) or _string_from(run_data.get("id")),
                    )
                except Exception:
                    logger.warning("Failed to store direct-channel LLM usage events", exc_info=True)
    except ProcessingClaimExpired:
        raise
    except Exception:
        run_persisted = False
        logger.error(
            "Could not persist direct-channel runbook result: source=%s message=%s",
            source,
            source_message_id,
            exc_info=True,
        )
        if processing_run:
            try:
                _finish_processing_run(
                    processing_run,
                    failed=True,
                    detail="Could not persist direct-channel runbook result",
                )
            except Exception:
                logger.exception("Could not mark direct-channel progress failed")
    if not run_persisted:
        requires_human = True

    issue_updates = {
        "activated_intent": activated_intent,
        "requires_human": requires_human,
        "action_log": _action_log(intent_result),
    }
    try:
        _require_processing_claim(processing_run)
        _patch(f"/api/collections/support_issues/records/{issue_id}", issue_updates)
        if result and result.intent_result.get("matched"):
            _prepare_runbook_action_approvals(
                issue_id=issue_id,
                intent_result=intent_result,
                source_message_id=source_message_id,
                tenant_id=tenant_id,
                project_id=project_id,
            )
    except ProcessingClaimExpired:
        raise
    except Exception:
        issue_updates["requires_human"] = True
        logger.error(
            "Could not apply direct-channel runbook state: source=%s message=%s",
            source,
            source_message_id,
            exc_info=True,
        )
        try:
            _patch(
                f"/api/collections/support_issues/records/{issue_id}",
                {"requires_human": True},
            )
        except Exception:
            logger.error("Could not persist direct-channel human-review fallback", exc_info=True)
    return {
        **issue,
        **issue_updates,
        **({"_processingRun": processing_run} if processing_run else {}),
    }


def _email_metadata_from_chat(chat: dict[str, Any]) -> dict[str, Any]:
    metadata = _record_from(chat.get("metadata"))
    references = metadata.get("references")
    if not isinstance(references, list):
        references = chat.get("references")
    attachments = metadata.get("attachments")
    return {
        "threadId": (
            _string_from(chat.get("thread_id"))
            or _string_from(chat.get("threadId"))
            or _string_from(metadata.get("threadId"))
            or _string_from(metadata.get("thread_id"))
            or _string_from(metadata.get("conversationId"))
        ),
        "messageId": (
            _string_from(chat.get("message_id"))
            or _string_from(chat.get("messageId"))
            or _string_from(metadata.get("messageId"))
            or _string_from(metadata.get("message_id"))
        ),
        "internetMessageId": (
            _string_from(chat.get("internet_message_id"))
            or _string_from(chat.get("internetMessageId"))
            or _string_from(metadata.get("internetMessageId"))
            or _string_from(metadata.get("internet_message_id"))
        ),
        "inReplyTo": (
            _string_from(chat.get("in_reply_to"))
            or _string_from(chat.get("inReplyTo"))
            or _string_from(metadata.get("inReplyTo"))
            or _string_from(metadata.get("in_reply_to"))
        ),
        "references": [_string_from(item) for item in references if _string_from(item)] if isinstance(references, list) else [],
        "attachments": attachments if isinstance(attachments, list) else [],
    }


def _email_issue_source_id(*, email_id: str, source: str, channel: dict[str, Any] | None, metadata: dict[str, Any]) -> str:
    thread_id = _string_from(metadata.get("threadId"))
    if not thread_id:
        return email_id
    source_key = _ticket_source_key(channel=channel or {}, thread_id=thread_id, message_id=email_id)
    if source_key == email_id:
        return email_id
    return _key_from(f"email-thread:{source}:{source_key}") or email_id


def _email_message_metadata(metadata: dict[str, Any], *, issue_source_id: str, email_id: str) -> dict[str, Any]:
    clean = {
        key: value
        for key, value in {
            "threadId": _string_from(metadata.get("threadId")),
            "messageId": _string_from(metadata.get("messageId")) or email_id,
            "internetMessageId": _string_from(metadata.get("internetMessageId")),
            "inReplyTo": _string_from(metadata.get("inReplyTo")),
            "references": metadata.get("references") if isinstance(metadata.get("references"), list) else [],
            "attachments": metadata.get("attachments") if isinstance(metadata.get("attachments"), list) else [],
            "sourceIssueId": issue_source_id,
            "sourceEmailId": email_id,
        }.items()
        if value
    }
    if not clean.get("references"):
        clean.pop("references", None)
    return clean


def _email_resolver_base(
    *,
    channel: dict[str, Any] | None,
    source: str,
    issue_source_id: str,
    email_id: str,
    metadata: dict[str, Any],
    from_address: str,
) -> dict[str, str]:
    channel_rec = channel or {}
    channel_key = (
        _string_from(channel_rec.get("channelKey"))
        or _string_from(channel_rec.get("channel_key"))
        or source
        or "email"
    )
    thread_id = _string_from(metadata.get("threadId"))
    provider_message_id = _string_from(metadata.get("messageId")) or email_id
    workspace_id = _sender_domain(from_address) or channel_key
    external_keys = _channel_external_keys(
        provider_key="email",
        channel_key=channel_key,
        workspace_id=workspace_id,
        channel_id=channel_key,
        thread_id=thread_id,
        conversation_id=thread_id,
        message_id=email_id,
        ticket_creation_mode=_ticket_creation_mode(channel_rec),
        author_id=from_address,
        author_display=from_address,
    )
    return _channel_resolver_base(
        channel=channel_rec,
        provider_key="email",
        source_issue_id=issue_source_id,
        source_message_id=email_id,
        external_keys=external_keys,
        workspace_id=workspace_id,
        provider_channel_id=channel_key,
        thread_id=thread_id,
        provider_message_id=provider_message_id,
    )


def _email_resolver_metadata(resolver: dict[str, str]) -> dict[str, Any]:
    metadata = {
        "ticketCreationMode": _string_from(resolver.get("ticketCreationMode")),
        "sourceIssueId": _string_from(resolver.get("sourceIssueId")),
        "sourceMessageId": _string_from(resolver.get("sourceMessageId")),
        "resolver": resolver,
    }
    for key in (
        "externalChannelKey",
        "externalConversationKey",
        "externalThreadKey",
        "externalMessageKey",
        "externalTicketKey",
    ):
        if resolver.get(key):
            metadata[key] = resolver[key]
    return {key: value for key, value in metadata.items() if value}


def upsert_issue_from_chat(
    chat: dict[str, Any],
    *,
    tenant_id: str | None,
    project_id: str | None,
    source: str = "addin",
) -> dict[str, Any] | None:
    if not project_id:
        return None

    email_id = _string_from(chat.get("email_id") or chat.get("id"))
    if not email_id:
        return None

    messages = _parse(chat.get("messages"), list)
    persisted_message_count = sum(_persist_support_message(message) for message in messages)
    email_metadata = _email_metadata_from_chat(chat)
    subject = _string_from(chat.get("subject"))
    from_address = _string_from(chat.get("from_address"))
    activated_intent = _string_from(chat.get("activated_intent"))
    requires_human = bool(chat.get("requires_human", False))
    identity_result = _record_from(chat.get("identity_result"))
    intent_result = _record_from(chat.get("intent_result"))
    intent_matched = bool(
        activated_intent
        or intent_result.get("matched") is True
        or _string_from(intent_result.get("intentName") or intent_result.get("intent_name"))
    )
    phishing_result = _record_from(chat.get("phishing_result"))
    prompt_injection_result = _record_from(chat.get("prompt_injection_result"))
    identity = _identity_fields(identity_result, from_address)
    channel = _ensure_channel(
        tenant_id=tenant_id,
        project_id=project_id,
        channel_type="email",
        source=source,
    )
    issue_source_id = _email_issue_source_id(
        email_id=email_id,
        source=source,
        channel=channel,
        metadata=email_metadata,
    )
    message_metadata = _email_message_metadata(email_metadata, issue_source_id=issue_source_id, email_id=email_id)
    resolver_base = _email_resolver_base(
        channel=channel,
        source=source,
        issue_source_id=issue_source_id,
        email_id=email_id,
        metadata=email_metadata,
        from_address=from_address,
    )
    identity_data = _record_from(identity_result.get("data"))
    priority = _priority(
        # A router no-match is a normal inbox item, not automatically a high-risk
        # support incident. Security monitoring can still independently make it urgent.
        requires_human=requires_human if intent_matched else False,
        phishing_result=phishing_result,
        prompt_injection_result=prompt_injection_result,
    )
    summary = _ai_summary(
        subject=subject,
        from_address=from_address,
        activated_intent=activated_intent,
        requires_human=requires_human,
        messages=messages,
    )
    chat_record_id = _string_from(chat.get("record_id"))
    filter_str = _issue_filter(
        tenant_id=tenant_id,
        project_id=project_id,
        extra=f"source_email_id='{_escape_pb(issue_source_id)}'",
    )
    existing, existing_redirected = _resolve_merged_issue_record(
        _first("support_issues", filter_str),
        tenant_id=tenant_id,
        project_id=project_id,
    )
    if existing and _completed_email_pipeline_run(
        issue_id=_string_from(existing.get("id")),
        email_id=email_id,
        source=source,
        tenant_id=tenant_id,
        project_id=project_id,
    ):
        return _normalize_issue(existing)

    account = _upsert_account(
        identity=identity,
        identity_data=identity_data,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    contact = (
        _upsert_contact(
            identity=identity,
            identity_data=identity_data,
            account_id=_string_from(account.get("id")),
            tenant_id=tenant_id,
            project_id=project_id,
        )
        if account
        else None
    )

    base_data: dict[str, Any] = {
        "source_email_id": issue_source_id,
        "channel": "email",
        "source": source,
        "subject": subject,
        "from_address": from_address,
        "account_name": identity["account_name"],
        "account_domain": identity["account_domain"],
        "contact_email": identity["contact_email"],
        "contact_name": identity["contact_name"],
        "ai_summary": summary,
        "activated_intent": activated_intent,
        "requires_human": requires_human,
        "message_count": persisted_message_count,
        "action_log": _action_log(intent_result) if intent_matched else [],
        "latest_message_at": _now_iso(),
    }
    if chat_record_id:
        base_data["chat"] = chat_record_id
    if account:
        base_data["account"] = account["id"]
    if contact:
        base_data["contact"] = contact["id"]

    if existing:
        issue_resolver = _channel_resolver_proof(
            resolver_base,
            issue_id=existing["id"],
            message_id=email_id,
            existing_issue=existing,
            message_created=True,
        )
        resolver_metadata = _email_resolver_metadata(issue_resolver)
        _upsert_messages(
            issue_id=existing["id"],
            email_id=email_id,
            chat_record_id=chat_record_id,
            creator=_string_from(chat.get("creator")),
            from_address=from_address,
            messages=messages,
            tenant_id=tenant_id,
            project_id=project_id,
            email_metadata={**message_metadata, **resolver_metadata},
        )
        update = dict(base_data)
        existing_metadata = _parse(existing.get("metadata"), dict)
        # A new customer message invalidates any earlier explicit resolution that
        # said no response was required.
        existing_metadata.pop("responseResolution", None)
        update["metadata"] = {**existing_metadata, **resolver_metadata}
        if existing_redirected:
            update.pop("source_email_id", None)
        existing_priority = _string_from(existing.get("priority")) or "normal"
        if priority in {"high", "urgent"} and existing_priority not in {"high", "urgent"}:
            update["priority"] = priority
        if not _string_from(existing.get("status")):
            update["status"] = "open"
        existing_was_done = _workflow_status(_string_from(existing.get("status"))) == "done"
        if existing_was_done:
            update["status"] = "open"
        if not _string_from(existing.get("queue_key")):
            _apply_default_queue(update, tenant_id=tenant_id, project_id=project_id, channel=channel)
        _patch(f"/api/collections/support_issues/records/{existing['id']}", update)
        issue = {**existing, **update}
        _refresh_account_contact_counts(
            account_id=_string_from(account.get("id")) if account else None,
            contact_id=_string_from(contact.get("id")) if contact else None,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        if intent_matched:
            _sync_external_objects(
                account_id=_string_from(account.get("id")) if account else "",
                contact_id=_string_from(contact.get("id")) if contact else "",
                issue_id=existing["id"],
                identity=identity,
                identity_data=identity_data,
                tenant_id=tenant_id,
                project_id=project_id,
            )
        _ensure_issue_sla_events(issue_id=existing["id"], tenant_id=tenant_id, project_id=project_id)
        if intent_matched:
            _sync_account_insights(
                account_id=_string_from(account.get("id")) if account else None,
                issue=issue,
                messages=messages,
                tenant_id=tenant_id,
                project_id=project_id,
            )
            _sync_knowledge_gap(issue=issue, messages=messages, tenant_id=tenant_id, project_id=project_id)
        pipeline_run = _upsert_ai_run_from_chat(
            issue_id=existing["id"],
            issue=issue,
            chat=chat,
            identity_result=identity_result,
            intent_result=intent_result,
            phishing_result=phishing_result,
            prompt_injection_result=prompt_injection_result,
            tenant_id=tenant_id,
            project_id=project_id,
            source=source,
        )
        if update.get("priority") and update["priority"] != existing_priority:
            _record_issue_event(
                issue_id=existing["id"],
                event_type="priority_changed",
                tenant_id=tenant_id,
                project_id=project_id,
                actor_email=_string_from(chat.get("creator")),
                title="Priority changed",
                from_priority=existing_priority,
                to_priority=_string_from(update.get("priority")),
                metadata={"source": source, "reason": "ai_triage"},
            )
        _record_issue_event(
            issue_id=existing["id"],
            event_type="message_ingested",
            tenant_id=tenant_id,
            project_id=project_id,
            actor_email=_string_from(chat.get("creator")),
            title="Message ingested",
            from_status="done" if existing_was_done else "",
            to_status="open" if existing_was_done else "",
            metadata={
                "source": source,
                "emailId": email_id,
                "issueSourceId": issue_source_id,
                **message_metadata,
                **resolver_metadata,
                "messageCount": persisted_message_count,
            },
        )
        _notify_customer_message_subscribers(
            issue=issue,
            issue_id=existing["id"],
            source=source,
            message_id=email_id,
            body=summary,
            actor_email=_string_from(chat.get("creator") or from_address),
            tenant_id=tenant_id,
            project_id=project_id,
            metadata={"emailId": email_id, "issueSourceId": issue_source_id, **message_metadata, **resolver_metadata, "messageCount": persisted_message_count},
        )
        if intent_matched:
            _prepare_runbook_action_approvals(
                issue_id=existing["id"],
                intent_result=intent_result,
                source_message_id=email_id,
                tenant_id=tenant_id,
                project_id=project_id,
            )
            automation_result = _run_message_update_automations(
                issue=issue,
                tenant_id=tenant_id,
                project_id=project_id,
                actor_email="automation",
                source=source,
                message_id=email_id,
                context={"emailId": email_id, "issueSourceId": issue_source_id, **message_metadata, **resolver_metadata, "messageCount": persisted_message_count},
            )
            if not _automation_created_customer_reply(automation_result):
                prepared = _ensure_email_channel_autopilot_package(
                    issue=issue,
                    channel=channel,
                    tenant_id=tenant_id,
                    project_id=project_id,
                    source=source,
                    message_id=email_id,
                    on_update=True,
                    automation_result=automation_result,
                    context={"emailId": email_id, "issueSourceId": issue_source_id, **message_metadata, **resolver_metadata, "messageCount": persisted_message_count},
                )
                if not prepared:
                    _ensure_email_pipeline_reply_draft(
                        issue=issue,
                        messages=messages,
                        chat=chat,
                        tenant_id=tenant_id,
                        project_id=project_id,
                        source=source,
                    )
        _mark_email_pipeline_run_completed(pipeline_run)
        return _normalize_issue(issue)

    new_issue_id = generate_id()
    issue_resolver = _channel_resolver_proof(
        resolver_base,
        issue_id=new_issue_id,
        message_id=email_id,
        existing_issue=None,
        message_created=True,
    )
    resolver_metadata = _email_resolver_metadata(issue_resolver)
    create_data = {
        "id": new_issue_id,
        **base_data,
        "status": "open",
        "priority": priority,
        "assignee_email": "",
        "metadata": resolver_metadata,
    }
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    _apply_default_queue(
        create_data,
        tenant_id=tenant_id,
        project_id=project_id,
        channel=channel,
    )
    default_assignee = _apply_default_assignee(
        create_data,
        tenant_id=tenant_id,
        project_id=project_id,
        channel=channel,
    )
    _mark_assignment_required(
        create_data,
        source=source,
        channel=channel,
        context={"emailId": email_id, "issueSourceId": issue_source_id},
    )
    rec = _post("/api/collections/support_issues/records", create_data)
    _record_default_assignment(
        issue_id=rec["id"],
        assignee_email=default_assignee,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    _ensure_issue_sla_events(issue_id=rec["id"], tenant_id=tenant_id, project_id=project_id)
    _upsert_messages(
        issue_id=rec["id"],
        email_id=email_id,
        chat_record_id=chat_record_id,
        creator=_string_from(chat.get("creator")),
        from_address=from_address,
        messages=messages,
        tenant_id=tenant_id,
        project_id=project_id,
        email_metadata={**message_metadata, **resolver_metadata},
    )
    _refresh_account_contact_counts(
        account_id=_string_from(account.get("id")) if account else None,
        contact_id=_string_from(contact.get("id")) if contact else None,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    if intent_matched:
        _sync_external_objects(
            account_id=_string_from(account.get("id")) if account else "",
            contact_id=_string_from(contact.get("id")) if contact else "",
            issue_id=rec["id"],
            identity=identity,
            identity_data=identity_data,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        _sync_account_insights(
            account_id=_string_from(account.get("id")) if account else None,
            issue=rec,
            messages=messages,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        _sync_knowledge_gap(issue=rec, messages=messages, tenant_id=tenant_id, project_id=project_id)
    pipeline_run = _upsert_ai_run_from_chat(
        issue_id=rec["id"],
        issue=rec,
        chat=chat,
        identity_result=identity_result,
        intent_result=intent_result,
        phishing_result=phishing_result,
        prompt_injection_result=prompt_injection_result,
        tenant_id=tenant_id,
        project_id=project_id,
        source=source,
    )
    _record_issue_event(
        issue_id=rec["id"],
        event_type="issue_created",
        tenant_id=tenant_id,
        project_id=project_id,
        actor_email=_string_from(chat.get("creator")),
        title="Issue created",
        to_status="open",
        to_priority=priority,
        metadata={
            "source": source,
            "emailId": email_id,
            "issueSourceId": issue_source_id,
            **message_metadata,
            **resolver_metadata,
            "messageCount": persisted_message_count,
        },
    )
    if intent_matched:
        _prepare_runbook_action_approvals(
            issue_id=rec["id"],
            intent_result=intent_result,
            source_message_id=email_id,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        automation_result = _run_automation_rules_for_issue(
            issue=rec,
            trigger="issue_created",
            tenant_id=tenant_id,
            project_id=project_id,
            actor_email="automation",
            context={"source": source, "emailId": email_id, "issueSourceId": issue_source_id, **message_metadata, **resolver_metadata},
        )
        if not _automation_created_customer_reply(automation_result):
            prepared = _ensure_email_channel_autopilot_package(
                issue=rec,
                channel=channel,
                tenant_id=tenant_id,
                project_id=project_id,
                source=source,
                message_id=email_id,
                automation_result=automation_result,
                context={"source": source, "emailId": email_id, "issueSourceId": issue_source_id, **message_metadata, **resolver_metadata},
            )
            if not prepared:
                _ensure_email_pipeline_reply_draft(
                    issue=rec,
                    messages=messages,
                    chat=chat,
                    tenant_id=tenant_id,
                    project_id=project_id,
                    source=source,
                )
    _mark_email_pipeline_run_completed(pipeline_run)
    return _normalize_issue(rec)


def list_issues(
    *,
    tenant_id: str | None,
    project_id: str,
    status: str = "all",
    queue_key: str = "",
    account_key: str = "",
    channel: str = "",
    assignee_email: str = "",
    tag: str = "",
    query: str = "",
    limit: int = 100,
) -> list[dict[str, Any]]:
    extra_parts = [part for part in [_status_filter(status)] if part]
    raw_queue_key = _string_from(queue_key).strip().lower()
    clean_queue_key = _queue_key_from(queue_key)
    if raw_queue_key in {"__no_queue__", "none", "no_queue"}:
        extra_parts.append("queue_key=''")
    elif clean_queue_key and clean_queue_key != "all" and clean_queue_key != "__all_queues__":
        extra_parts.append(f"queue_key='{_escape_pb(clean_queue_key)}'")
    extra = " && ".join(extra_parts)
    fetch_limit = max(1, min(max(limit * 2, limit), 200))
    records = _list_all(
        "support_issues",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=extra),
        sort="-updated",
        per_page=fetch_limit,
    )
    matching_records = [
        rec for rec in records
        if not _merged_into_issue_id(rec)
        and _issue_matches_inbox_filters(
            rec,
            account_key=account_key,
            channel=channel,
            assignee_email=assignee_email,
            tag=tag,
            query=query,
        )
    ]
    limited_records = matching_records[:limit]
    issue_ids = [_string_from(rec.get("id")) for rec in limited_records]
    duplicate_summaries = _duplicate_summary_by_issue(matching_records)
    summaries = _approval_summary_by_issue(
        issue_ids,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    ai_summaries = _ai_run_summary_by_issue(
        issue_ids,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    knowledge_gap_summaries = _knowledge_gap_summary_by_issue(
        issue_ids,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    sla_summaries = _sla_summary_by_issue(
        issue_ids,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    csat_summaries = _csat_summary_by_issue(
        issue_ids,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    response_summaries = _message_response_summary_by_issue(
        limited_records,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    items: list[dict[str, Any]] = []
    for rec in limited_records:
        issue = _normalize_issue(rec)
        issue_id = _string_from(rec.get("id"))
        issue.update(summaries.get(issue_id, {}))
        issue.update(ai_summaries.get(issue_id, {}))
        issue.update(knowledge_gap_summaries.get(issue_id, {}))
        issue.update(sla_summaries.get(issue_id, {}))
        issue.update(csat_summaries.get(issue_id, {}))
        response_summary = dict(response_summaries.get(issue_id, {}))
        if not response_summary.get("latestMessageAt"):
            response_summary.pop("latestMessageAt", None)
        issue.update(response_summary)
        issue.update(duplicate_summaries.get(issue_id, {}))
        issue["ticketState"] = _issue_ticket_state(issue)
        if not _issue_matches_operational_filter(issue, status):
            continue
        items.append(issue)
    return items


def _issue_attention_summary(issues: list[dict[str, Any]]) -> dict[str, int]:
    summary = {
        "unassigned": 0,
        "needsResponse": 0,
        "approvals": 0,
        "failedDelivery": 0,
        "overdueSla": 0,
        "closeBlocked": 0,
        "attentionCount": 0,
    }
    for issue in issues:
        pending_approvals = int(issue.get("pendingApprovalCount") or 0)
        pending_replies = int(issue.get("pendingReplyApprovalCount") or 0)
        pending_actions = int(issue.get("pendingActionApprovalCount") or 0)
        pending_delivery = int(issue.get("pendingDeliveryCount") or 0)
        failed_delivery = int(issue.get("failedDeliveryCount") or 0)
        overdue_sla = int(issue.get("overdueSlaCount") or 0)
        if not _string_from(issue.get("assigneeEmail")):
            summary["unassigned"] += 1
        if bool(issue.get("needsResponse")):
            summary["needsResponse"] += 1
        if bool(issue.get("hasPendingApproval")) or pending_approvals > 0:
            summary["approvals"] += 1
        if bool(issue.get("hasFailedDelivery")) or failed_delivery > 0:
            summary["failedDelivery"] += 1
        if bool(issue.get("hasOverdueSla")) or overdue_sla > 0:
            summary["overdueSla"] += 1
        if pending_replies > 0 or pending_actions > 0 or pending_approvals > 0 or pending_delivery > 0 or failed_delivery > 0:
            summary["closeBlocked"] += 1
    summary["attentionCount"] = (
        summary["unassigned"]
        + summary["needsResponse"]
        + summary["approvals"]
        + summary["failedDelivery"]
        + summary["overdueSla"]
    )
    return summary


def _issue_breakdown(items: list[dict[str, Any]], key: str, *, fallback: str = "Unassigned") -> list[dict[str, Any]]:
    counts: dict[str, dict[str, Any]] = {}
    for item in items:
        value = _string_from(item.get(key))
        bucket_key = value.lower() if value else "__unassigned__"
        bucket = counts.setdefault(bucket_key, {"key": bucket_key, "label": value or fallback, "count": 0})
        bucket["count"] += 1
    return sorted(counts.values(), key=lambda item: (-int(item["count"]), str(item["label"]).lower()))[:10]


def _issue_board_operating_action(issues: list[dict[str, Any]], *, lane: str = "all") -> dict[str, Any]:
    summary = _issue_attention_summary(issues)
    action_specs = (
        (
            "assign_owners",
            "Assign owners",
            "Tickets need assignees before work can move forward.",
            "unassigned",
            "assignment",
            "unassigned",
        ),
        (
            "recover_delivery",
            "Recover delivery",
            "Replies failed to send and need retry or channel route repair.",
            "failedDelivery",
            "delivery",
            "failed-delivery",
        ),
        (
            "review_approvals",
            "Review approvals",
            "Agent replies or actions are waiting for human approval.",
            "approvals",
            "review",
            "approvals",
        ),
        (
            "escalate_sla",
            "Escalate SLA",
            "SLA targets are overdue and need owner action.",
            "overdueSla",
            "sla",
            "overdue-sla",
        ),
        (
            "answer_customers",
            "Answer customers",
            "Customer messages are waiting for a response.",
            "needsResponse",
            "reply",
            "needs-response",
        ),
        (
            "clear_close_blockers",
            "Clear close blockers",
            "Tickets cannot move to done until approvals and delivery blockers are cleared.",
            "closeBlocked",
            "closure",
            "all",
        ),
    )
    for kind, label, detail, count_key, phase, status_filter in action_specs:
        count = int(summary.get(count_key, 0))
        if count > 0:
            return {
                "kind": kind,
                "label": label,
                "detail": detail,
                "phase": phase,
                "lane": lane,
                "statusFilter": status_filter,
                "count": count,
                "issueCount": len(issues),
                "attentionCount": summary["attentionCount"],
                "blocked": True,
            }

    fallback_by_lane = {
        "open": (
            "triage_open",
            "Triage open tickets",
            "Open tickets are ready for first owner, reply, or move to ongoing.",
            "triage",
        ),
        "ongoing": (
            "work_ongoing",
            "Work active tickets",
            "Ongoing tickets are assigned and ready for replies, actions, or customer follow-up.",
            "work",
        ),
        "done": (
            "audit_done",
            "Audit closed tickets",
            "Done tickets have no active board blocker.",
            "done",
        ),
    }
    kind, label, detail, phase = fallback_by_lane.get(
        lane,
        (
            "clear",
            "Board clear",
            "No active board blocker is waiting.",
            "clear",
        ),
    )
    return {
        "kind": kind,
        "label": label,
        "detail": detail,
        "phase": phase,
        "lane": lane,
        "statusFilter": lane if lane in WORKFLOW_LANES else "all",
        "count": 0,
        "issueCount": len(issues),
        "attentionCount": summary["attentionCount"],
        "blocked": False,
    }


def _list_records_from(value: Any) -> list[dict[str, Any]]:
    if not isinstance(value, list):
        return []
    return [item for item in value if isinstance(item, dict)]


def _issue_workflow_lane_policy(lane: str) -> dict[str, Any]:
    allowed_transitions = [target for target in WORKFLOW_LANES if target != lane]
    descriptions = {
        "open": "New or reopened tickets that need triage, assignment, or first action.",
        "ongoing": "Owned tickets being worked, waiting on a customer, or waiting on provider delivery.",
        "done": "Resolved tickets with approvals and delivery blockers cleared.",
    }
    entry_requirements = {
        "open": ["Ticket exists in the support system of record."],
        "ongoing": ["Ticket has an assignee."],
        "done": ["Ticket has an assignee.", "No pending approvals, action approvals, queued replies, or failed deliveries."],
    }
    return {
        "status": lane,
        "label": WORKFLOW_LANE_LABELS[lane],
        "description": descriptions[lane],
        "allowedTransitions": allowed_transitions,
        "entryRequirements": entry_requirements[lane],
        "requiresAssignee": lane in {"ongoing", "done"},
        "doneGate": lane == "done",
    }


def _issue_workflow_policy() -> dict[str, Any]:
    lane_policies = [_issue_workflow_lane_policy(lane) for lane in WORKFLOW_LANES]
    return {
        "kind": "support_ticket_workflow_policy",
        "version": 1,
        "lanes": lane_policies,
        "laneOrder": list(WORKFLOW_LANES),
        "assigneeRequiredStatuses": ["ongoing", "done"],
        "doneRequiresNoBlockers": True,
        "doneBlockers": list(WORKFLOW_DONE_BLOCKERS),
        "dragDropEnabled": True,
        "bulkMoveEnabled": True,
        "claimOnDropStatuses": ["ongoing", "done"],
    }


def issue_kanban_board(
    *,
    tenant_id: str | None,
    project_id: str,
    status: str = "all",
    queue_key: str = "",
    account_key: str = "",
    channel: str = "",
    assignee_email: str = "",
    tag: str = "",
    query: str = "",
    limit: int = 200,
) -> dict[str, Any]:
    issue_limit = max(1, min(limit, 200))
    issues = list_issues(
        tenant_id=tenant_id,
        project_id=project_id,
        status=status,
        queue_key=queue_key,
        account_key=account_key,
        channel=channel,
        assignee_email=assignee_email,
        tag=tag,
        query=query,
        limit=issue_limit,
    )
    grouped: dict[str, list[dict[str, Any]]] = {lane: [] for lane in WORKFLOW_LANES}
    for issue in issues:
        grouped[_canonical_status(_string_from(issue.get("workflowStatus") or issue.get("status")))].append(issue)

    lanes = []
    totals = _issue_attention_summary(issues)
    for lane in WORKFLOW_LANES:
        lane_issues = grouped[lane]
        lanes.append({
            "status": lane,
            "label": WORKFLOW_LANE_LABELS[lane],
            "policy": _issue_workflow_lane_policy(lane),
            "count": len(lane_issues),
            "attention": _issue_attention_summary(lane_issues),
            "assigneeBreakdown": _issue_breakdown(lane_issues, "assigneeEmail"),
            "priorityBreakdown": _issue_breakdown(lane_issues, "priority", fallback="normal"),
            "channelBreakdown": _issue_breakdown(lane_issues, "channel", fallback="unknown"),
            "operatingAction": _issue_board_operating_action(lane_issues, lane=lane),
            "issues": lane_issues,
        })

    return {
        "kind": "support_issue_kanban_board",
        "status": status or "all",
        "queueKey": queue_key,
        "accountKey": account_key,
        "channel": channel,
        "assigneeEmail": assignee_email,
        "tag": tag,
        "query": query,
        "limit": issue_limit,
        "total": len(issues),
        "attention": totals,
        "nextAction": _issue_board_operating_action(issues),
        "workflow": _issue_workflow_policy(),
        "lanes": lanes,
    }


def _issue_answer_workspace_next_action(issue: dict[str, Any]) -> dict[str, Any]:
    status = _canonical_status(_string_from(issue.get("workflowStatus") or issue.get("status")) or "open")
    pending_reply_approvals = int(issue.get("pendingReplyApprovalCount") or 0)
    pending_action_approvals = int(issue.get("pendingActionApprovalCount") or 0)
    pending_approvals = int(issue.get("pendingApprovalCount") or 0)
    failed_delivery = int(issue.get("failedDeliveryCount") or 0)
    pending_delivery = int(issue.get("pendingDeliveryCount") or 0)
    overdue_sla = int(issue.get("overdueSlaCount") or 0)
    if status == "done":
        return {
            "kind": "done",
            "phase": "closed",
            "priority": 100,
            "title": "Ticket closed",
            "detail": "Ticket is in the done lane.",
            "actions": [],
        }
    if not _string_from(issue.get("assigneeEmail")) and status != "done":
        return {
            "kind": "assign_owner",
            "phase": "triage",
            "priority": 10,
            "title": "Assign ticket owner",
            "detail": "Ticket needs an assignee before work can move forward.",
            "actions": ["assign_to_me", "set_assignee"],
        }
    if failed_delivery > 0:
        return {
            "kind": "failed_delivery",
            "phase": "delivery",
            "priority": 20,
            "title": "Fix failed delivery",
            "detail": f"{failed_delivery} outbound reply delivery failed.",
            "actions": ["retry_failed_delivery", "edit_reply"],
        }
    if pending_reply_approvals > 0:
        return {
            "kind": "reply_approval",
            "phase": "human_review",
            "priority": 30,
            "title": "Review reply draft",
            "detail": f"{pending_reply_approvals} reply draft awaits human approval.",
            "actions": ["approve_reply", "request_changes"],
        }
    if pending_action_approvals > 0:
        return {
            "kind": "action_approval",
            "phase": "human_review",
            "priority": 40,
            "title": "Review action proposal",
            "detail": f"{pending_action_approvals} action proposal awaits human approval.",
            "actions": ["approve_action", "reject_action"],
        }
    if pending_delivery > 0:
        return {
            "kind": "pending_delivery",
            "phase": "delivery",
            "priority": 50,
            "title": "Run delivery",
            "detail": f"{pending_delivery} outbound reply is queued.",
            "actions": ["run_delivery"],
        }
    if bool(issue.get("needsResponse")) and status != "done":
        return {
            "kind": "reply_needed",
            "phase": "answer",
            "priority": 60,
            "title": "Prepare customer reply",
            "detail": "Latest customer message has no newer agent reply.",
            "actions": ["ask_agent", "prepare_reply"],
        }
    if bool(issue.get("hasOverdueSla")) or overdue_sla > 0:
        return {
            "kind": "overdue_sla",
            "phase": "sla",
            "priority": 70,
            "title": "Escalate overdue SLA",
            "detail": f"{overdue_sla or 1} SLA target is overdue.",
            "actions": ["escalate_sla", "prepare_reply"],
        }
    if pending_approvals > 0:
        return {
            "kind": "approval",
            "phase": "human_review",
            "priority": 80,
            "title": "Review pending approval",
            "detail": f"{pending_approvals} approval item needs human review.",
            "actions": ["open_review"],
        }
    return {
        "kind": "ready_to_close",
        "phase": "close",
        "priority": 90,
        "title": "Ready to close",
        "detail": "No reply, delivery, approval, or SLA blocker is active.",
        "actions": ["mark_done"],
    }


def _configured_secret_value(env_name: str, secrets: dict[str, str] | None) -> str:
    clean = _string_from(env_name)
    if not clean:
        return ""
    if isinstance(secrets, dict) and _string_from(secrets.get(clean)):
        return _string_from(secrets.get(clean))
    return _string_from(os.getenv(clean))


def _reply_webhook_readiness(config: dict[str, Any], secrets: dict[str, str] | None) -> tuple[bool, list[str]]:
    env_name = _string_from(config.get("outboundWebhookUrlEnv") or config.get("outbound_webhook_url_env"))
    if env_name:
        return bool(_configured_secret_value(env_name, secrets)), ([env_name] if not _configured_secret_value(env_name, secrets) else [])
    if _string_from(config.get("outboundWebhookUrl") or config.get("outbound_webhook_url")):
        return True, []
    template = _string_from(config.get("outboundWebhookUrlTemplate") or config.get("outbound_webhook_url_template"))
    if not template:
        return False, []
    missing = [
        name
        for name in dict.fromkeys(re.findall(r"\{([^}]+)\}", template))
        if not _configured_secret_value(name, secrets)
    ]
    return not missing, missing


def _reply_provider_required_envs(channel: str, config: dict[str, Any]) -> list[str]:
    clean_channel = _string_from(channel).lower()

    def configured_env(*keys: str, default: str) -> str:
        return _string_from(next((config.get(key) for key in keys if config.get(key)), "")) or default

    if clean_channel == "slack":
        return [configured_env("slackBotTokenEnv", "slack_bot_token_env", "botTokenEnv", "bot_token_env", default="SUPPORT_SLACK_BOT_TOKEN")]
    if clean_channel == "teams":
        return [
            configured_env("teamsAppIdEnv", "teams_app_id_env", default="SUPPORT_TEAMS_APP_ID"),
            configured_env("teamsAppPasswordEnv", "teams_app_password_env", default="SUPPORT_TEAMS_APP_PASSWORD"),
        ]
    if clean_channel == "discord":
        return [configured_env("discordBotTokenEnv", "discord_bot_token_env", "botTokenEnv", "bot_token_env", default="SUPPORT_DISCORD_BOT_TOKEN")]
    if clean_channel == "telegram":
        return [configured_env("telegramBotTokenEnv", "telegram_bot_token_env", "botTokenEnv", "bot_token_env", default="SUPPORT_TELEGRAM_BOT_TOKEN")]
    if clean_channel == "line":
        return [
            configured_env(
                "lineChannelAccessTokenEnv",
                "line_channel_access_token_env",
                "channelAccessTokenEnv",
                "channel_access_token_env",
                "accessTokenEnv",
                "access_token_env",
                default="SUPPORT_LINE_CHANNEL_ACCESS_TOKEN",
            )
        ]
    if clean_channel == "viber":
        return [
            configured_env(
                "viberAuthTokenEnv",
                "viber_auth_token_env",
                "authTokenEnv",
                "auth_token_env",
                "accessTokenEnv",
                "access_token_env",
                "outboundWebhookTokenEnv",
                "outbound_webhook_token_env",
                default="SUPPORT_VIBER_AUTH_TOKEN",
            )
        ]
    if clean_channel == "whatsapp":
        envs = [configured_env("whatsappAccessTokenEnv", "whatsapp_access_token_env", "accessTokenEnv", "access_token_env", default="SUPPORT_WHATSAPP_ACCESS_TOKEN")]
        if not _string_from(config.get("phoneNumberId") or config.get("phone_number_id") or config.get("whatsappPhoneNumberId") or config.get("whatsapp_phone_number_id")):
            envs.append(configured_env("phoneNumberIdEnv", "phone_number_id_env", "whatsappPhoneNumberIdEnv", "whatsapp_phone_number_id_env", default="SUPPORT_WHATSAPP_PHONE_NUMBER_ID"))
        return envs
    if clean_channel in {"messenger", "facebook_messenger"}:
        envs = [configured_env("messengerPageAccessTokenEnv", "messenger_page_access_token_env", "pageAccessTokenEnv", "page_access_token_env", "accessTokenEnv", "access_token_env", default="SUPPORT_MESSENGER_PAGE_ACCESS_TOKEN")]
        if not _string_from(config.get("messengerPageId") or config.get("messenger_page_id") or config.get("pageId") or config.get("page_id")):
            envs.append(configured_env("messengerPageIdEnv", "messenger_page_id_env", "pageIdEnv", "page_id_env", default="SUPPORT_MESSENGER_PAGE_ID"))
        return envs
    if clean_channel in {"sms", "twilio"}:
        envs = [
            configured_env("twilioAccountSidEnv", "twilio_account_sid_env", "accountSidEnv", "account_sid_env", default="SUPPORT_TWILIO_ACCOUNT_SID"),
            configured_env("twilioAuthTokenEnv", "twilio_auth_token_env", "authTokenEnv", "auth_token_env", default="SUPPORT_TWILIO_AUTH_TOKEN"),
        ]
        has_from = _string_from(config.get("twilioFromNumber") or config.get("twilio_from_number") or config.get("fromNumber") or config.get("from_number"))
        has_service = _string_from(config.get("twilioMessagingServiceSid") or config.get("twilio_messaging_service_sid") or config.get("messagingServiceSid") or config.get("messaging_service_sid"))
        if not has_from and not has_service:
            envs.append(configured_env("twilioFromNumberEnv", "twilio_from_number_env", "fromNumberEnv", "from_number_env", default="SUPPORT_TWILIO_FROM_NUMBER"))
        return envs
    return []


def _reply_provider_transport_supported(channel: str) -> bool:
    return _string_from(channel).lower() in {"slack", "teams", "discord", "telegram", "line", "viber", "whatsapp", "messenger", "facebook_messenger", "sms", "twilio"}


def _reply_webhook_configured(config: dict[str, Any]) -> bool:
    return bool(
        _string_from(config.get("outboundWebhookUrl") or config.get("outbound_webhook_url"))
        or _string_from(config.get("outboundWebhookUrlEnv") or config.get("outbound_webhook_url_env"))
        or _string_from(config.get("outboundWebhookUrlTemplate") or config.get("outbound_webhook_url_template"))
    )


def _reply_adapter_capabilities(
    *,
    channel: str,
    transport: str,
    provider: str,
    channel_record: dict[str, Any] | None,
    channel_config: dict[str, Any],
    target: dict[str, Any],
    required_env_vars: list[str],
    missing_env_vars: list[str],
) -> dict[str, Any]:
    clean_channel = _string_from(channel).lower() or "email"
    clean_transport = _string_from(transport) or "unknown"
    native_provider = _reply_provider_transport_supported(clean_channel)
    webhook_adapter = _reply_webhook_configured(channel_config) or clean_transport == "webhook"
    internal_delivery = clean_channel == "web_chat"
    supported_transports: list[str] = []
    if clean_channel == "email":
        if webhook_adapter:
            supported_transports.append("webhook")
        supported_transports.append("smtp")
    elif internal_delivery:
        supported_transports.append("internal")
    else:
        if native_provider:
            supported_transports.append("provider_api")
        if webhook_adapter or not native_provider:
            supported_transports.append("webhook")
    return {
        "channel": clean_channel,
        "selectedTransport": clean_transport,
        "selectedProvider": _string_from(provider),
        "supportedTransports": list(dict.fromkeys(supported_transports)),
        "nativeProvider": native_provider,
        "webhookAdapter": webhook_adapter,
        "internal": internal_delivery,
        "requiresChannelConfig": clean_channel not in {"email", "web_chat"},
        "channelConfigured": bool(channel_record) or clean_channel in {"email", "web_chat"},
        "requiresRuntimeSecrets": bool(required_env_vars),
        "requiredEnvVars": list(dict.fromkeys(required_env_vars)),
        "missingEnvVars": list(dict.fromkeys(missing_env_vars)),
        "targetKey": _string_from(target.get("key")),
        "targetLabel": _string_from(target.get("label")),
    }


def _reply_readiness(
    issue: dict[str, Any],
    *,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    channel = _string_from(issue.get("channel")).lower() or "email"
    context = _reply_channel_context(issue)
    target = _reply_target_context(issue, context)
    target_value = _string_from(target.get("value"))
    blockers: list[str] = []
    missing_env: list[str] = []
    channel_key = _reply_delivery_channel_key(context, channel)
    channel_record: dict[str, Any] | None = None
    if channel_key and channel != "web_chat":
        channel_record = get_channel_by_key(channel_key, tenant_id=tenant_id, project_id=project_id) or None
    channel_config = channel_record.get("config") if isinstance(channel_record, dict) and isinstance(channel_record.get("config"), dict) else {}
    if channel == "email" and channel_key:
        channel_config = {**channel_config}
        channel_config.setdefault("outboundWebhookUrlEnv", "SUPPORT_EMAIL_OUTBOUND_WEBHOOK_URL")
    secrets: dict[str, str] | None = load_runtime_secrets(tenant_id, project_id) if channel_config or channel != "email" else {}
    transport = _string_from(channel_config.get("outboundTransport") or channel_config.get("outbound_transport") or channel_config.get("transport")).lower()
    provider = "smtp" if channel == "email" else f"{channel}_webhook"
    provider_envs: list[str] = []
    if not target_value:
        blockers.append("missing_reply_target")
    if channel == "web_chat":
        transport = "internal"
        provider = "web_chat_internal"
    elif channel == "email":
        webhook_ready, _webhook_missing = _reply_webhook_readiness(channel_config, secrets)
        if webhook_ready:
            transport = "webhook"
            provider = "email_webhook"
        else:
            transport = "smtp"
            provider = "smtp"
            if not (_string_from(os.getenv("SMTP_HOST")) and (_string_from(os.getenv("SMTP_FROM")) or _string_from(os.getenv("SMTP_USER")))):
                blockers.append("smtp_not_configured")
    elif not channel_record:
        blockers.append("channel_not_configured")
    elif _string_from(channel_record.get("status") or "active").lower() != "active":
        blockers.append("channel_inactive")
    else:
        webhook_ready, webhook_missing = _reply_webhook_readiness(channel_config, secrets)
        provider_envs = _reply_provider_required_envs(channel, channel_config)
        missing_provider_envs = [env for env in provider_envs if not _configured_secret_value(env, secrets)]
        if transport in {"webhook", "http", "adapter"} or webhook_ready:
            transport = "webhook"
            provider = f"{channel}_webhook"
            missing_env.extend(webhook_missing)
        elif transport in {"bot", "provider_api", "bot_api", "slack_bot", "teams_bot", "discord_bot", "telegram_bot", "line", "line_messaging", "line_messaging_api", "viber", "viber_bot", "whatsapp", "messenger", "sms", "twilio"} or _reply_provider_transport_supported(channel):
            transport = "provider_api"
            provider = "twilio_sms" if channel in {"sms", "twilio"} else channel
            missing_env.extend(missing_provider_envs)
        else:
            blockers.append("outbound_transport_not_configured")
    if missing_env:
        blockers.append("missing_runtime_secrets")
    return {
        "ready": not blockers and not missing_env,
        "status": "ready" if not blockers and not missing_env else "blocked",
        "transport": transport or "unknown",
        "provider": provider,
        "channelKey": channel_key,
        "target": target,
        "adapter": _reply_adapter_capabilities(
            channel=channel,
            transport=transport,
            provider=provider,
            channel_record=channel_record,
            channel_config=channel_config,
            target=target,
            required_env_vars=provider_envs,
            missing_env_vars=missing_env,
        ),
        "blockers": list(dict.fromkeys(blockers)),
        "missingEnvVars": list(dict.fromkeys(missing_env)),
    }


def issue_reply_readiness_error(readiness: dict[str, Any]) -> str:
    blockers = [_string_from(item) for item in readiness.get("blockers", []) if _string_from(item)]
    missing_env = [_string_from(item) for item in readiness.get("missingEnvVars", []) if _string_from(item)]
    details: list[str] = []
    if blockers:
        details.append(", ".join(blockers))
    if missing_env:
        details.append(f"missing env: {', '.join(missing_env)}")
    return f"Reply channel is blocked: {'; '.join(details)}" if details else "Reply channel is blocked"


def issue_reply_delivery_readiness(
    issue: dict[str, Any],
    reply: dict[str, Any],
    *,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    metadata = _parse(reply.get("metadata"), dict)
    issue_metadata = _record_from(issue.get("metadata"))
    reply_target = _record_from(metadata.get("replyTarget") or metadata.get("reply_target"))
    target_key = _string_from(reply_target.get("key"))
    target_value = _string_from(reply_target.get("value"))
    channel = _string_from(reply.get("channel") or issue.get("channel")).lower() or "email"
    if channel == "email" and not target_value:
        target_key = "email"
        target_value = _string_from(reply.get("to_address") or reply.get("toAddress"))
    readiness_metadata = {**issue_metadata, **metadata}
    if target_key and target_value and not _string_from(readiness_metadata.get(target_key)):
        readiness_metadata[target_key] = target_value
    readiness_issue = {
        **issue,
        "channel": channel,
        "source": _string_from(metadata.get("issueSource") or metadata.get("issue_source") or issue.get("source")),
        "metadata": readiness_metadata,
    }
    if channel == "email" and target_value and target_key == "email":
        readiness_issue.setdefault("contactEmail", target_value)
        readiness_issue.setdefault("fromAddress", target_value)
    return _reply_readiness(readiness_issue, tenant_id=tenant_id, project_id=project_id)


def _issue_operating_proof(
    issue: dict[str, Any],
    *,
    readiness: dict[str, Any],
    knowledge_suggestions: list[dict[str, Any]],
    knowledge_gaps: list[dict[str, Any]],
    ai_runs: list[dict[str, Any]],
    outbound_messages: list[dict[str, Any]],
    action_executions: list[dict[str, Any]],
) -> dict[str, Any]:
    status = _canonical_status(_string_from(issue.get("workflowStatus") or issue.get("status")) or "open")
    channel = _string_from(issue.get("channel")) or "email"
    source = _string_from(issue.get("source"))
    assignee = _string_from(issue.get("assigneeEmail") or issue.get("assignee_email"))
    account = _string_from(issue.get("accountName") or issue.get("account_name"))
    contact = _string_from(
        issue.get("contactEmail")
        or issue.get("contact_email")
        or issue.get("fromAddress")
        or issue.get("from_address")
    )
    target = _record_from(readiness.get("target"))
    target_label = _string_from(target.get("label"))
    draft_count = sum(1 for reply in outbound_messages if _string_from(reply.get("status")) == "draft")
    queued_count = sum(1 for reply in outbound_messages if _string_from(reply.get("status")) == "queued")
    sent_count = sum(1 for reply in outbound_messages if _string_from(reply.get("status")) == "sent")
    failed_count = sum(1 for reply in outbound_messages if _string_from(reply.get("status")) == "failed")
    pending_approval_count = int(issue.get("pendingApprovalCount") or issue.get("pending_approval_count") or 0)
    pending_action_count = sum(1 for action in action_executions if _string_from(action.get("status")) == "pending")
    successful_action_count = sum(1 for action in action_executions if _string_from(action.get("status")) == "success")

    checks: list[dict[str, Any]] = []

    def add_check(key: str, label: str, ready: bool, detail: str, action: str = "") -> None:
        checks.append(
            {
                "key": key,
                "label": label,
                "ready": ready,
                "detail": detail,
                "action": action,
            }
        )

    add_check(
        "source",
        "Channel source",
        bool(channel or source),
        source or f"{channel} channel",
    )
    add_check(
        "assignee",
        "Assignee",
        bool(assignee),
        assignee or "Ticket has no assignee.",
        "" if assignee else "assign_owner",
    )
    add_check(
        "workflow",
        "Workflow lane",
        status in CANONICAL_ISSUE_STATUSES,
        f"Ticket is in {status}.",
    )
    add_check(
        "account",
        "Account/contact",
        bool(account or contact or target_label),
        account or contact or target_label or "No account or contact proof.",
    )
    add_check(
        "knowledge",
        "Knowledge",
        len(knowledge_suggestions) > 0 and len(knowledge_gaps) == 0,
        f"{len(knowledge_suggestions)} suggestions, {len(knowledge_gaps)} open gaps.",
        "fill_knowledge" if knowledge_gaps or not knowledge_suggestions else "",
    )
    add_check(
        "agent",
        "Agent prep",
        bool(ai_runs or draft_count or queued_count or sent_count or successful_action_count),
        f"{len(ai_runs)} agent runs, {draft_count} drafts, {successful_action_count} actions.",
        "" if ai_runs or draft_count or queued_count or sent_count or successful_action_count else "ask_agent",
    )
    add_check(
        "reply_route",
        "Reply route",
        bool(readiness.get("ready")),
        (
            f"{_string_from(readiness.get('provider')) or 'provider'} via "
            f"{_string_from(readiness.get('transport')) or 'unknown'}."
        )
        if readiness.get("ready")
        else issue_reply_readiness_error(readiness),
        "" if readiness.get("ready") else "fix_channel",
    )
    add_check(
        "human_loop",
        "Human loop",
        pending_approval_count > 0 or pending_action_count > 0 or draft_count > 0 or sent_count > 0 or failed_count == 0,
        f"{pending_approval_count} approvals, {pending_action_count} pending actions.",
        "open_review" if pending_approval_count or pending_action_count else "",
    )

    ready_count = sum(1 for check in checks if check["ready"])
    blocked_keys = [_string_from(check.get("key")) for check in checks if not check.get("ready")]
    return {
        "kind": "support_ticket_operating_proof",
        "ready": ready_count == len(checks),
        "summary": {
            "totalChecks": len(checks),
            "readyChecks": ready_count,
            "blockedChecks": len(checks) - ready_count,
            "blockedKeys": blocked_keys,
        },
        "checks": checks,
    }


def _reply_metadata_with_delivery_preflight(
    metadata: dict[str, Any],
    readiness: dict[str, Any],
) -> dict[str, Any]:
    checked_at = _now_iso()
    target = _record_from(readiness.get("target"))
    route = {
        "phase": "preflight",
        "status": _string_from(readiness.get("status")) or ("ready" if readiness.get("ready") else "blocked"),
        "ready": bool(readiness.get("ready")),
        "transport": _string_from(readiness.get("transport")) or "unknown",
        "provider": _string_from(readiness.get("provider")),
        "channel": _string_from(target.get("channel")),
        "channelKey": _string_from(readiness.get("channelKey")),
        "target": target,
        "blockers": [
            item
            for item in (_string_from(value) for value in readiness.get("blockers", []))
            if item
        ],
        "missingEnvVars": [
            item
            for item in (_string_from(value) for value in readiness.get("missingEnvVars", []))
            if item
        ],
        "checkedAt": checked_at,
    }
    route = {key: value for key, value in route.items() if value not in ("", [], {})}
    return {
        **metadata,
        "replyReadiness": readiness,
        "replyReadinessCheckedAt": checked_at,
        "deliveryPreflight": route,
        "deliveryRoute": route,
    }


def issue_answer_workspace(
    issue_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    actor_email: str = "",
    actor_role: str = "viewer",
) -> dict[str, Any] | None:
    access_kwargs: dict[str, Any] = {}
    if actor_email:
        access_kwargs["actor_email"] = actor_email
    if actor_role != "viewer":
        access_kwargs["actor_role"] = actor_role
    issue = get_issue(
        issue_id,
        tenant_id=tenant_id,
        project_id=project_id,
        **access_kwargs,
    )
    if not issue:
        return None
    ai_runs = [run for run in _list_records_from(issue.get("aiRuns")) if _string_from(run.get("source")) == "agent_answer"]
    latest_run = ai_runs[0] if ai_runs else {}
    latest_run_metadata = _record_from(latest_run.get("metadata"))
    agent_messages = _list_records_from(issue.get("agentMessages"))
    assistant_messages = [
        message for message in agent_messages
        if _string_from(message.get("role")).lower() == "assistant"
    ]
    latest_agent_message = agent_messages[-1] if agent_messages else {}
    latest_assistant_message = assistant_messages[-1] if assistant_messages else {}
    knowledge_suggestions = _list_records_from(issue.get("knowledgeSuggestions"))
    knowledge_gaps = [
        gap
        for gap in _list_records_from(issue.get("knowledgeGaps"))
        if _string_from(gap.get("status") or "open").lower() == "open"
    ]
    outbound_messages = _list_records_from(issue.get("outboundMessages"))
    action_executions = _list_records_from(issue.get("actionExecutions"))
    draft_replies = [reply for reply in outbound_messages if _string_from(reply.get("status")) == "draft"]
    queued_replies = [reply for reply in outbound_messages if _string_from(reply.get("status")) == "queued"]
    failed_replies = [reply for reply in outbound_messages if _string_from(reply.get("status")) == "failed"]
    sent_replies = [reply for reply in outbound_messages if _string_from(reply.get("status")) == "sent"]
    citation_count = len(_list_records_from(latest_run_metadata.get("citations") or latest_run.get("toolCalls")))
    readiness = _reply_readiness(issue, tenant_id=tenant_id, project_id=project_id)
    return {
        "kind": "support_issue_answer_workspace",
        "issueId": _string_from(issue.get("id")),
        "status": _canonical_status(_string_from(issue.get("workflowStatus") or issue.get("status")) or "open"),
        "nextAction": _issue_answer_workspace_next_action(issue),
        "agent": {
            "runCount": len(ai_runs),
            "messageCount": len(agent_messages),
            "latestMessageId": _string_from(latest_agent_message.get("id")),
            "latestAssistantMessageId": _string_from(latest_assistant_message.get("id")),
            "latestMessagePreview": _clip(_string_from(latest_agent_message.get("body")), 300),
            "latestRunId": _string_from(latest_run.get("id")),
            "latestQuestion": _string_from(latest_run_metadata.get("question")),
            "latestAnswerPreview": _clip(_string_from(latest_run_metadata.get("answer") or latest_run.get("summary")), 500),
            "confidence": _string_from(latest_run_metadata.get("confidence")),
            "citationCount": citation_count,
            "hasDraft": any(_string_from(reply.get("id")) == _string_from(latest_run_metadata.get("replyId")) for reply in outbound_messages),
        },
        "knowledge": {
            "suggestionCount": len(knowledge_suggestions),
            "openGapCount": len(knowledge_gaps),
            "topSuggestionIds": [_string_from(article.get("id")) for article in knowledge_suggestions[:5] if _string_from(article.get("id"))],
            "topGapId": _string_from(knowledge_gaps[0].get("id")) if knowledge_gaps else "",
            "covered": len(knowledge_suggestions) > 0 and len(knowledge_gaps) == 0,
        },
        "reply": {
            "draftCount": len(draft_replies),
            "queuedCount": len(queued_replies),
            "sentCount": len(sent_replies),
            "failedCount": len(failed_replies),
            "latestReplyId": _string_from(outbound_messages[0].get("id")) if outbound_messages else "",
        },
        "humanLoop": {
            "pendingApprovalCount": int(issue.get("pendingApprovalCount") or 0),
            "pendingReplyApprovalCount": int(issue.get("pendingReplyApprovalCount") or 0),
            "pendingActionApprovalCount": int(issue.get("pendingActionApprovalCount") or 0),
            "pendingActionCount": sum(1 for action in action_executions if _string_from(action.get("status")) == "pending"),
            "requiresReview": bool(issue.get("hasPendingApproval")) or int(issue.get("pendingApprovalCount") or 0) > 0,
        },
        "channel": {
            "channel": _string_from(issue.get("channel")),
            "source": _string_from(issue.get("source")),
            "canAnswerFromApp": bool(readiness.get("ready")),
        },
        "replyReadiness": readiness,
        "ticketProof": _issue_operating_proof(
            issue,
            readiness=readiness,
            knowledge_suggestions=knowledge_suggestions,
            knowledge_gaps=knowledge_gaps,
            ai_runs=ai_runs,
            outbound_messages=outbound_messages,
            action_executions=action_executions,
        ),
    }


def list_issue_notifications(
    *,
    tenant_id: str | None,
    project_id: str,
    recipient_email: str,
    status: str = "unread",
    limit: int = 50,
) -> list[dict[str, Any]]:
    recipient = _string_from(recipient_email).lower()
    if not recipient:
        return []
    extra_parts = [f"recipient_email='{_escape_pb(recipient)}'"]
    clean_status = _string_from(status).lower()
    if clean_status and clean_status != "all":
        extra_parts.append(f"status='{_escape_pb(clean_status)}'")
    records = _list_all(
        "support_notifications",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=" && ".join(extra_parts),
        ),
        sort="-created",
        per_page=max(1, min(limit, 200)),
    )
    return [_normalize_notification(rec) for rec in records[:limit]]


def mark_issue_notification_read(
    notification_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    recipient_email: str,
) -> dict[str, Any] | None:
    recipient = _string_from(recipient_email).lower()
    if not recipient:
        return None
    rec = _first(
        "support_notifications",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=(
                f"id='{_escape_pb(notification_id)}' && "
                f"recipient_email='{_escape_pb(recipient)}'"
            ),
        ),
    )
    if not rec:
        return None
    data = {"status": "read", "read_at": _now_iso()}
    patched = _patch(f"/api/collections/support_notifications/records/{rec['id']}", data)
    return _normalize_notification({**rec, **patched, **data})


def list_support_queues(
    *,
    tenant_id: str | None,
    project_id: str,
    status: str = "active",
    include_owner_workload: bool = False,
) -> list[dict[str, Any]]:
    extra = ""
    clean_status = _string_from(status).lower()
    if clean_status and clean_status != "all":
        extra = f"status='{_escape_pb(clean_status)}'"
    records = _list_all(
        "support_queues",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=extra),
        sort="name",
        per_page=200,
    )
    items = [_normalize_queue(rec) for rec in records]
    if clean_status in {"", "all", "active"} and not any(item["queueKey"] == DEFAULT_QUEUE_KEY for item in items):
        items.insert(0, {
            "id": "default-support",
            "queueKey": DEFAULT_QUEUE_KEY,
            "name": DEFAULT_QUEUE_NAME,
            "description": "",
            "defaultAssigneeEmail": "",
            "status": "active",
            "metadata": {"virtual": True},
            "created": "",
            "updated": "",
        })
    if include_owner_workload:
        workload_issues = _list_all(
            "support_issues",
            _issue_filter(tenant_id=tenant_id, project_id=project_id),
            sort="-created",
            per_page=500,
        )
        workloads_by_queue = _queue_owner_workloads(
            support_queues=items,
            issues=workload_issues,
        )
        for item in items:
            item["ownerWorkloads"] = workloads_by_queue.get(item["queueKey"], [])
    return items


def list_inbox_views(
    *,
    tenant_id: str | None,
    project_id: str,
    owner_email: str = "",
) -> list[dict[str, Any]]:
    owner = _string_from(owner_email).lower()
    records = _list_all(
        "support_inbox_views",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="sort_order,name",
        per_page=200,
    )
    items = []
    for rec in records:
        visibility = _string_from(rec.get("visibility")) or "private"
        record_owner = _string_from(rec.get("owner_email")).lower()
        if visibility == "shared" or not owner or record_owner == owner:
            items.append(_normalize_inbox_view(rec))
    return items


def upsert_inbox_view(
    *,
    tenant_id: str | None,
    project_id: str,
    owner_email: str,
    view_id: str = "",
    name: str = "",
    visibility: str = "private",
    filters: dict[str, Any] | None = None,
    sort_order: int = 0,
) -> dict[str, Any]:
    clean_name = _string_from(name)
    if not clean_name:
        raise ValueError("View name is required")
    clean_visibility = _string_from(visibility).lower() or "private"
    if clean_visibility not in {"private", "shared"}:
        raise ValueError(f"Unsupported view visibility: {clean_visibility}")
    clean_owner = _string_from(owner_email).lower()
    data = {
        "name": clean_name[:120],
        "visibility": clean_visibility,
        "owner_email": clean_owner,
        "filters": filters or {},
        "sort_order": int(sort_order or 0),
    }
    existing = None
    if view_id:
        existing = _first(
            "support_inbox_views",
            _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=f"id='{_escape_pb(view_id)}'"),
        )
        if not existing:
            raise ValueError("Inbox view not found")
        existing_owner = _string_from(existing.get("owner_email")).lower()
        if existing_owner and clean_owner and existing_owner != clean_owner:
            raise ValueError("Only the owner can update this view")
    if existing:
        patched = _patch(f"/api/collections/support_inbox_views/records/{existing['id']}", data)
        return _normalize_inbox_view({**existing, **patched, **data})
    create_data = {"id": generate_id(), **data}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _normalize_inbox_view(_post("/api/collections/support_inbox_views/records", create_data))


def delete_inbox_view(
    view_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    owner_email: str,
) -> bool:
    rec = _first(
        "support_inbox_views",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=f"id='{_escape_pb(view_id)}'"),
    )
    if not rec:
        return False
    owner = _string_from(owner_email).lower()
    record_owner = _string_from(rec.get("owner_email")).lower()
    if record_owner and owner and record_owner != owner:
        raise ValueError("Only the owner can delete this view")
    return _delete(f"/api/collections/support_inbox_views/records/{rec['id']}")


def _clean_reply_macro_tags(tags: list[str] | None) -> list[str]:
    cleaned: list[str] = []
    seen: set[str] = set()
    for raw_tag in tags or []:
        tag = _string_from(raw_tag).replace("\n", " ").strip()[:64]
        key = tag.lower()
        if not tag or key in seen:
            continue
        seen.add(key)
        cleaned.append(tag)
        if len(cleaned) >= 20:
            break
    return cleaned


def _reply_macro_is_visible(rec: dict[str, Any], owner_email: str) -> bool:
    visibility = _string_from(rec.get("visibility")).lower() or "shared"
    record_owner = _string_from(rec.get("owner_email")).lower()
    return visibility == "shared" or bool(owner_email and record_owner == owner_email)


def _macro_record_value(record: dict[str, Any], key: str) -> str:
    value = record.get(key)
    if isinstance(value, str):
        return value.strip()
    if isinstance(value, (int, float, bool)):
        return str(value)
    return ""


def _reply_macro_custom_field_value(issue: dict[str, Any], field_key: str) -> str:
    custom_fields = _parse(issue.get("customFields"), dict)
    value = _macro_record_value(custom_fields, field_key)
    if value:
        return value
    metadata = _parse(issue.get("metadata"), dict)
    return _macro_record_value(_parse(metadata.get("customFields") or metadata.get("custom_fields"), dict), field_key)


def _reply_macro_account_health(issue: dict[str, Any]) -> str:
    value = _string_from(issue.get("accountHealth") or issue.get("accountHealthStatus") or issue.get("healthStatus"))
    if value:
        return value
    metadata = _parse(issue.get("metadata"), dict)
    account = _parse(metadata.get("account"), dict)
    return _string_from(account.get("healthStatus") or account.get("health_status"))


def _reply_macro_token_value(token: str, *, issue: dict[str, Any], actor_email: str) -> str:
    key = token.strip().lower()
    if not key:
        return ""
    if key == "today":
        return datetime.now(timezone.utc).date().isoformat()
    if key == "now":
        return datetime.now(timezone.utc).replace(microsecond=0).isoformat()
    if key.startswith(("custom.", "field.", "customfields.")):
        return _reply_macro_custom_field_value(issue, token.split(".", 1)[1])
    values = {
        "ticket.id": _string_from(issue.get("id")),
        "issue.id": _string_from(issue.get("id")),
        "ticket.subject": _string_from(issue.get("subject")),
        "issue.subject": _string_from(issue.get("subject")),
        "ticket.status": _string_from(issue.get("workflowStatus") or issue.get("status")),
        "issue.status": _string_from(issue.get("workflowStatus") or issue.get("status")),
        "ticket.priority": _string_from(issue.get("priority")),
        "issue.priority": _string_from(issue.get("priority")),
        "ticket.channel": _string_from(issue.get("channel")),
        "issue.channel": _string_from(issue.get("channel")),
        "ticket.queue": _string_from(issue.get("queueName") or issue.get("queueKey")),
        "issue.queue": _string_from(issue.get("queueName") or issue.get("queueKey")),
        "queue.name": _string_from(issue.get("queueName")),
        "queue.key": _string_from(issue.get("queueKey")),
        "assignee.email": _string_from(issue.get("assigneeEmail")),
        "owner.email": _string_from(issue.get("assigneeEmail")),
        "agent.email": _string_from(actor_email).lower(),
        "current_user.email": _string_from(actor_email).lower(),
        "contact.name": _string_from(issue.get("contactName")),
        "customer.name": _string_from(issue.get("contactName")),
        "requester.name": _string_from(issue.get("contactName")),
        "contact.email": _string_from(issue.get("contactEmail") or issue.get("fromAddress")),
        "customer.email": _string_from(issue.get("contactEmail") or issue.get("fromAddress")),
        "requester.email": _string_from(issue.get("contactEmail") or issue.get("fromAddress")),
        "account.name": _string_from(issue.get("accountName")),
        "account.domain": _string_from(issue.get("accountDomain")),
        "account.health": _reply_macro_account_health(issue),
    }
    return values.get(key, "")


def _render_reply_macro_body(body: str, *, issue: dict[str, Any], actor_email: str) -> str:
    def replace(match: re.Match[str]) -> str:
        token = match.group(1)
        value = _reply_macro_token_value(token, issue=issue, actor_email=actor_email)
        return value or match.group(0)

    return REPLY_MACRO_TOKEN_RE.sub(replace, body)


def _unresolved_reply_macro_tokens(body: str) -> list[str]:
    tokens: list[str] = []
    seen: set[str] = set()
    for token in REPLY_MACRO_TOKEN_RE.findall(body):
        clean = token.strip()
        key = clean.lower()
        if not clean or key in seen:
            continue
        seen.add(key)
        tokens.append(clean)
    return tokens


def list_reply_macros(
    *,
    tenant_id: str | None,
    project_id: str,
    owner_email: str = "",
    status: str = "active",
    limit: int = 200,
) -> list[dict[str, Any]]:
    clean_status = _string_from(status).lower()
    extra = ""
    if clean_status and clean_status != "all":
        extra = f"status='{_escape_pb(clean_status)}'"
    records = _list_all(
        "support_reply_macros",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=extra),
        sort="title",
        per_page=max(1, min(limit, 200)),
    )
    owner = _string_from(owner_email).lower()
    items = [_normalize_reply_macro(rec) for rec in records if _reply_macro_is_visible(rec, owner)]
    return items[:limit]


def render_reply_macro(
    macro_id: str,
    *,
    issue_id: str,
    tenant_id: str | None,
    project_id: str,
    owner_email: str,
) -> dict[str, Any] | None:
    macro = _first(
        "support_reply_macros",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"id='{_escape_pb(macro_id)}' && status='active'",
        ),
    )
    owner = _string_from(owner_email).lower()
    if not macro or not _reply_macro_is_visible(macro, owner):
        return None
    issue = get_issue(
        issue_id,
        tenant_id=tenant_id,
        project_id=project_id,
        actor_email=owner,
        actor_role="viewer",
    )
    if not issue:
        raise ValueError("Issue not found")
    normalized_macro = _normalize_reply_macro(macro)
    body = _render_reply_macro_body(normalized_macro["body"], issue=issue, actor_email=owner)
    return {
        "macro": normalized_macro,
        "issueId": issue["id"],
        "body": body,
        "unresolvedVariables": _unresolved_reply_macro_tokens(body),
    }


def upsert_reply_macro(
    *,
    tenant_id: str | None,
    project_id: str,
    owner_email: str,
    macro_id: str = "",
    title: str = "",
    body: str = "",
    visibility: str = "shared",
    status: str = "active",
    tags: list[str] | None = None,
    metadata: dict[str, Any] | None = None,
) -> dict[str, Any]:
    clean_title = _string_from(title)
    clean_body = _string_from(body)
    if not clean_title:
        raise ValueError("Macro title is required")
    if not clean_body:
        raise ValueError("Macro body is required")
    clean_visibility = _string_from(visibility).lower() or "shared"
    if clean_visibility not in {"private", "shared"}:
        raise ValueError(f"Unsupported macro visibility: {clean_visibility}")
    clean_status = _string_from(status).lower() or "active"
    if clean_status not in {"active", "archived"}:
        raise ValueError(f"Unsupported macro status: {clean_status}")
    clean_owner = _string_from(owner_email).lower()
    data = {
        "title": clean_title[:160],
        "body": clean_body,
        "visibility": clean_visibility,
        "owner_email": clean_owner,
        "status": clean_status,
        "tags": _clean_reply_macro_tags(tags),
        "metadata": metadata or {},
    }
    existing = None
    if macro_id:
        existing = _first(
            "support_reply_macros",
            _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=f"id='{_escape_pb(macro_id)}'"),
        )
        if not existing:
            raise ValueError("Reply macro not found")
        existing_visibility = _string_from(existing.get("visibility")).lower() or "shared"
        existing_owner = _string_from(existing.get("owner_email")).lower()
        if existing_visibility == "private" and existing_owner and clean_owner and existing_owner != clean_owner:
            raise ValueError("Only the owner can update this macro")
    if existing:
        patched = _patch(f"/api/collections/support_reply_macros/records/{existing['id']}", data)
        return _normalize_reply_macro({**existing, **patched, **data})
    create_data = {"id": generate_id(), **data}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _normalize_reply_macro(_post("/api/collections/support_reply_macros/records", create_data))


def archive_reply_macro(
    macro_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    owner_email: str,
) -> dict[str, Any] | None:
    rec = _first(
        "support_reply_macros",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=f"id='{_escape_pb(macro_id)}'"),
    )
    if not rec:
        return None
    owner = _string_from(owner_email).lower()
    visibility = _string_from(rec.get("visibility")).lower() or "shared"
    record_owner = _string_from(rec.get("owner_email")).lower()
    if visibility == "private" and record_owner and owner and record_owner != owner:
        raise ValueError("Only the owner can archive this macro")
    data = {"status": "archived"}
    patched = _patch(f"/api/collections/support_reply_macros/records/{rec['id']}", data)
    return _normalize_reply_macro({**rec, **patched, **data})


def upsert_support_queue(
    *,
    tenant_id: str | None,
    project_id: str,
    queue_key: str = "",
    name: str = "",
    description: str = "",
    default_assignee_email: str = "",
    status: str = "active",
    metadata: dict[str, Any] | None = None,
) -> dict[str, Any]:
    clean_key = _queue_key_from(queue_key) or _queue_key_from(name)
    if not clean_key:
        raise ValueError("Queue key or name is required")
    clean_name = _queue_name_from(clean_key, name)
    clean_status = _string_from(status).lower() or "active"
    if clean_status not in {"active", "archived"}:
        raise ValueError(f"Unsupported queue status: {clean_status}")
    clean_metadata, allowed_assignees = _queue_metadata_with_allowed_assignees(metadata)
    clean_default_assignee = _string_from(default_assignee_email)
    if allowed_assignees and clean_default_assignee and clean_default_assignee.lower() not in allowed_assignees:
        raise ValueError("Default assignee must be included in queue owners")
    data = {
        "queue_key": clean_key,
        "name": clean_name,
        "description": _string_from(description),
        "default_assignee_email": clean_default_assignee,
        "status": clean_status,
        "metadata": clean_metadata,
    }
    existing = _first(
        "support_queues",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=f"queue_key='{_escape_pb(clean_key)}'"),
    )
    if existing:
        patched = _patch(f"/api/collections/support_queues/records/{existing['id']}", data)
        return _normalize_queue({**existing, **patched})
    create_data = {"id": generate_id(), **data}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _normalize_queue(_post("/api/collections/support_queues/records", create_data))


