def record_channel_webhook_event(
    *,
    tenant_id: str | None,
    project_id: str,
    channel_id: str,
    provider: str,
    event_id: str,
    event_type: str,
    provider_message_id: str,
    status: str,
    payload: dict[str, Any],
    outbound_message_id: str = "",
    result: dict[str, Any] | None = None,
    error: str = "",
    received_at: str = "",
    processed_at: str = "",
    processing_claim_token: str = "",
    processing_claimed_at: str = "",
    processing_claim_expires_at: str = "",
    processing_attempt: int = 0,
    processing_retry_safe: bool = False,
    retry_policy_version: int = 0,
) -> dict[str, Any]:
    data: dict[str, Any] = {
        "id": generate_id(),
        "channel": channel_id,
        "provider": provider,
        "event_id": event_id,
        "event_type": event_type,
        "provider_message_id": provider_message_id,
        "status": status,
        "error": error,
        "payload": payload,
        "result": result or {},
        "received_at": received_at or _now_iso(),
        "processed_at": processed_at,
    }
    if processing_claim_token:
        data.update(
            {
                "processing_claim_token": processing_claim_token,
                "processing_claimed_at": processing_claimed_at,
                "processing_claim_expires_at": processing_claim_expires_at,
                "processing_attempt": processing_attempt,
                "processing_retry_safe": processing_retry_safe,
                "retry_policy_version": retry_policy_version,
            }
        )
    if outbound_message_id:
        data["outbound_message"] = outbound_message_id
    if tenant_id:
        data["tenant"] = tenant_id
    data["project"] = project_id
    return _normalize_channel_webhook_event(_post("/api/collections/support_channel_webhook_events/records", data))


def _claim_channel_webhook_event(
    *,
    tenant_id: str | None,
    project_id: str,
    channel_id: str,
    provider: str,
    event_id: str,
    event_type: str,
    provider_message_id: str,
    payload: dict[str, Any],
    received_at: str,
) -> tuple[dict[str, Any], str]:
    """Acquire durable ownership for one event, including safe stale retries."""
    existing = get_channel_webhook_event(
        channel_id,
        event_id,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    if existing:
        return _claim_existing_channel_webhook_event(
            existing,
            tenant_id=tenant_id,
            project_id=project_id,
        )

    claim_token = secrets.token_hex(16)
    claimed_at = _now_utc()
    claimed_at_iso = claimed_at.isoformat()
    expires_at = (claimed_at + timedelta(seconds=CHANNEL_WEBHOOK_CLAIM_LEASE_SECONDS)).isoformat()
    claim_result = {
        "_webhookClaim": {
            "version": 1,
            "retryPolicyVersion": CHANNEL_WEBHOOK_RETRY_POLICY_VERSION,
            "attempt": 1,
            "tokenFingerprint": hashlib.sha256(claim_token.encode("utf-8")).hexdigest()[:12],
            "workerId": _channel_webhook_worker_id(),
            "claimedAt": claimed_at_iso,
            "leaseExpiresAt": expires_at,
            "history": [],
        }
    }
    try:
        created = record_channel_webhook_event(
            tenant_id=tenant_id,
            project_id=project_id,
            channel_id=channel_id,
            provider=provider,
            event_id=event_id,
            event_type=event_type,
            provider_message_id=provider_message_id,
            status="received",
            payload=payload,
            result=claim_result,
            received_at=received_at,
            processing_claim_token=claim_token,
            processing_claimed_at=claimed_at_iso,
            processing_claim_expires_at=expires_at,
            processing_attempt=1,
            retry_policy_version=CHANNEL_WEBHOOK_RETRY_POLICY_VERSION,
        )
        return created, claim_token
    except httpx.HTTPStatusError as exc:
        if exc.response.status_code not in {400, 409}:
            raise
        for attempt in range(CHANNEL_WEBHOOK_REPLAY_POLL_ATTEMPTS):
            winner = get_channel_webhook_event(
                channel_id,
                event_id,
                tenant_id=tenant_id,
                project_id=project_id,
            )
            if winner:
                return winner, ""
            if attempt + 1 < CHANNEL_WEBHOOK_REPLAY_POLL_ATTEMPTS:
                time.sleep(CHANNEL_WEBHOOK_REPLAY_POLL_INTERVAL_SECONDS)
        raise


def _channel_webhook_worker_id() -> str:
    host = _string_from(os.getenv("HOSTNAME")) or "support-worker"
    return f"{host}:{os.getpid()}:{threading.get_ident()}"


def _claim_existing_channel_webhook_event(
    webhook_event: dict[str, Any],
    *,
    tenant_id: str | None,
    project_id: str,
) -> tuple[dict[str, Any], str]:
    status = _string_from(webhook_event.get("status")).lower()
    claim_expires_at = _parse_iso_datetime(webhook_event.get("processingClaimExpiresAt"))
    stale_received = status == "received" and (
        not _string_from(webhook_event.get("processingClaimToken"))
        or claim_expires_at is None
        or claim_expires_at <= _now_utc()
    )
    retryable_failed = (
        status == "failed"
        and bool(webhook_event.get("processingRetrySafe"))
        and int(webhook_event.get("retryPolicyVersion") or 0) == CHANNEL_WEBHOOK_RETRY_POLICY_VERSION
        and int(webhook_event.get("processingAttempt") or 0) < CHANNEL_WEBHOOK_MAX_PROCESSING_ATTEMPTS
    )
    if not stale_received and not retryable_failed:
        return webhook_event, ""

    claim = _post(
        f"/api/mantly/support-channel-webhooks/{quote(_string_from(webhook_event.get('id')), safe='')}/claim",
        {
            "project_id": project_id,
            "tenant_id": tenant_id or "",
            "worker_id": _channel_webhook_worker_id(),
            "lease_seconds": CHANNEL_WEBHOOK_CLAIM_LEASE_SECONDS,
            "allow_failed": retryable_failed,
            "retry_policy_version": CHANNEL_WEBHOOK_RETRY_POLICY_VERSION,
            "max_attempts": CHANNEL_WEBHOOK_MAX_PROCESSING_ATTEMPTS,
        },
    )
    event = _record_from(claim.get("event"))
    normalized = _normalize_channel_webhook_event(event) if event else webhook_event
    claim_token = _string_from(claim.get("claim_token"))
    if claim.get("claimed") is True and claim_token:
        normalized.update(
            {
                "processingClaimToken": claim_token,
                "processingClaimedAt": _string_from(claim.get("claimed_at")),
                "processingClaimExpiresAt": _string_from(claim.get("lease_expires_at")),
                "processingAttempt": int(claim.get("attempt") or 0),
                "retryPolicyVersion": CHANNEL_WEBHOOK_RETRY_POLICY_VERSION,
            }
        )
        return normalized, claim_token
    return normalized, ""


def _wait_for_channel_webhook_winner(
    webhook_event: dict[str, Any],
    *,
    channel_id: str,
    event_id: str,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    """Briefly wait for the claim owner to persist its terminal result."""
    winner = webhook_event
    for attempt in range(CHANNEL_WEBHOOK_REPLAY_POLL_ATTEMPTS):
        if _string_from(winner.get("status")) in CHANNEL_WEBHOOK_TERMINAL_STATUSES:
            return winner
        if attempt + 1 >= CHANNEL_WEBHOOK_REPLAY_POLL_ATTEMPTS:
            break
        time.sleep(CHANNEL_WEBHOOK_REPLAY_POLL_INTERVAL_SECONDS)
        refreshed = get_channel_webhook_event(
            channel_id,
            event_id,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        if refreshed:
            winner = refreshed
    return winner


def _channel_webhook_replay_item(
    webhook_event: dict[str, Any],
    *,
    event_id: str,
    event_type: str,
    provider_message_id: str,
) -> dict[str, Any]:
    """Return the winner's stored result using stable skipped replay fields."""
    winner_status = _string_from(webhook_event.get("status"))
    if winner_status == "processed":
        replay_error = "Event already processed"
    elif winner_status in CHANNEL_WEBHOOK_TERMINAL_STATUSES:
        replay_error = f"Event already handled with status {winner_status}"
    else:
        replay_error = "Event processing already claimed"
    stored_result = {
        key: value
        for key, value in _record_from(webhook_event.get("result")).items()
        if not key.startswith("_")
    }
    replay_item = {
        **stored_result,
        "eventId": event_id,
        "eventType": event_type,
        "providerMessageId": provider_message_id,
        "status": "skipped",
        "error": replay_error,
        "winnerStatus": winner_status or "received",
    }
    winner_error = _string_from(webhook_event.get("error"))
    if winner_error:
        replay_item["winnerError"] = winner_error
    return replay_item


def _complete_channel_webhook_claim(
    webhook_event_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    claim_token: str,
    status: str,
    result: dict[str, Any] | None = None,
    error: str = "",
    outbound_message_id: str = "",
    retry_safe: bool = False,
) -> dict[str, Any] | None:
    """Finalize only while ``claim_token`` remains the current durable owner."""
    del tenant_id, project_id
    path = f"/api/mantly/support-channel-webhooks/{quote(webhook_event_id, safe='')}/complete"
    payload = {
        "claim_token": claim_token,
        "status": status,
        "result": result or {},
        "error": error,
        "outbound_message_id": outbound_message_id,
        "retry_safe": retry_safe,
    }
    try:
        completion = _post(path, payload)
    except httpx.RequestError:
        completion = _post(path, payload)
    event = _record_from(completion.get("event"))
    if completion.get("completed") is not True or not event:
        raise RuntimeError("PocketBase returned an invalid channel webhook completion")
    return _normalize_channel_webhook_event(event)


def _try_complete_channel_webhook_claim(
    webhook_event_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    claim_token: str,
    status: str,
    result: dict[str, Any] | None = None,
    error: str = "",
    outbound_message_id: str = "",
    retry_safe: bool = False,
) -> bool:
    try:
        _complete_channel_webhook_claim(
            webhook_event_id,
            tenant_id=tenant_id,
            project_id=project_id,
            claim_token=claim_token,
            status=status,
            result=result,
            error=error,
            outbound_message_id=outbound_message_id,
            retry_safe=retry_safe,
        )
    except httpx.HTTPStatusError as exc:
        if exc.response.status_code != 409:
            raise
        return False
    return True


def update_channel_webhook_event(
    webhook_event_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    status: str,
    outbound_message_id: str = "",
    result: dict[str, Any] | None = None,
    error: str = "",
    processed_at: str = "",
) -> dict[str, Any] | None:
    rec = _first(
        "support_channel_webhook_events",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"id='{_escape_pb(webhook_event_id)}'",
        ),
    )
    if not rec:
        return None
    data: dict[str, Any] = {
        "status": status,
        "result": result or {},
        "error": error,
        "processed_at": processed_at or _now_iso(),
    }
    if outbound_message_id:
        data["outbound_message"] = outbound_message_id
    _patch(f"/api/collections/support_channel_webhook_events/records/{rec['id']}", data)
    return _normalize_channel_webhook_event({**rec, **data})


def rematch_channel_webhook_event(
    webhook_event_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    outbound_message_id: str = "",
) -> dict[str, Any] | None:
    rec = _first(
        "support_channel_webhook_events",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"id='{_escape_pb(webhook_event_id)}'",
        ),
    )
    if not rec:
        return None

    event = _parse(rec.get("payload"), dict)
    if outbound_message_id:
        event = {**event, "outboundMessageId": outbound_message_id}
    event_type = _string_from(rec.get("event_type")) or _channel_event_type(event)
    provider = _string_from(rec.get("provider")) or _channel_provider(event, {"type": "channel"})
    provider_message_id = _channel_receipt_provider_message_id(
        event,
        provider=provider,
        fallback=_string_from(rec.get("provider_message_id")) or _channel_provider_message_id(event),
    )
    outbound = _find_outbound_for_receipt(
        tenant_id=tenant_id,
        project_id=project_id,
        provider_message_id=provider_message_id,
        event=event,
        provider=provider,
    )
    if not outbound:
        result = {
            "matched": False,
            "rematched": True,
            "providerMessageId": provider_message_id,
            "eventType": event_type,
        }
        return update_channel_webhook_event(
            webhook_event_id,
            tenant_id=tenant_id,
            project_id=project_id,
            status="unmatched",
            result=result,
        )

    updated_outbound = _apply_channel_delivery_receipt(
        tenant_id=tenant_id,
        project_id=project_id,
        outbound=outbound,
        event=event,
        event_type=event_type,
        provider=provider,
        provider_message_id=provider_message_id,
    )
    result = {
        "matched": True,
        "rematched": True,
        "outboundMessageId": updated_outbound["id"],
        "outboundStatus": updated_outbound["status"],
        "issueId": updated_outbound.get("issueId", ""),
        "providerMessageId": provider_message_id,
        "eventType": event_type,
    }
    return update_channel_webhook_event(
        webhook_event_id,
        tenant_id=tenant_id,
        project_id=project_id,
        status="processed",
        outbound_message_id=updated_outbound["id"],
        result=result,
    )


def list_channel_webhook_events(
    *,
    tenant_id: str | None,
    project_id: str,
    channel_id: str = "",
    status: str = "",
    limit: int = 50,
) -> list[dict[str, Any]]:
    extras: list[str] = []
    if channel_id:
        extras.append(f"channel='{_escape_pb(channel_id)}'")
    if status:
        extras.append(f"status='{_escape_pb(status)}'")
    records = _list_all(
        "support_channel_webhook_events",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=" && ".join(extras)),
        sort="-received_at",
        per_page=max(1, min(limit, 200)),
    )
    return [_normalize_channel_webhook_event(rec) for rec in records[:limit]]


def _channel_events_from_payload(payload: Any) -> list[dict[str, Any]]:
    if isinstance(payload, list):
        return [item for item in payload if isinstance(item, dict)]
    if not isinstance(payload, dict):
        return []
    twilio_events = _twilio_events_from_payload(payload)
    if twilio_events:
        return twilio_events
    whatsapp_events = _whatsapp_events_from_payload(payload)
    if whatsapp_events:
        return whatsapp_events
    messenger_events = _messenger_events_from_payload(payload)
    if messenger_events:
        return messenger_events
    instagram_events = _instagram_events_from_payload(payload)
    if instagram_events:
        return instagram_events
    line_events = _line_events_from_payload(payload)
    if line_events:
        return line_events
    viber_events = _viber_events_from_payload(payload)
    if viber_events:
        return viber_events
    twitter_events = _twitter_events_from_payload(payload)
    if twitter_events:
        return twitter_events
    for key in ("events", "items", "records"):
        value = payload.get(key)
        if isinstance(value, list):
            return [item for item in value if isinstance(item, dict)]
    return [payload]


def _twilio_provider_message_id(message_sid: str) -> str:
    clean_sid = _string_from(message_sid)
    if not clean_sid:
        return ""
    return clean_sid if clean_sid.startswith("twilio:") else f"twilio:{clean_sid}"


def _twilio_media_attachments(payload: dict[str, Any]) -> list[dict[str, Any]]:
    try:
        media_count = int(_first_string(payload, ("NumMedia", "num_media", "numMedia")) or "0")
    except ValueError:
        media_count = 0
    attachments: list[dict[str, Any]] = []
    for index in range(max(0, media_count)):
        url = _first_string(payload, (f"MediaUrl{index}", f"media_url_{index}", f"mediaUrl{index}"))
        content_type = _first_string(
            payload,
            (f"MediaContentType{index}", f"media_content_type_{index}", f"mediaContentType{index}"),
        )
        if not url and not content_type:
            continue
        attachment: dict[str, Any] = {
            "id": f"twilio-media-{index}",
            "filename": f"twilio-media-{index}",
            "provider": "sms",
        }
        if url:
            attachment["url"] = url
        if content_type:
            attachment["contentType"] = content_type
        attachments.append(attachment)
    return attachments


def _twilio_status_value(payload: dict[str, Any]) -> str:
    return _event_token(_first_string(payload, ("MessageStatus", "SmsStatus", "message_status", "sms_status")))


def _twilio_events_from_payload(payload: dict[str, Any]) -> list[dict[str, Any]]:
    message_sid = _first_string(payload, ("MessageSid", "SmsSid", "SmsMessageSid", "message_sid", "sms_sid"))
    account_sid = _first_string(payload, ("AccountSid", "account_sid"))
    from_number = _first_string(payload, ("From", "from"))
    to_number = _first_string(payload, ("To", "to"))
    body = _first_string(payload, ("Body", "body", "text"))
    status = _twilio_status_value(payload)
    media = _twilio_media_attachments(payload)
    if not message_sid and not from_number and not to_number and not body and not media:
        return []
    provider_message_id = _twilio_provider_message_id(message_sid)
    messaging_service_sid = _first_string(payload, ("MessagingServiceSid", "messaging_service_sid"))
    if (body or media) and status in {"", "received"}:
        channel_id = to_number or messaging_service_sid or _first_string(payload, ("ToCountry", "to_country"))
        contact_name = _first_string(payload, ("ProfileName", "profile_name", "FromCity", "from_city")) or from_number
        message_record: dict[str, Any] = {
            "id": message_sid,
            "messageId": message_sid,
            "providerMessageId": provider_message_id,
            "channelId": channel_id,
            "chatId": from_number,
            "conversationId": from_number,
            "threadId": from_number,
            "text": body,
            "from": {"id": from_number, "name": contact_name, "phone": from_number},
            "senderId": from_number,
            "senderName": contact_name,
            "workspaceId": account_sid or channel_id,
            "accountSid": account_sid,
            "messagingServiceSid": messaging_service_sid,
            "to": to_number,
            "direction": "inbound",
            "attachments": media,
        }
        return [{
            "eventId": message_sid or f"sms:{from_number}:{to_number}",
            "eventType": "message",
            "provider": "sms",
            "providerMessageId": provider_message_id,
            "message": {key: value for key, value in message_record.items() if value not in ("", [], {})},
            "raw": payload,
        }]
    if status:
        error = _first_string(payload, ("ErrorMessage", "error_message", "ErrorCode", "error_code"))
        return [{
            "eventId": f"{message_sid}:{status}" if message_sid else status,
            "eventType": status,
            "provider": "sms",
            "providerMessageId": provider_message_id,
            "channelId": from_number or messaging_service_sid,
            "chatId": to_number,
            "workspaceId": account_sid or from_number,
            "payload": payload,
            "raw": payload,
            "error": error,
        }]
    return []


def _whatsapp_message_body(message: dict[str, Any]) -> str:
    message_type = _event_token(_first_string(message, ("type", "messageType", "message_type")))
    text = _record_from(message.get("text"))
    if message_type == "text" or text:
        return _first_string(text, ("body", "text")) or _first_string(message, ("body", "text", "caption"))
    for media_key in ("image", "video", "document", "audio", "sticker"):
        media = _record_from(message.get(media_key))
        if media:
            return (
                _first_string(media, ("caption", "filename", "fileName", "file_name", "mime_type", "mimeType"))
                or f"WhatsApp {media_key}"
            )
    button = _record_from(message.get("button"))
    if button:
        return _first_string(button, ("text", "payload")) or "WhatsApp button response"
    interactive = _record_from(message.get("interactive"))
    for key in ("button_reply", "buttonReply", "list_reply", "listReply"):
        reply = _record_from(interactive.get(key))
        if reply:
            return _first_string(reply, ("title", "description", "id")) or "WhatsApp interactive response"
    location = _record_from(message.get("location"))
    if location:
        return _first_string(location, ("name", "address")) or "WhatsApp location shared"
    if isinstance(message.get("contacts"), list):
        return "WhatsApp contact shared"
    return _first_string(message, ("body", "text", "caption"))


def _whatsapp_message_media(message: dict[str, Any]) -> dict[str, Any]:
    for media_key in ("image", "video", "document", "audio", "sticker"):
        media = _record_from(message.get(media_key))
        if media:
            filename = _first_string(media, ("filename", "fileName", "file_name")) or _first_string(media, ("id",))
            return {
                key: value
                for key, value in {
                    "id": _first_string(media, ("id",)),
                    "filename": filename,
                    "mimeType": _first_string(media, ("mime_type", "mimeType")),
                    "sha256": _first_string(media, ("sha256",)),
                    "caption": _first_string(media, ("caption",)),
                    "type": media_key,
                }.items()
                if value
            }
    return {}


def _whatsapp_contact_by_wa_id(value: dict[str, Any]) -> dict[str, dict[str, Any]]:
    contacts = value.get("contacts")
    if not isinstance(contacts, list):
        return {}
    by_id: dict[str, dict[str, Any]] = {}
    for contact in contacts:
        if not isinstance(contact, dict):
            continue
        wa_id = _first_string(contact, ("wa_id", "waId", "id"))
        if wa_id:
            by_id[wa_id] = contact
    return by_id


def _whatsapp_message_events(value: dict[str, Any], *, business_account_id: str) -> list[dict[str, Any]]:
    messages = value.get("messages")
    if not isinstance(messages, list):
        return []
    metadata = _record_from(value.get("metadata"))
    phone_number_id = _first_string(metadata, ("phone_number_id", "phoneNumberId"))
    display_phone_number = _first_string(metadata, ("display_phone_number", "displayPhoneNumber"))
    contacts_by_id = _whatsapp_contact_by_wa_id(value)
    events: list[dict[str, Any]] = []
    for raw_message in messages:
        if not isinstance(raw_message, dict):
            continue
        message_id = _first_string(raw_message, ("id", "message_id", "messageId"))
        wa_id = _first_string(raw_message, ("from", "wa_id", "waId", "senderId", "sender_id"))
        contact = contacts_by_id.get(wa_id, {})
        profile = _record_from(contact.get("profile"))
        contact_name = _first_string(profile, ("name",)) or _first_string(contact, ("name", "displayName", "display_name")) or wa_id
        context = _record_from(raw_message.get("context"))
        body = _whatsapp_message_body(raw_message)
        message_record: dict[str, Any] = {
            "id": message_id,
            "messageId": message_id,
            "channelId": phone_number_id or display_phone_number or wa_id,
            "chatId": wa_id,
            "conversationId": wa_id,
            "threadId": wa_id,
            "replyToId": _first_string(context, ("id", "message_id", "messageId")),
            "text": body,
            "from": {"id": wa_id, "name": contact_name, "phone": wa_id},
            "senderId": wa_id,
            "senderName": contact_name,
            "timestamp": _first_string(raw_message, ("timestamp",)),
            "phoneNumberId": phone_number_id,
            "displayPhoneNumber": display_phone_number,
            "workspaceId": business_account_id or phone_number_id,
            "businessAccountId": business_account_id,
            "messageType": _first_string(raw_message, ("type",)),
        }
        media = _whatsapp_message_media(raw_message)
        if media:
            message_record["media"] = media
        events.append({
            "eventId": message_id or f"whatsapp:{wa_id}:{message_record['timestamp']}",
            "eventType": "message",
            "provider": "whatsapp",
            "message": {key: value for key, value in message_record.items() if value},
            "raw": raw_message,
        })
    return events


def _whatsapp_status_events(value: dict[str, Any], *, business_account_id: str) -> list[dict[str, Any]]:
    statuses = value.get("statuses")
    if not isinstance(statuses, list):
        return []
    metadata = _record_from(value.get("metadata"))
    phone_number_id = _first_string(metadata, ("phone_number_id", "phoneNumberId"))
    events: list[dict[str, Any]] = []
    for raw_status in statuses:
        if not isinstance(raw_status, dict):
            continue
        provider_message_id = _first_string(raw_status, ("id", "message_id", "messageId"))
        status = _first_string(raw_status, ("status", "eventType", "event_type")) or "delivery_event"
        recipient_id = _first_string(raw_status, ("recipient_id", "recipientId", "to"))
        events.append({
            "eventId": f"{provider_message_id}:{status}" if provider_message_id else _first_string(raw_status, ("timestamp",)) or status,
            "eventType": status,
            "provider": "whatsapp",
            "providerMessageId": provider_message_id,
            "channelId": phone_number_id,
            "chatId": recipient_id,
            "workspaceId": business_account_id or phone_number_id,
            "payload": raw_status,
            "error": _first_string(raw_status, ("error", "reason")),
        })
    return events


def _whatsapp_events_from_payload(payload: dict[str, Any]) -> list[dict[str, Any]]:
    if _event_token(_first_string(payload, ("object",))) != "whatsapp_business_account":
        return []
    entries = payload.get("entry")
    if not isinstance(entries, list):
        return []
    events: list[dict[str, Any]] = []
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        business_account_id = _first_string(entry, ("id", "businessAccountId", "business_account_id"))
        changes = entry.get("changes")
        if not isinstance(changes, list):
            continue
        for change in changes:
            if not isinstance(change, dict):
                continue
            value = _record_from(change.get("value"))
            if not value:
                continue
            events.extend(_whatsapp_message_events(value, business_account_id=business_account_id))
            events.extend(_whatsapp_status_events(value, business_account_id=business_account_id))
    return events


def _messenger_message_body(message: dict[str, Any], *, label: str = "Messenger") -> str:
    text = _first_string(message, ("text", "body"))
    if text:
        return text
    quick_reply = _record_from(message.get("quick_reply") or message.get("quickReply"))
    if quick_reply:
        return _first_string(quick_reply, ("payload", "text", "title")) or f"{label} quick reply"
    attachments = message.get("attachments")
    if isinstance(attachments, list) and attachments:
        first = _record_from(attachments[0])
        attachment_type = _first_string(first, ("type",)) or "attachment"
        return f"{label} {attachment_type}"
    return ""


def _messenger_message_attachments(message: dict[str, Any], *, provider: str = "messenger") -> list[dict[str, Any]]:
    raw_attachments = message.get("attachments")
    if not isinstance(raw_attachments, list):
        return []
    attachments: list[dict[str, Any]] = []
    for index, raw_attachment in enumerate(raw_attachments):
        if not isinstance(raw_attachment, dict):
            continue
        payload = _record_from(raw_attachment.get("payload"))
        attachment_type = _first_string(raw_attachment, ("type",)) or "file"
        url = _first_string(payload, ("url", "downloadUrl", "download_url"))
        attachment_id = (
            _first_string(raw_attachment, ("id", "attachmentId", "attachment_id"))
            or _first_string(payload, ("attachment_id", "attachmentId", "sticker_id", "stickerId"))
            or f"{provider}-attachment-{index}"
        )
        item: dict[str, Any] = {
            "id": attachment_id,
            "filename": _first_string(payload, ("filename", "fileName", "name")) or attachment_id,
            "provider": provider,
            "type": attachment_type,
        }
        if url:
            item["url"] = url
        attachments.append(item)
    return attachments


def _messenger_message_event(
    raw_event: dict[str, Any],
    *,
    page_id: str,
    provider: str = "messenger",
    label: str = "Messenger",
) -> dict[str, Any] | None:
    message = _record_from(raw_event.get("message"))
    postback = _record_from(raw_event.get("postback"))
    if not message and not postback:
        return None
    sender = _record_from(raw_event.get("sender"))
    recipient = _record_from(raw_event.get("recipient"))
    sender_id = _first_string(sender, ("id", "senderId", "sender_id"))
    recipient_id = _first_string(recipient, ("id", "recipientId", "recipient_id")) or page_id
    message_id = _first_string(message, ("mid", "id", "messageId", "message_id")) or _first_string(
        postback,
        ("mid", "id", "messageId", "message_id"),
    )
    body = _messenger_message_body(message, label=label)
    if postback and not body:
        body = _first_string(postback, ("title", "payload")) or f"{label} postback"
    attachments = _messenger_message_attachments(message, provider=provider)
    timestamp = _first_string(raw_event, ("timestamp", "time"))
    message_record: dict[str, Any] = {
        "id": message_id,
        "messageId": message_id,
        "providerMessageId": f"{provider}:{message_id}" if message_id else "",
        "channelId": recipient_id,
        "chatId": sender_id,
        "conversationId": sender_id,
        "threadId": sender_id,
        "text": body,
        "from": {"id": sender_id, "name": sender_id},
        "senderId": sender_id,
        "senderName": sender_id,
        "recipientId": recipient_id,
        "workspaceId": page_id or recipient_id,
        "timestamp": timestamp,
        "messageType": _first_string(message, ("type",)) or ("postback" if postback else ""),
        "attachments": attachments,
    }
    if provider == "instagram":
        message_record["instagramAccountId"] = recipient_id
    else:
        message_record["pageId"] = recipient_id
    if postback:
        message_record["postback"] = postback
    return {
        "eventId": message_id or f"{provider}:{sender_id}:{timestamp}",
        "eventType": "message",
        "provider": provider,
        "providerMessageId": f"{provider}:{message_id}" if message_id else "",
        "message": {key: value for key, value in message_record.items() if value not in ("", [], {})},
        "raw": raw_event,
    }


def _messenger_receipt_event(
    raw_event: dict[str, Any],
    *,
    page_id: str,
    provider: str = "messenger",
) -> dict[str, Any] | None:
    delivery = _record_from(raw_event.get("delivery"))
    read = _record_from(raw_event.get("read"))
    if not delivery and not read:
        return None
    sender = _record_from(raw_event.get("sender"))
    recipient = _record_from(raw_event.get("recipient"))
    sender_id = _first_string(sender, ("id", "senderId", "sender_id"))
    recipient_id = _first_string(recipient, ("id", "recipientId", "recipient_id")) or page_id
    mids = delivery.get("mids") if isinstance(delivery.get("mids"), list) else []
    provider_message_id = _string_from(mids[0]) if mids else ""
    watermark = _first_string(delivery or read, ("watermark", "timestamp"))
    event_type = "delivered" if delivery else "read"
    return {
        "eventId": f"{provider}:{provider_message_id}:{event_type}" if provider_message_id else f"{provider}:{sender_id}:{watermark}:{event_type}",
        "eventType": event_type,
        "provider": provider,
        "providerMessageId": f"{provider}:{provider_message_id}" if provider_message_id else "",
        "channelId": recipient_id,
        "chatId": sender_id,
        "workspaceId": page_id or recipient_id,
        "payload": raw_event,
        "raw": raw_event,
    }


def _messenger_events_from_payload(payload: dict[str, Any]) -> list[dict[str, Any]]:
    if _event_token(_first_string(payload, ("object",))) != "page":
        return []
    entries = payload.get("entry")
    if not isinstance(entries, list):
        return []
    events: list[dict[str, Any]] = []
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        page_id = _first_string(entry, ("id", "pageId", "page_id"))
        messaging_events = entry.get("messaging")
        if not isinstance(messaging_events, list):
            continue
        for raw_event in messaging_events:
            if not isinstance(raw_event, dict):
                continue
            message_event = _messenger_message_event(raw_event, page_id=page_id)
            if message_event:
                events.append(message_event)
                continue
            receipt_event = _messenger_receipt_event(raw_event, page_id=page_id)
            if receipt_event:
                events.append(receipt_event)
    return events


def _instagram_events_from_payload(payload: dict[str, Any]) -> list[dict[str, Any]]:
    if _event_token(_first_string(payload, ("object",))) not in {"instagram", "instagram_business_account"}:
        return []
    entries = payload.get("entry")
    if not isinstance(entries, list):
        return []
    events: list[dict[str, Any]] = []
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        account_id = _first_string(entry, ("id", "instagramAccountId", "instagram_account_id"))
        messaging_events = entry.get("messaging")
        if not isinstance(messaging_events, list):
            continue
        for raw_event in messaging_events:
            if not isinstance(raw_event, dict):
                continue
            message_event = _messenger_message_event(
                raw_event,
                page_id=account_id,
                provider="instagram",
                label="Instagram",
            )
            if message_event:
                events.append(message_event)
                continue
            receipt_event = _messenger_receipt_event(raw_event, page_id=account_id, provider="instagram")
            if receipt_event:
                events.append(receipt_event)
    return events


def _line_message_body(message: dict[str, Any]) -> str:
    message_type = _event_token(_first_string(message, ("type", "messageType", "message_type")))
    text = _first_string(message, ("text", "body"))
    if message_type == "text" or text:
        return text
    if message_type == "sticker":
        return _first_string(message, ("stickerId", "sticker_id", "packageId", "package_id")) or "LINE sticker"
    if message_type == "location":
        return _first_string(message, ("title", "address")) or "LINE location shared"
    if message_type == "file":
        return _first_string(message, ("fileName", "file_name", "filename", "id")) or "LINE file"
    if message_type in {"image", "video", "audio"}:
        return f"LINE {message_type}"
    return _first_string(message, ("caption", "description"))


def _line_message_attachments(message: dict[str, Any], raw_event: dict[str, Any]) -> list[dict[str, Any]]:
    attachments: list[dict[str, Any]] = []
    raw_attachments = raw_event.get("attachments")
    if isinstance(raw_attachments, list):
        for index, raw_attachment in enumerate(raw_attachments):
            if not isinstance(raw_attachment, dict):
                continue
            attachment_id = _first_string(raw_attachment, ("id", "attachmentId", "attachment_id")) or f"line-attachment-{index}"
            item: dict[str, Any] = {
                "id": attachment_id,
                "filename": _first_string(raw_attachment, ("filename", "fileName", "file_name", "name")) or attachment_id,
                "provider": "line",
                "type": _first_string(raw_attachment, ("type", "contentType", "content_type")) or "file",
            }
            url = _first_string(raw_attachment, ("url", "downloadUrl", "download_url"))
            if url:
                item["url"] = url
            content_type = _first_string(raw_attachment, ("contentType", "content_type", "mimeType", "mime_type"))
            if content_type:
                item["contentType"] = content_type
            attachments.append(item)

    message_type = _event_token(_first_string(message, ("type", "messageType", "message_type")))
    if message_type in {"image", "video", "audio", "file"}:
        message_id = _first_string(message, ("id", "messageId", "message_id"))
        if message_id and not any(_first_string(item, ("id",)) == message_id for item in attachments):
            item = {
                "id": message_id,
                "filename": _first_string(message, ("fileName", "file_name", "filename")) or message_id,
                "provider": "line",
                "type": message_type,
            }
            file_size = _first_string(message, ("fileSize", "file_size"))
            if file_size:
                item["fileSize"] = file_size
            attachments.append(item)
    return attachments


def _line_message_event(raw_event: dict[str, Any], *, payload: dict[str, Any]) -> dict[str, Any] | None:
    if _event_token(_first_string(raw_event, ("type", "eventType", "event_type"))) != "message":
        return None
    message = _record_from(raw_event.get("message"))
    if not message:
        return None
    body = _line_message_body(message)
    attachments = _line_message_attachments(message, raw_event)
    if not body and not attachments:
        return None
    source = _record_from(raw_event.get("source"))
    source_type = _first_string(source, ("type",))
    user_id = _first_string(source, ("userId", "user_id"))
    group_id = _first_string(source, ("groupId", "group_id"))
    room_id = _first_string(source, ("roomId", "room_id"))
    conversation_id = group_id or room_id or user_id
    destination = _first_string(payload, ("destination", "botUserId", "bot_user_id"))
    message_id = _first_string(message, ("id", "messageId", "message_id"))
    timestamp = _first_string(raw_event, ("timestamp",))
    webhook_event_id = _first_string(raw_event, ("webhookEventId", "webhook_event_id", "eventId", "event_id"))
    sender_id = user_id or conversation_id
    message_record: dict[str, Any] = {
        "id": message_id,
        "messageId": message_id,
        "providerMessageId": f"line:{message_id}" if message_id else "",
        "channelId": destination or conversation_id,
        "chatId": conversation_id,
        "conversationId": conversation_id,
        "threadId": conversation_id,
        "text": body,
        "from": {"id": sender_id, "name": sender_id},
        "senderId": sender_id,
        "senderName": sender_id,
        "destination": destination,
        "workspaceId": destination or conversation_id,
        "timestamp": timestamp,
        "messageType": _first_string(message, ("type",)),
        "replyToken": _first_string(raw_event, ("replyToken", "reply_token")),
        "lineSourceType": source_type,
        "lineUserId": user_id,
        "lineGroupId": group_id,
        "lineRoomId": room_id,
        "attachments": attachments,
    }
    return {
        "eventId": webhook_event_id or message_id or f"line:{sender_id}:{timestamp}",
        "eventType": "message",
        "provider": "line",
        "providerMessageId": f"line:{message_id}" if message_id else "",
        "message": {key: value for key, value in message_record.items() if value not in ("", [], {})},
        "raw": raw_event,
    }


def _line_events_from_payload(payload: dict[str, Any]) -> list[dict[str, Any]]:
    raw_events = payload.get("events")
    if not isinstance(raw_events, list):
        return []
    events: list[dict[str, Any]] = []
    for raw_event in raw_events:
        if not isinstance(raw_event, dict):
            continue
        message_event = _line_message_event(raw_event, payload=payload)
        if message_event:
            events.append(message_event)
    return events


def _viber_provider_message_id(message_token: str) -> str:
    clean_token = _string_from(message_token)
    if not clean_token:
        return ""
    return clean_token if clean_token.startswith("viber:") else f"viber:{clean_token}"


def _viber_message_body(message: dict[str, Any]) -> str:
    message_type = _event_token(_first_string(message, ("type", "messageType", "message_type")))
    text = _first_string(message, ("text", "body"))
    if message_type == "text" or text:
        return text
    if message_type in {"picture", "video", "file"}:
        return _first_string(message, ("file_name", "fileName", "filename", "media")) or f"Viber {message_type}"
    if message_type == "url":
        return _first_string(message, ("media", "text")) or "Viber URL"
    if message_type == "location":
        location = _record_from(message.get("location"))
        return _first_string(location, ("address", "lat", "lon")) or "Viber location shared"
    if message_type == "contact":
        contact = _record_from(message.get("contact"))
        return _first_string(contact, ("name", "phone_number", "phoneNumber")) or "Viber contact shared"
    if message_type == "sticker":
        return _first_string(message, ("sticker_id", "stickerId")) or "Viber sticker"
    return _first_string(message, ("caption", "description", "media"))


def _viber_message_attachments(message: dict[str, Any]) -> list[dict[str, Any]]:
    message_type = _event_token(_first_string(message, ("type", "messageType", "message_type")))
    media_url = _first_string(message, ("media", "url", "downloadUrl", "download_url"))
    if message_type not in {"picture", "video", "file", "url"} and not media_url:
        return []
    attachment_id = _first_string(message, ("id", "messageId", "message_id", "media")) or f"viber-{message_type or 'attachment'}"
    item: dict[str, Any] = {
        "id": attachment_id,
        "filename": _first_string(message, ("file_name", "fileName", "filename", "name")) or attachment_id,
        "provider": "viber",
        "type": message_type or "file",
    }
    if media_url:
        item["url"] = media_url
    file_size = _first_string(message, ("size", "file_size", "fileSize"))
    if file_size:
        item["fileSize"] = file_size
    content_type = _first_string(message, ("mime_type", "mimeType", "contentType", "content_type"))
    if content_type:
        item["contentType"] = content_type
    return [item]


def _viber_message_event(payload: dict[str, Any]) -> dict[str, Any] | None:
    if _event_token(_first_string(payload, ("event", "eventType", "event_type"))) != "message":
        return None
    message = _record_from(payload.get("message"))
    sender = _record_from(payload.get("sender"))
    if not message or not sender:
        return None
    body = _viber_message_body(message)
    attachments = _viber_message_attachments(message)
    if not body and not attachments:
        return None
    message_token = _first_string(payload, ("message_token", "messageToken", "message_id", "messageId"))
    sender_id = _first_string(sender, ("id", "senderId", "sender_id"))
    sender_name = _first_string(sender, ("name", "displayName", "display_name")) or sender_id
    channel_id = _first_string(payload, ("chat_hostname", "chatHostname", "receiver", "to")) or sender_id
    timestamp = _first_string(payload, ("timestamp",))
    provider_message_id = _viber_provider_message_id(message_token)
    message_record: dict[str, Any] = {
        "id": message_token,
        "messageId": message_token,
        "providerMessageId": provider_message_id,
        "channelId": channel_id,
        "chatId": sender_id,
        "conversationId": sender_id,
        "threadId": sender_id,
        "text": body,
        "from": {
            "id": sender_id,
            "name": sender_name,
            "avatar": _first_string(sender, ("avatar",)),
            "country": _first_string(sender, ("country",)),
            "language": _first_string(sender, ("language",)),
        },
        "senderId": sender_id,
        "senderName": sender_name,
        "workspaceId": channel_id,
        "timestamp": timestamp,
        "messageType": _first_string(message, ("type",)),
        "trackingData": _first_string(message, ("tracking_data", "trackingData")),
        "viberUserId": sender_id,
        "attachments": attachments,
    }
    return {
        "eventId": message_token or f"viber:{sender_id}:{timestamp}",
        "eventType": "message",
        "provider": "viber",
        "providerMessageId": provider_message_id,
        "message": {key: value for key, value in message_record.items() if value not in ("", [], {})},
        "raw": payload,
    }


def _viber_receipt_event(payload: dict[str, Any]) -> dict[str, Any] | None:
    event_type = _event_token(_first_string(payload, ("event", "eventType", "event_type")))
    if event_type not in {"delivered", "seen", "failed", "subscribed", "unsubscribed", "conversation_started"}:
        return None
    message_token = _first_string(payload, ("message_token", "messageToken", "message_id", "messageId"))
    user_id = _first_string(payload, ("user_id", "userId", "chat_id", "chatId"))
    user = _record_from(payload.get("user") or payload.get("sender"))
    if not user_id:
        user_id = _first_string(user, ("id", "senderId", "sender_id"))
    timestamp = _first_string(payload, ("timestamp",))
    provider_message_id = _viber_provider_message_id(message_token)
    return {
        "eventId": f"{provider_message_id}:{event_type}" if provider_message_id else f"viber:{user_id}:{timestamp}:{event_type}",
        "eventType": event_type,
        "provider": "viber",
        "providerMessageId": provider_message_id,
        "channelId": _first_string(payload, ("chat_hostname", "chatHostname", "receiver")),
        "chatId": user_id,
        "workspaceId": _first_string(payload, ("chat_hostname", "chatHostname", "receiver")),
        "payload": payload,
        "raw": payload,
        "error": _first_string(payload, ("desc", "description", "error", "status_message", "statusMessage")),
    }


def _viber_events_from_payload(payload: dict[str, Any]) -> list[dict[str, Any]]:
    provider = _event_token(_first_string(payload, ("provider",)))
    if "event" not in payload and provider != "viber":
        return []
    event_type = _event_token(_first_string(payload, ("event", "eventType", "event_type")))
    if not event_type:
        return []
    message_event = _viber_message_event(payload)
    if message_event:
        return [message_event]
    receipt_event = _viber_receipt_event(payload)
    return [receipt_event] if receipt_event else []


def _twitter_user(payload: dict[str, Any], user_id: str) -> dict[str, Any]:
    users = payload.get("users")
    if isinstance(users, dict):
        user = users.get(user_id)
        if isinstance(user, dict):
            return user
    includes = payload.get("includes")
    if isinstance(includes, dict) and isinstance(includes.get("users"), list):
        for user in includes["users"]:
            if isinstance(user, dict) and _first_string(user, ("id",)) == user_id:
                return user
    return {}


def _twitter_message_attachments(message_data: dict[str, Any]) -> list[dict[str, Any]]:
    attachment = _record_from(message_data.get("attachment"))
    if not attachment:
        return []
    media = _record_from(attachment.get("media"))
    attachment_id = _first_string(media, ("id", "media_key", "mediaKey")) or _first_string(attachment, ("id", "type"))
    item: dict[str, Any] = {
        "id": attachment_id or "twitter-attachment",
        "filename": attachment_id or "twitter-attachment",
        "provider": "twitter",
        "type": _first_string(attachment, ("type",)) or _first_string(media, ("type",)) or "media",
    }
    url = _first_string(media, ("media_url_https", "media_url", "url", "preview_image_url"))
    if url:
        item["url"] = url
    content_type = _first_string(media, ("mime_type", "mimeType", "contentType", "content_type"))
    if content_type:
        item["contentType"] = content_type
    return [item]


def _twitter_message_event(raw_event: dict[str, Any], *, payload: dict[str, Any]) -> dict[str, Any] | None:
    if _event_token(_first_string(raw_event, ("type",))) != "message_create":
        return None
    message_create = _record_from(raw_event.get("message_create") or raw_event.get("messageCreate"))
    message_data = _record_from(message_create.get("message_data") or message_create.get("messageData"))
    body = _first_string(message_data, ("text", "body"))
    attachments = _twitter_message_attachments(message_data)
    if not body and not attachments:
        return None
    target = _record_from(message_create.get("target"))
    message_id = _first_string(raw_event, ("id", "message_id", "messageId"))
    sender_id = _first_string(message_create, ("sender_id", "senderId"))
    recipient_id = _first_string(target, ("recipient_id", "recipientId"))
    subscribed_user_id = _first_string(payload, ("for_user_id", "forUserId")) or recipient_id
    sender = _twitter_user(payload, sender_id)
    sender_name = _first_string(sender, ("name", "screen_name", "username")) or sender_id
    sender_username = _first_string(sender, ("screen_name", "username"))
    timestamp = _first_string(raw_event, ("created_timestamp", "createdTimestamp", "timestamp_ms", "timestamp"))
    message_record: dict[str, Any] = {
        "id": message_id,
        "messageId": message_id,
        "providerMessageId": f"twitter:{message_id}" if message_id else "",
        "channelId": subscribed_user_id or recipient_id,
        "chatId": sender_id,
        "conversationId": sender_id,
        "threadId": sender_id,
        "text": body,
        "from": {"id": sender_id, "name": sender_name, "username": sender_username},
        "senderId": sender_id,
        "senderName": sender_name,
        "recipientId": recipient_id,
        "workspaceId": subscribed_user_id or recipient_id,
        "timestamp": timestamp,
        "messageType": "direct_message",
        "attachments": attachments,
    }
    return {
        "eventId": message_id or f"twitter:{sender_id}:{timestamp}",
        "eventType": "message",
        "provider": "twitter",
        "providerMessageId": f"twitter:{message_id}" if message_id else "",
        "message": {key: value for key, value in message_record.items() if value not in ("", [], {})},
        "raw": raw_event,
    }


def _twitter_events_from_payload(payload: dict[str, Any]) -> list[dict[str, Any]]:
    raw_events = payload.get("direct_message_events")
    if not isinstance(raw_events, list):
        return []
    events: list[dict[str, Any]] = []
    for raw_event in raw_events:
        if not isinstance(raw_event, dict):
            continue
        message_event = _twitter_message_event(raw_event, payload=payload)
        if message_event:
            events.append(message_event)
    return events


def _channel_event_type(event: dict[str, Any]) -> str:
    explicit = _first_string(
        event,
        ("eventType", "event_type", "type", "event", "t", "status", "deliveryStatus", "delivery_status"),
    )
    if explicit:
        return explicit
    if any(isinstance(event.get(key), dict) and _generic_message_body(event[key]) for key in ("message", "activity", "data", "d")):
        return "message"
    return "delivery_event"


def _channel_provider(event: dict[str, Any], channel: dict[str, Any]) -> str:
    config = channel.get("config") if isinstance(channel.get("config"), dict) else {}
    return (
        _first_string(event, ("provider", "source", "adapter"))
        or _string_from(channel.get("type"))
        or _string_from(config.get("adapter"))
        or "channel"
    )


def _channel_provider_message_id(event: dict[str, Any]) -> str:
    provider_message_id = _first_string(
        event,
        (
            "providerMessageId",
            "provider_message_id",
            "messageId",
            "message_id",
            "smtpMessageId",
            "smtp_message_id",
            "emailId",
            "email_id",
            "sg_message_id",
            "mailgunMessageId",
            "mailgun_message_id",
        ),
    )
    if provider_message_id:
        return provider_message_id
    record = _generic_message_record(event)
    if record is event:
        return ""
    return _first_string(
        record,
        (
            "providerMessageId",
            "provider_message_id",
            "messageId",
            "message_id",
            "id",
            "mid",
            "ts",
            "timestamp",
            "updateId",
            "update_id",
        ),
    )


def _channel_receipt_records(event: dict[str, Any]) -> list[dict[str, Any]]:
    records = [event]
    for key in ("message", "activity", "event", "data", "d", "result", "payload", "status"):
        nested = _record_from(event.get(key))
        if nested:
            records.append(nested)
    return records


def _add_unique_string(items: list[str], value: Any) -> None:
    clean = _string_from(value)
    if clean and clean not in items:
        items.append(clean)


def _provider_message_id_parts(provider_message_id: str) -> list[str]:
    parts: list[str] = []
    for part in _string_from(provider_message_id).split(";"):
        _add_unique_string(parts, part)
    return parts


def _first_from_records(records: list[dict[str, Any]], keys: tuple[str, ...]) -> str:
    for record in records:
        value = _first_string(record, keys)
        if value:
            return value
    return ""


def _nested_first_from_records(records: list[dict[str, Any]], nested_keys: tuple[str, ...], keys: tuple[str, ...]) -> str:
    for record in records:
        value = _nested_first_string(record, nested_keys, keys)
        if value:
            return value
    return ""


def _channel_provider_message_id_candidates(
    event: dict[str, Any],
    *,
    provider: str = "",
    provider_message_id: str = "",
) -> list[str]:
    records = _channel_receipt_records(event)
    raw_provider_message_id = provider_message_id or _channel_provider_message_id(event)
    raw_parts = _provider_message_id_parts(raw_provider_message_id)
    candidates: list[str] = []
    provider_key = _event_token(provider or _channel_provider(event, {"type": "channel"}))

    for part in raw_parts:
        if ":" in part:
            _add_unique_string(candidates, part)

    if "slack" in provider_key:
        channel_id = (
            _first_from_records(records, ("channel", "channelId", "channel_id"))
            or _nested_first_from_records(records, ("channel", "conversation", "room"), ("id", "channelId", "channel_id"))
        )
        message_ts = (
            _first_from_records(records, ("ts", "messageTs", "message_ts", "eventTs", "event_ts", "timestamp"))
            or next((part for part in raw_parts if "." in part and ":" not in part), "")
        )
        if channel_id and message_ts:
            _add_unique_string(candidates, f"slack:{channel_id}:{message_ts}")

    if "discord" in provider_key:
        discord_message_id = _first_from_records(records, ("messageId", "message_id", "id"))
        for part in [discord_message_id, *raw_parts]:
            if part and not part.startswith("discord:"):
                _add_unique_string(candidates, f"discord:{part}")

    if "telegram" in provider_key:
        telegram_message_id = _first_from_records(records, ("messageId", "message_id", "id"))
        if not telegram_message_id and raw_parts:
            telegram_message_id = raw_parts[0]
        chat_id = (
            _first_from_records(records, ("chatId", "chat_id", "channelId", "channel_id"))
            or _nested_first_from_records(records, ("chat", "channel", "conversation"), ("id", "chatId", "chat_id"))
        )
        if chat_id and telegram_message_id and not telegram_message_id.startswith("telegram:"):
            _add_unique_string(candidates, f"telegram:{chat_id}:{telegram_message_id}")

    if "teams" in provider_key:
        teams_message_id = _first_from_records(
            records,
            ("providerMessageId", "provider_message_id", "messageId", "message_id", "activityId", "activity_id", "replyToId", "reply_to_id", "id"),
        )
        conversation_id = (
            _first_from_records(records, ("conversationId", "conversation_id", "threadId", "thread_id"))
            or _nested_first_from_records(records, ("conversation", "channel"), ("id", "conversationId", "conversation_id"))
        )
        if teams_message_id:
            _add_unique_string(candidates, teams_message_id)
            if not teams_message_id.startswith("teams:"):
                _add_unique_string(candidates, f"teams:{teams_message_id}")
        if conversation_id:
            _add_unique_string(candidates, f"teams:reply:{conversation_id}")
            if teams_message_id and not teams_message_id.startswith("teams:"):
                _add_unique_string(candidates, f"teams:{conversation_id}:{teams_message_id}")

    for part in raw_parts:
        _add_unique_string(candidates, part)
    return candidates


def _channel_receipt_provider_message_id(event: dict[str, Any], *, provider: str, fallback: str = "") -> str:
    candidates = _channel_provider_message_id_candidates(event, provider=provider, provider_message_id=fallback)
    return candidates[0] if candidates else fallback


def _outbound_provider_message_id_matches(stored: Any, candidates: list[str]) -> bool:
    candidate_set = set(candidates)
    if not candidate_set:
        return False
    return any(part in candidate_set for part in _provider_message_id_parts(_string_from(stored)))


def _recent_outbound_messages_for_receipt(
    *,
    tenant_id: str | None,
    project_id: str,
) -> list[dict[str, Any]]:
    data = _get(
        "/api/collections/support_outbound_messages/records",
        {
            "filter": _issue_filter(tenant_id=tenant_id, project_id=project_id),
            "sort": "-updated",
            "perPage": 200,
        },
    )
    items = data.get("items")
    return items if isinstance(items, list) else []


def _channel_event_id(event: dict[str, Any], event_type: str, provider_message_id: str, index: int) -> str:
    explicit = _first_string(event, ("eventId", "event_id", "webhookId", "webhook_id", "id"))
    if explicit:
        return explicit
    record = _generic_message_record(event)
    if record is not event:
        nested_explicit = _first_string(
            record,
            (
                "eventId",
                "event_id",
                "webhookId",
                "webhook_id",
                "messageId",
                "message_id",
                "id",
                "mid",
                "ts",
                "timestamp",
                "updateId",
                "update_id",
            ),
        )
        if nested_explicit:
            return nested_explicit
    return f"{event_type}:{provider_message_id or index}"


def _receipt_outbound_status(event_type: str) -> tuple[str, str, str]:
    clean = event_type.lower()
    failure_tokens = ("bounce", "bounced", "failed", "failure", "dropped", "reject", "rejected", "complaint", "spam")
    if any(token in clean for token in failure_tokens):
        return "failed", "reply_delivery_failed", "Reply delivery failed"
    success_tokens = ("delivered", "delivery", "sent", "processed", "accepted", "open", "opened", "click", "clicked")
    if any(token in clean for token in success_tokens):
        return "sent", "reply_delivery_event", "Reply delivery event"
    return "", "reply_delivery_event", "Reply delivery event"


def _receipt_error(event: dict[str, Any]) -> str:
    return _first_string(event, ("error", "reason", "message", "description", "failureReason", "failure_reason"))


def _find_outbound_for_receipt(
    *,
    tenant_id: str | None,
    project_id: str,
    provider_message_id: str,
    event: dict[str, Any],
    provider: str = "",
) -> dict[str, Any] | None:
    explicit_id = _first_string(event, ("outboundMessageId", "outbound_message_id", "replyId", "reply_id"))
    if explicit_id:
        rec = _first(
            "support_outbound_messages",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"id='{_escape_pb(explicit_id)}'",
            ),
        )
        if rec:
            return rec
    candidates = _channel_provider_message_id_candidates(
        event,
        provider=provider,
        provider_message_id=provider_message_id,
    )
    if not candidates:
        return None
    for candidate in candidates:
        rec = _first(
            "support_outbound_messages",
            _issue_filter(
                tenant_id=tenant_id,
                project_id=project_id,
                extra=f"provider_message_id='{_escape_pb(candidate)}'",
            ),
        )
        if rec:
            return rec
    scoped_records = _recent_outbound_messages_for_receipt(tenant_id=tenant_id, project_id=project_id)
    for rec in scoped_records:
        if _outbound_provider_message_id_matches(rec.get("provider_message_id"), candidates):
            return rec
    return None


def _apply_channel_delivery_receipt(
    *,
    tenant_id: str | None,
    project_id: str,
    outbound: dict[str, Any],
    event: dict[str, Any],
    event_type: str,
    provider: str,
    provider_message_id: str,
) -> dict[str, Any]:
    outbound_status, issue_event_type, issue_title = _receipt_outbound_status(event_type)
    metadata = _parse(outbound.get("metadata"), dict)
    receipt = {
        "eventType": event_type,
        "provider": provider,
        "providerMessageId": provider_message_id,
        "receivedAt": _now_iso(),
        "payload": event,
    }
    metadata["deliveryReceipt"] = receipt
    data: dict[str, Any] = {
        "metadata": metadata,
        "provider": provider or _string_from(outbound.get("provider")),
        "provider_message_id": provider_message_id or _string_from(outbound.get("provider_message_id")),
    }
    if outbound_status:
        data["status"] = outbound_status
    if outbound_status == "sent" and not outbound.get("sent_at"):
        data["sent_at"] = _now_iso()
    error = _receipt_error(event)
    if outbound_status == "failed":
        data["error"] = error or "Delivery receipt marked reply failed"
    _patch(f"/api/collections/support_outbound_messages/records/{outbound['id']}", data)
    updated = {**outbound, **data}
    issue_id = _string_from(outbound.get("issue"))
    if issue_id:
        _record_issue_event(
            issue_id=issue_id,
            event_type=issue_event_type,
            tenant_id=tenant_id,
            project_id=project_id,
            actor_email=_string_from(outbound.get("created_by")) or "channel-webhook",
            title=issue_title,
            body=error,
            metadata={
                "replyId": _string_from(outbound.get("id")),
                "provider": provider,
                "providerMessageId": provider_message_id,
                "eventType": event_type,
            },
        )
        if outbound_status == "failed":
            _notify_reply_delivery_failed(
                issue_id=issue_id,
                reply=updated,
                error=error,
                tenant_id=tenant_id,
                project_id=project_id,
            )
        elif outbound_status == "sent":
            _append_outbound_timeline_message(
                outbound=updated,
                tenant_id=tenant_id,
                project_id=project_id,
            )
            _mark_issue_sla_met(
                issue_id=issue_id,
                event_type="first_response_due",
                tenant_id=tenant_id,
                project_id=project_id,
            )
    return _normalize_outbound_message(updated)


GENERIC_INBOUND_EVENT_TYPES = {
    "message",
    "message_create",
    "message_created",
    "message_received",
    "new_message",
    "incoming_message",
    "inbound_message",
    "app_mention",
    "telegram_message",
    "discord_message",
}

GENERIC_INBOUND_DIRECTIONS = {"incoming", "inbound", "customer", "user", "visitor"}


def _event_token(value: str) -> str:
    clean = []
    for char in (value or "").strip().lower():
        clean.append(char if char.isalnum() else "_")
    return "_".join(part for part in "".join(clean).split("_") if part)


def _generic_message_body(data: dict[str, Any]) -> str:
    body = _first_string(data, ("body", "text", "content", "messageText", "message_text", "caption", "description"))
    if body:
        return body
    message = data.get("message")
    return _string_from(message) if not isinstance(message, dict) else ""


def _generic_message_record(event: dict[str, Any]) -> dict[str, Any]:
    for key in ("message", "activity", "event", "data", "d"):
        nested = event.get(key)
        if isinstance(nested, dict) and _generic_message_body(nested):
            return nested
    return event


def _nested_first_string(data: dict[str, Any], nested_keys: tuple[str, ...], keys: tuple[str, ...]) -> str:
    direct = _first_string(data, keys)
    if direct:
        return direct
    for nested_key in nested_keys:
        nested = _record_from(data.get(nested_key))
        value = _first_string(nested, keys)
        if value:
            return value
    return ""


def _generic_event_is_inbound_message(event: dict[str, Any]) -> bool:
    record = _generic_message_record(event)
    body = _generic_message_body(record)
    attachments = _channel_message_attachments(
        event=event,
        record=record,
        provider=_channel_provider(event, {}),
    )
    if not body and not attachments:
        return False
    direction = _event_token(
        _first_string(event, ("direction", "messageDirection", "message_direction"))
        or _first_string(record, ("direction", "messageDirection", "message_direction"))
    )
    if direction in GENERIC_INBOUND_DIRECTIONS:
        return True
    raw_event_type = _first_string(
        event,
        ("eventType", "event_type", "type", "event", "t", "status", "deliveryStatus", "delivery_status"),
    )
    if record is not event and not raw_event_type:
        return True
    event_type = _event_token(raw_event_type)
    if event_type in GENERIC_INBOUND_EVENT_TYPES:
        return True
    receipt_status, _event, _title = _receipt_outbound_status(event_type)
    if receipt_status:
        return False
    if record is not event:
        return True
    return bool(
        _first_string(record, ("messageId", "message_id", "id", "mid", "ts", "timestamp", "updateId", "update_id"))
        or _nested_first_string(record, ("author", "sender", "from", "user", "contact", "customer"), ("id", "userId", "user_id", "email"))
    )


def _generic_channel_identity(event: dict[str, Any], record: dict[str, Any], channel: dict[str, Any]) -> tuple[str, str, str]:
    channel_id = (
        _first_string(record, ("channelId", "channel_id", "chatId", "chat_id", "roomId", "room_id", "conversationId", "conversation_id"))
        or _first_string(event, ("channelId", "channel_id", "chatId", "chat_id", "roomId", "room_id", "conversationId", "conversation_id"))
        or _nested_first_string(record, ("channel", "chat", "conversation", "room"), ("id", "channelId", "channel_id", "chatId", "chat_id"))
        or _nested_first_string(event, ("channel", "chat", "conversation", "room"), ("id", "channelId", "channel_id", "chatId", "chat_id"))
        or _string_from(channel.get("channelKey"))
    )
    workspace_id = (
        _first_string(record, ("guildId", "guild_id", "serverId", "server_id", "workspaceId", "workspace_id", "teamId", "team_id"))
        or _first_string(event, ("guildId", "guild_id", "serverId", "server_id", "workspaceId", "workspace_id", "teamId", "team_id"))
        or _nested_first_string(record, ("guild", "server", "workspace", "team", "chat"), ("id", "guildId", "guild_id", "serverId", "server_id", "teamId", "team_id"))
        or _nested_first_string(event, ("guild", "server", "workspace", "team", "chat"), ("id", "guildId", "guild_id", "serverId", "server_id", "teamId", "team_id"))
        or channel_id
    )
    channel_title = (
        _nested_first_string(record, ("channel", "chat", "conversation", "room"), ("title", "name", "username"))
        or _nested_first_string(event, ("channel", "chat", "conversation", "room"), ("title", "name", "username"))
    )
    return channel_id, workspace_id, channel_title


def _generic_message_ids(event: dict[str, Any], record: dict[str, Any], channel: dict[str, Any], provider: str) -> tuple[str, str, str, str, str]:
    channel_id, workspace_id, _channel_title = _generic_channel_identity(event, record, channel)
    message_id = (
        _first_string(record, ("messageId", "message_id", "id", "mid", "ts", "timestamp", "updateId", "update_id"))
        or _first_string(event, ("messageId", "message_id", "eventId", "event_id", "id", "updateId", "update_id"))
    )
    thread_id = (
        _first_string(record, ("threadId", "thread_id", "threadTs", "thread_ts", "conversationId", "conversation_id", "ticketId", "ticket_id", "parentId", "parent_id"))
        or _first_string(event, ("threadId", "thread_id", "threadTs", "thread_ts", "conversationId", "conversation_id", "ticketId", "ticket_id", "parentId", "parent_id"))
        or message_id
    )
    if not message_id:
        message_id = _channel_event_id(event, _channel_event_type(event), _channel_provider_message_id(event), 0)
    provider_key = _event_token(provider) or "channel"
    source_issue_key = _ticket_source_key(channel=channel, thread_id=thread_id, message_id=message_id)
    source_issue_id = f"{provider_key}:{_string_from(channel.get('channelKey'))}:{channel_id}:{source_issue_key}"
    source_message_id = f"{source_issue_id}:{message_id}"
    return source_issue_id, source_message_id, channel_id, workspace_id, thread_id


def _generic_message_target_metadata(
    event: dict[str, Any],
    record: dict[str, Any],
    *,
    channel_id: str,
    provider_message_id: str,
    provider_key: str,
) -> dict[str, str]:
    metadata: dict[str, str] = {"channelId": channel_id}
    if provider_message_id:
        metadata["providerMessageId"] = provider_message_id
        metadata["messageId"] = provider_message_id
    thread_id = (
        _first_string(record, ("threadId", "thread_id", "ticketId", "ticket_id", "parentId", "parent_id"))
        or _first_string(event, ("threadId", "thread_id", "ticketId", "ticket_id", "parentId", "parent_id"))
    )
    thread_ts = (
        _first_string(record, ("threadTs", "thread_ts"))
        or _first_string(event, ("threadTs", "thread_ts"))
    )
    conversation_id = (
        _first_string(record, ("conversationId", "conversation_id"))
        or _first_string(event, ("conversationId", "conversation_id"))
        or _nested_first_string(record, ("conversation",), ("id", "conversationId", "conversation_id"))
        or _nested_first_string(event, ("conversation",), ("id", "conversationId", "conversation_id"))
    )
    chat_id = (
        _first_string(record, ("chatId", "chat_id"))
        or _first_string(event, ("chatId", "chat_id"))
        or _nested_first_string(record, ("chat",), ("id", "chatId", "chat_id"))
        or _nested_first_string(event, ("chat",), ("id", "chatId", "chat_id"))
    )
    reply_to_id = (
        _first_string(record, ("replyToId", "reply_to_id"))
        or _first_string(event, ("replyToId", "reply_to_id"))
    )
    service_url = (
        _first_string(record, ("serviceUrl", "service_url"))
        or _first_string(event, ("serviceUrl", "service_url"))
    )
    instagram_account_id = (
        _first_string(record, ("instagramAccountId", "instagram_account_id"))
        or _first_string(event, ("instagramAccountId", "instagram_account_id"))
    )
    viber_user_id = (
        _first_string(record, ("viberUserId", "viber_user_id"))
        or _first_string(event, ("viberUserId", "viber_user_id"))
    )
    if thread_id:
        metadata["threadId"] = thread_id
    if thread_ts:
        metadata["threadTs"] = thread_ts
    if conversation_id:
        metadata["conversationId"] = conversation_id
    if chat_id:
        metadata["chatId"] = chat_id
    if reply_to_id or (provider_key == "teams" and provider_message_id):
        metadata["replyToId"] = reply_to_id or provider_message_id
    if service_url:
        metadata["serviceUrl"] = service_url
    if instagram_account_id:
        metadata["instagramAccountId"] = instagram_account_id
    if viber_user_id:
        metadata["viberUserId"] = viber_user_id
    return metadata


def _generic_sender_identity(
    *,
    event: dict[str, Any],
    record: dict[str, Any],
    provider: str,
    channel: dict[str, Any],
    channel_id: str,
    workspace_id: str,
) -> tuple[dict[str, str], dict[str, Any]]:
    sender = {}
    for key in ("author", "sender", "from", "user", "contact", "customer"):
        sender = _record_from(record.get(key)) or _record_from(event.get(key))
        if sender:
            break
    first_name = _first_string(sender, ("firstName", "first_name"))
    last_name = _first_string(sender, ("lastName", "last_name"))
    sender_name = (
        _first_string(sender, ("name", "displayName", "display_name", "username", "globalName", "global_name"))
        or " ".join(part for part in (first_name, last_name) if part)
        or _first_string(record, ("senderName", "sender_name", "userName", "user_name", "username"))
        or f"{provider.title()} user"
    )
    sender_id = (
        _first_string(sender, ("id", "userId", "user_id", "fromId", "from_id", "username", "email"))
        or _first_string(record, ("senderId", "sender_id", "userId", "user_id", "fromId", "from_id"))
        or channel_id
    )
    sender_email = (
        _first_string(sender, ("email", "emailAddress", "email_address"))
        or _first_string(record, ("senderEmail", "sender_email", "fromAddress", "from_address", "email"))
    )
    contact_email = sender_email or f"{_event_token(provider) or 'channel'}:{workspace_id}:{sender_id}"
    config = channel.get("config") if isinstance(channel.get("config"), dict) else {}
    _unused_channel_id, _unused_workspace_id, channel_title = _generic_channel_identity(event, record, channel)
    account_name = (
        _first_string(config, ("workspaceName", "workspace_name", "guildName", "guild_name", "teamName", "team_name", "accountName", "account_name"))
        or channel_title
        or f"{provider.title()} workspace {workspace_id or channel_id}"
    )
    identity = {
        "account_name": account_name,
        "account_domain": _sender_domain(sender_email),
        "contact_email": contact_email,
        "contact_name": sender_name,
    }
    identity_data = {
        "provider": provider,
        "workspaceId": workspace_id,
        "channelId": channel_id,
        "senderId": sender_id,
        "senderName": sender_name,
        "senderEmail": sender_email,
        "channelKey": _string_from(channel.get("channelKey")),
    }
    return identity, identity_data


def _ingest_generic_channel_message_event(
    *,
    channel: dict[str, Any],
    event: dict[str, Any],
    tenant_id: str | None,
    project_id: str,
    resume_incomplete: bool = False,
) -> dict[str, Any]:
    provider = _channel_provider(event, channel)
    provider_key = _event_token(provider) or "channel"
    record = _generic_message_record(event)
    attachments = _channel_message_attachments(event=event, record=record, provider=provider_key)
    body = _generic_message_body(record) or _channel_attachment_body(provider=provider, attachments=attachments)
    if not body:
        return {
            "eventType": _channel_event_type(event),
            "status": "ignored",
            "processed": 0,
            "skipped": 1,
            "error": "Ignored channel message without text",
        }
    source_issue_id, source_message_id, channel_id, workspace_id, thread_id = _generic_message_ids(event, record, channel, provider)
    provider_message_id = _channel_provider_message_id(event) or source_message_id.rsplit(":", 1)[-1]
    target_metadata = _generic_message_target_metadata(
        event,
        record,
        channel_id=channel_id,
        provider_message_id=provider_message_id,
        provider_key=provider_key,
    )
    identity, identity_data = _generic_sender_identity(
        event=event,
        record=record,
        provider=provider_key,
        channel=channel,
        channel_id=channel_id,
        workspace_id=workspace_id,
    )
    external_keys = _channel_external_keys(
        provider_key=provider_key,
        channel_key=_string_from(channel.get("channelKey")),
        workspace_id=workspace_id,
        channel_id=channel_id,
        thread_id=thread_id,
        conversation_id=_string_from(target_metadata.get("conversationId")) or thread_id,
        message_id=provider_message_id,
        ticket_creation_mode=_ticket_creation_mode(channel),
        author_id=_string_from(identity_data.get("senderId") or identity_data.get("userId")),
        author_display=identity["contact_name"],
    )
    resolver_base = _channel_resolver_base(
        channel=channel,
        provider_key=provider_key,
        source_issue_id=source_issue_id,
        source_message_id=source_message_id,
        external_keys=external_keys,
        workspace_id=workspace_id,
        provider_channel_id=channel_id,
        thread_id=thread_id,
        provider_message_id=provider_message_id,
    )
    account = _upsert_account(
        identity=identity,
        identity_data=identity_data,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    contact = _upsert_contact(
        identity=identity,
        identity_data=identity_data,
        account_id=_string_from(account.get("id")) if account else "",
        tenant_id=tenant_id,
        project_id=project_id,
    ) if account else None
    issue_filter = _issue_filter(
        tenant_id=tenant_id,
        project_id=project_id,
        extra=f"source_email_id='{_escape_pb(source_issue_id)}'",
    )
    existing_issue, _existing_redirected = _resolve_merged_issue_record(
        _first("support_issues", issue_filter),
        tenant_id=tenant_id,
        project_id=project_id,
    )
    now = _now_iso()
    if existing_issue:
        issue_id = _string_from(existing_issue.get("id"))
    else:
        issue_id = generate_id()
        issue_data: dict[str, Any] = {
            "id": issue_id,
            "source_email_id": source_issue_id,
            "channel": provider_key,
            "source": _string_from(channel.get("channelKey")),
            "status": "open",
            "priority": "normal",
            "subject": _channel_subject(body, provider=provider.title(), channel_id=channel_id, thread_id=""),
            "from_address": identity["contact_email"],
            "account_name": identity["account_name"],
            "account_domain": identity["account_domain"],
            "contact_email": identity["contact_email"],
            "contact_name": identity["contact_name"],
            "ai_summary": _clip(body, 300),
            "activated_intent": "",
            "requires_human": True,
            "message_count": 0,
            "action_log": [],
            "latest_message_at": now,
        }
        if account:
            issue_data["account"] = account["id"]
        if contact:
            issue_data["contact"] = contact["id"]
        if tenant_id:
            issue_data["tenant"] = tenant_id
        issue_data["project"] = project_id
        _apply_default_queue(
            issue_data,
            tenant_id=tenant_id,
            project_id=project_id,
            channel=channel,
        )
        default_assignee = _apply_default_assignee(
            issue_data,
            tenant_id=tenant_id,
            project_id=project_id,
            channel=channel,
        )
        _mark_assignment_required(
            issue_data,
            source=provider_key,
            channel=channel,
            context={"workspaceId": workspace_id, "channelId": channel_id, "threadId": thread_id},
        )
        _post("/api/collections/support_issues/records", issue_data)
        _record_default_assignment(
            issue_id=issue_id,
            assignee_email=default_assignee,
            tenant_id=tenant_id,
            project_id=project_id,
        )
    message, created = _append_channel_timeline_message(
        issue_id=issue_id,
        source_message_id=source_message_id,
        direction="customer",
        sender=identity["contact_name"],
        body=body,
        message_kind=f"{provider_key}_message",
        metadata={
            "provider": provider_key,
            "workspaceId": workspace_id,
            **target_metadata,
            "sourceIssueId": source_issue_id,
            "sourceMessageId": source_message_id,
            "eventId": _channel_event_id(event, _channel_event_type(event), _channel_provider_message_id(event), 0),
            "ticketCreationMode": _ticket_creation_mode(channel),
            "resolver": resolver_base,
            **external_keys,
        },
        tenant_id=tenant_id,
        project_id=project_id,
        attachments=attachments,
    )
    resolver_proof = _channel_resolver_proof(
        resolver_base,
        issue_id=issue_id,
        message_id=message["id"],
        existing_issue=existing_issue,
        message_created=created,
    )
    if resume_incomplete:
        resolver_proof["processingRecovery"] = "resumed"
    if not created and not resume_incomplete:
        return {
            "eventType": _channel_event_type(event),
            "status": "skipped",
            "processed": 0,
            "skipped": 1,
            "issueId": issue_id,
            "messageId": message["id"],
            "resolver": resolver_proof,
            "error": "",
        }

    issue_was_existing = bool(existing_issue)
    resume_processing_run = False
    if not created:
        durable_run = _direct_channel_processing_run(
            issue_id=issue_id,
            source=provider_key,
            source_message_id=source_message_id,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        durable_status = _string_from((durable_run or {}).get("status")).lower()
        if durable_run and durable_status != "processing":
            return {
                "eventType": _channel_event_type(event),
                "status": "success",
                "processed": 1,
                "skipped": 0,
                "issueId": issue_id,
                "messageId": message["id"],
                "resolver": resolver_proof,
                "processingRecovered": True,
                "processingRunId": _string_from(durable_run.get("id")),
                "processingRunStatus": durable_status,
                "error": "",
            }
        if durable_run and not _direct_channel_run_can_resume_package(durable_run):
            return {
                "eventType": _channel_event_type(event),
                "status": "skipped",
                "processed": 0,
                "skipped": 1,
                "issueId": issue_id,
                "messageId": message["id"],
                "resolver": resolver_proof,
                "processingRecovered": False,
                "processingRunId": _string_from(durable_run.get("id")),
                "processingRunStatus": durable_status or "processing",
                "error": "Ticket processing is already in progress",
            }
        resume_processing_run = bool(durable_run)
    if resume_incomplete:
        persisted_messages = _list_issue_messages(
            issue_id=issue_id,
            tenant_id=tenant_id,
            project_id=project_id,
        )
        customer_message_count = sum(
            1
            for persisted_message in persisted_messages
            if _string_from(persisted_message.get("direction")).lower() == "customer"
        )
        issue_was_existing = (
            _ticket_creation_mode(channel) != "per_message"
            and customer_message_count > 1
        )
        if not issue_was_existing:
            resolver_proof["resolverAction"] = "created"
            _record_default_assignment(
                issue_id=issue_id,
                assignee_email=_string_from(
                    (existing_issue or {}).get("assignee_email")
                    or (existing_issue or {}).get("assigneeEmail")
                ),
                tenant_id=tenant_id,
                project_id=project_id,
                idempotent=True,
            )
    else:
        customer_message_count = 0

    if issue_was_existing and (created or resume_incomplete):
        _supersede_pending_channel_autopilot_drafts(
            issue_id=issue_id,
            source_message_id=source_message_id,
            tenant_id=tenant_id,
            project_id=project_id,
        )

    previous_count = int(existing_issue.get("message_count") or 0) if existing_issue else 0
    next_count = (
        max(previous_count, customer_message_count or 1)
        if not created
        else previous_count + 1
    )
    issue_updates = {
        "message_count": next_count,
        "latest_message_at": now,
    }
    existing_was_done = issue_was_existing and _workflow_status(
        _string_from((existing_issue or {}).get("status"))
    ) == "done"
    if existing_was_done:
        issue_updates["status"] = "open"
    _patch(f"/api/collections/support_issues/records/{issue_id}", issue_updates)
    _record_issue_event(
        issue_id=issue_id,
        event_type=f"{provider_key}_message_received",
        tenant_id=tenant_id,
        project_id=project_id,
        actor_email=identity["contact_email"],
        title=f"{provider.title()} message received",
        body=_clip(body, 240),
        from_status="done" if existing_was_done else "",
        to_status="open" if existing_was_done else "",
        metadata={
            "provider": provider_key,
            "workspaceId": workspace_id,
            "channelId": channel_id,
            "threadId": thread_id,
            "messageId": message["id"],
            "ticketCreationMode": _ticket_creation_mode(channel),
            "resolver": resolver_proof,
            **external_keys,
        },
        record_id=_stable_record_id(
            "support_issue_event",
            project_id,
            issue_id,
            source_message_id,
            f"{provider_key}_message_received",
        ),
    )
    if issue_was_existing:
        _notify_customer_message_subscribers(
            issue={**existing_issue, **issue_updates},
            issue_id=issue_id,
            source=provider_key,
            message_id=source_message_id,
            body=body,
            actor_email=identity["contact_email"],
            tenant_id=tenant_id,
            project_id=project_id,
            metadata={
                "channelKey": _string_from(channel.get("channelKey")),
                "workspaceId": workspace_id,
                "channelId": channel_id,
                "threadId": thread_id,
                **external_keys,
            },
        )
    processed_issue = _apply_direct_channel_runbooks(
        issue={**(existing_issue if existing_issue else issue_data), **issue_updates, "id": issue_id},
        source=provider_key,
        source_message_id=source_message_id,
        subject=_channel_subject(body, provider=provider.title(), channel_id=channel_id, thread_id=thread_id),
        body=body,
        identity=identity,
        identity_data=identity_data,
        tenant_id=tenant_id,
        project_id=project_id,
        resume_processing_run=resume_processing_run,
    )
    processing_run = _processing_run_from_issue(processed_issue)
    _require_processing_claim(processing_run)
    if not issue_was_existing:
        _ensure_issue_sla_events(issue_id=issue_id, tenant_id=tenant_id, project_id=project_id)
        _require_processing_claim(processing_run)
        automation_result = _run_automation_rules_for_issue(
            issue=processed_issue,
            trigger="issue_created",
            tenant_id=tenant_id,
            project_id=project_id,
            actor_email="automation",
            context={
                "source": provider_key,
                "channelKey": _string_from(channel.get("channelKey")),
                "messageId": source_message_id,
                **external_keys,
            },
            processing_run=processing_run,
        )
        _channel_auto_prepare_agent_reply(
            channel=channel,
            issue_id=issue_id,
            tenant_id=tenant_id,
            project_id=project_id,
            source=provider_key,
            message_id=source_message_id,
            automation_result=automation_result,
            context=external_keys,
            processing_run=processing_run,
        )
    else:
        automation_result = _run_message_update_automations(
            issue=processed_issue,
            tenant_id=tenant_id,
            project_id=project_id,
            actor_email="automation",
            source=provider_key,
            message_id=source_message_id,
            context={
                "channelKey": _string_from(channel.get("channelKey")),
                "workspaceId": workspace_id,
                "channelId": channel_id,
                "threadId": thread_id,
                **external_keys,
            },
            processing_run=processing_run,
        )
        _channel_auto_prepare_agent_reply(
            channel=channel,
            issue_id=issue_id,
            tenant_id=tenant_id,
            project_id=project_id,
            source=provider_key,
            message_id=source_message_id,
            on_update=True,
            automation_result=automation_result,
            context=external_keys,
            processing_run=processing_run,
        )
    _sync_channel_account_insights(
        account_id=_string_from(account.get("id")) if account else None,
        issue=processed_issue,
        body=body,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    _refresh_account_contact_counts(
        account_id=_string_from(account.get("id")) if account else None,
        contact_id=_string_from(contact.get("id")) if contact else None,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    return {
        "eventType": _channel_event_type(event),
        "status": "success",
        "processed": 1,
        "skipped": 0,
        "issueId": issue_id,
        "messageId": message["id"],
        "resolver": resolver_proof,
        "processingRecovered": bool(resume_incomplete),
        "error": "",
    }


def ingest_channel_webhook(
    channel_key: str,
    *,
    payload: Any,
    tenant_id: str | None = None,
    project_id: str | None = None,
    source: str = "webhook",
) -> dict[str, Any]:
    del source
    channel = get_channel_by_key(channel_key, tenant_id=tenant_id, project_id=project_id)
    if not channel:
        raise ValueError("Channel not found")
    channel_id = _string_from(channel.get("id"))
    channel_project_id = _string_from(channel.get("projectId") or project_id)
    if not channel_project_id:
        raise ValueError("Channel has no project")
    channel_tenant_id = _string_from(channel.get("tenantId")) or tenant_id
    events = _channel_events_from_payload(payload)
    processed = 0
    failed = 0
    skipped = 0
    unmatched = 0
    items: list[dict[str, Any]] = []
    received_at = _now_iso()
    for index, event in enumerate(events):
        event_type = _channel_event_type(event)
        provider = _channel_provider(event, channel)
        is_inbound_message = _generic_event_is_inbound_message(event)
        raw_provider_message_id = _channel_provider_message_id(event)
        provider_message_id = (
            raw_provider_message_id if is_inbound_message else _channel_receipt_provider_message_id(
                event,
                provider=provider,
                fallback=raw_provider_message_id,
            )
        )
        event_id = _channel_event_id(event, event_type, provider_message_id, index)
        webhook_event, claim_token = _claim_channel_webhook_event(
            tenant_id=channel_tenant_id,
            project_id=channel_project_id,
            channel_id=channel_id,
            provider=provider,
            event_id=event_id,
            event_type=event_type,
            provider_message_id=provider_message_id,
            payload=event,
            received_at=received_at,
        )
        if not claim_token:
            webhook_event = _wait_for_channel_webhook_winner(
                webhook_event,
                channel_id=channel_id,
                event_id=event_id,
                tenant_id=channel_tenant_id,
                project_id=channel_project_id,
            )
            skipped += 1
            items.append(
                _channel_webhook_replay_item(
                    webhook_event,
                    event_id=event_id,
                    event_type=event_type,
                    provider_message_id=provider_message_id,
                )
            )
            continue
        if is_inbound_message:
            try:
                message_result = _ingest_generic_channel_message_event(
                    channel=channel,
                    event=event,
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                    resume_incomplete=int(webhook_event.get("processingAttempt") or 0) > 1,
                )
                result = {
                    "matched": True,
                    "kind": "inbound_message",
                    **message_result,
                }
                event_status = "processed" if message_result.get("status") == "success" else message_result.get("status") or "processed"
                completed = _try_complete_channel_webhook_claim(
                    webhook_event["id"],
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                    claim_token=claim_token,
                    status=event_status,
                    result=result,
                )
                if not completed:
                    latest = get_channel_webhook_event(
                        channel_id,
                        event_id,
                        tenant_id=channel_tenant_id,
                        project_id=channel_project_id,
                    ) or webhook_event
                    latest = _wait_for_channel_webhook_winner(
                        latest,
                        channel_id=channel_id,
                        event_id=event_id,
                        tenant_id=channel_tenant_id,
                        project_id=channel_project_id,
                    )
                    skipped += 1
                    items.append(
                        _channel_webhook_replay_item(
                            latest,
                            event_id=event_id,
                            event_type=event_type,
                            provider_message_id=provider_message_id,
                        )
                    )
                    continue
                if message_result.get("status") == "success":
                    processed += 1
                else:
                    skipped += 1
                items.append({"eventId": event_id, **result})
            except Exception as exc:
                error = str(exc)
                completed = _try_complete_channel_webhook_claim(
                    webhook_event["id"],
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                    claim_token=claim_token,
                    status="failed",
                    result={
                        "matched": False,
                        "kind": "inbound_message",
                        "eventType": event_type,
                        "providerMessageId": provider_message_id,
                    },
                    error=error,
                    retry_safe=True,
                )
                if not completed:
                    latest = get_channel_webhook_event(
                        channel_id,
                        event_id,
                        tenant_id=channel_tenant_id,
                        project_id=channel_project_id,
                    ) or webhook_event
                    latest = _wait_for_channel_webhook_winner(
                        latest,
                        channel_id=channel_id,
                        event_id=event_id,
                        tenant_id=channel_tenant_id,
                        project_id=channel_project_id,
                    )
                    skipped += 1
                    items.append(
                        _channel_webhook_replay_item(
                            latest,
                            event_id=event_id,
                            event_type=event_type,
                            provider_message_id=provider_message_id,
                        )
                    )
                    continue
                failed += 1
                items.append(
                    {
                        "eventId": event_id,
                        "eventType": event_type,
                        "providerMessageId": provider_message_id,
                        "status": "failed",
                        "error": error,
                    }
                )
            continue
        outbound = _find_outbound_for_receipt(
            tenant_id=channel_tenant_id,
            project_id=channel_project_id,
            provider_message_id=provider_message_id,
            event=event,
            provider=provider,
        )
        if not outbound:
            result = {
                "matched": False,
                "providerMessageId": provider_message_id,
                "eventType": event_type,
            }
            completed = _try_complete_channel_webhook_claim(
                webhook_event["id"],
                tenant_id=channel_tenant_id,
                project_id=channel_project_id,
                claim_token=claim_token,
                status="unmatched",
                result=result,
            )
            if not completed:
                latest = get_channel_webhook_event(
                    channel_id,
                    event_id,
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                ) or webhook_event
                latest = _wait_for_channel_webhook_winner(
                    latest,
                    channel_id=channel_id,
                    event_id=event_id,
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                )
                skipped += 1
                items.append(
                    _channel_webhook_replay_item(
                        latest,
                        event_id=event_id,
                        event_type=event_type,
                        provider_message_id=provider_message_id,
                    )
                )
                continue
            unmatched += 1
            items.append({"eventId": event_id, "eventType": event_type, "status": "unmatched", **result})
            continue
        try:
            updated_outbound = _apply_channel_delivery_receipt(
                tenant_id=channel_tenant_id,
                project_id=channel_project_id,
                outbound=outbound,
                event=event,
                event_type=event_type,
                provider=provider,
                provider_message_id=provider_message_id,
            )
            result = {
                "matched": True,
                "outboundMessageId": updated_outbound["id"],
                "outboundStatus": updated_outbound["status"],
                "issueId": updated_outbound.get("issueId", ""),
                "providerMessageId": provider_message_id,
                "eventType": event_type,
            }
            completed = _try_complete_channel_webhook_claim(
                webhook_event["id"],
                tenant_id=channel_tenant_id,
                project_id=channel_project_id,
                claim_token=claim_token,
                status="processed",
                outbound_message_id=updated_outbound["id"],
                result=result,
            )
            if not completed:
                latest = get_channel_webhook_event(
                    channel_id,
                    event_id,
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                ) or webhook_event
                latest = _wait_for_channel_webhook_winner(
                    latest,
                    channel_id=channel_id,
                    event_id=event_id,
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                )
                skipped += 1
                items.append(
                    _channel_webhook_replay_item(
                        latest,
                        event_id=event_id,
                        event_type=event_type,
                        provider_message_id=provider_message_id,
                    )
                )
                continue
            processed += 1
            items.append({"eventId": event_id, "status": "processed", **result})
        except Exception as exc:
            error = str(exc)
            completed = _try_complete_channel_webhook_claim(
                webhook_event["id"],
                tenant_id=channel_tenant_id,
                project_id=channel_project_id,
                claim_token=claim_token,
                status="failed",
                result={
                    "matched": False,
                    "eventType": event_type,
                    "providerMessageId": provider_message_id,
                },
                error=error,
                retry_safe=False,
            )
            if not completed:
                latest = get_channel_webhook_event(
                    channel_id,
                    event_id,
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                ) or webhook_event
                latest = _wait_for_channel_webhook_winner(
                    latest,
                    channel_id=channel_id,
                    event_id=event_id,
                    tenant_id=channel_tenant_id,
                    project_id=channel_project_id,
                )
                skipped += 1
                items.append(
                    _channel_webhook_replay_item(
                        latest,
                        event_id=event_id,
                        event_type=event_type,
                        provider_message_id=provider_message_id,
                    )
                )
                continue
            failed += 1
            items.append(
                {
                    "eventId": event_id,
                    "eventType": event_type,
                    "providerMessageId": provider_message_id,
                    "status": "failed",
                    "error": error,
                }
            )
    status = "failed" if failed and not processed else "partial" if failed else "success"
    if unmatched and not processed and not failed:
        status = "unmatched"
    if skipped and not processed and not failed and not unmatched:
        status = "skipped"
    if not events:
        status = "idle"
    return {
        "channelId": channel_id,
        "channelKey": channel.get("channelKey", channel_key),
        "status": status,
        "processed": processed,
        "failed": failed,
        "skipped": skipped,
        "unmatched": unmatched,
        "items": items,
        "error": next((item.get("error", "") for item in items if item.get("status") == "failed"), ""),
    }


def get_channel_cursor(
    channel_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    cursor_key: str = "inbound",
) -> dict[str, Any] | None:
    rec = _first(
        "support_channel_cursors",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"channel='{_escape_pb(channel_id)}' && cursor_key='{_escape_pb(cursor_key)}'",
        ),
    )
    return _normalize_channel_cursor(rec) if rec else None


def list_channel_cursors(
    *,
    tenant_id: str | None,
    project_id: str,
    channel_id: str = "",
    limit: int = 100,
) -> list[dict[str, Any]]:
    extra = f"channel='{_escape_pb(channel_id)}'" if channel_id else ""
    records = _list_all(
        "support_channel_cursors",
        _issue_filter(tenant_id=tenant_id, project_id=project_id, extra=extra),
        sort="-last_synced_at",
        per_page=max(1, min(limit, 200)),
    )
    return [_normalize_channel_cursor(rec) for rec in records[:limit]]


def upsert_channel_cursor(
    channel_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    cursor_key: str = "inbound",
    cursor_value: str = "",
    status: str = "idle",
    last_error: str = "",
    metadata: dict[str, Any] | None = None,
) -> dict[str, Any]:
    key = _string_from(cursor_key) or "inbound"
    existing = _first(
        "support_channel_cursors",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"channel='{_escape_pb(channel_id)}' && cursor_key='{_escape_pb(key)}'",
        ),
    )
    data: dict[str, Any] = {
        "channel": channel_id,
        "cursor_key": key,
        "cursor_value": cursor_value,
        "status": status,
        "last_error": last_error,
        "metadata": metadata or {},
        "last_synced_at": _now_iso(),
    }
    if existing:
        _patch(f"/api/collections/support_channel_cursors/records/{existing['id']}", data)
        return _normalize_channel_cursor({**existing, **data})
    create_data = {"id": generate_id(), **data}
    if tenant_id:
        create_data["tenant"] = tenant_id
    create_data["project"] = project_id
    return _normalize_channel_cursor(_post("/api/collections/support_channel_cursors/records", create_data))


