def upsert_crm_cursor(
    connector_id: str,
    *,
    tenant_id: str | None,
    project_id: str,
    cursor_key: str = "poll",
    cursor_value: str = "",
    status: str = "idle",
    last_error: str = "",
    metadata: dict[str, Any] | None = None,
) -> dict[str, Any]:
    key = _string_from(cursor_key) or "poll"
    existing = _first(
        "support_crm_cursors",
        _issue_filter(
            tenant_id=tenant_id,
            project_id=project_id,
            extra=f"connector='{_escape_pb(connector_id)}' && cursor_key='{_escape_pb(key)}'",
        ),
    )
    now = _now_iso()
    data: dict[str, Any] = {
        "connector": connector_id,
        "cursor_key": key,
        "cursor_value": cursor_value,
        "status": status,
        "last_error": last_error,
        "metadata": metadata or {},
        "last_synced_at": now,
    }
    if existing:
        _patch(f"/api/collections/support_crm_cursors/records/{existing['id']}", data)
        cursor = _normalize_crm_cursor({**existing, **data})
    else:
        create_data = {"id": generate_id(), **data}
        if tenant_id:
            create_data["tenant"] = tenant_id
        create_data["project"] = project_id
        cursor = _normalize_crm_cursor(_post("/api/collections/support_crm_cursors/records", create_data))
    _patch(f"/api/collections/support_crm_connectors/records/{connector_id}", {"last_sync_at": now})
    return cursor


