def support_analytics(
    *,
    tenant_id: str | None,
    project_id: str,
) -> dict[str, Any]:
    schema_health = support_schema_health()
    schema_blockers = _support_schema_launch_blockers(schema_health)
    if schema_health.get("missingCollections"):
        return _empty_support_analytics(blockers=schema_blockers, schema_health=schema_health)
    runtime_secrets = load_runtime_secrets(tenant_id, project_id) or {}

    issues = _list_all(
        "support_issues",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-created",
        per_page=500,
    )
    channels = _list_all(
        "support_channels",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="type,name",
        per_page=500,
    )
    support_queues = _list_all(
        "support_queues",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="queue_key",
        per_page=500,
    )
    sla_policies = _list_all(
        "support_sla_policies",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-active,name",
        per_page=100,
    )
    accounts = _list_all(
        "support_accounts",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-latest_issue_at",
        per_page=500,
    )
    articles = _list_all(
        "knowledge_articles",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-updated",
        per_page=500,
    )
    insights = _list_all(
        "support_account_insights",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-last_seen_at",
        per_page=500,
    )
    external_objects = _list_all(
        "support_external_objects",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-last_seen_at",
        per_page=500,
    )
    external_sync_runs = _list_all(
        "support_external_sync_runs",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-started_at",
        per_page=500,
    )
    crm_connectors = _list_all(
        "support_crm_connectors",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="provider,name",
        per_page=500,
    )
    crm_sync_runs = _list_all(
        "support_crm_sync_runs",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-started_at",
        per_page=500,
    )
    crm_webhook_events = _list_all(
        "support_crm_webhook_events",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-received_at",
        per_page=500,
    )
    knowledge_gaps = _list_all(
        "support_knowledge_gaps",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-updated",
        per_page=500,
    )
    ai_runs = _list_all(
        "support_ai_runs",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-created",
        per_page=500,
    )
    action_executions = _list_all(
        "support_action_executions",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-created",
        per_page=500,
    )
    automation_rules = _list_all(
        "support_automation_rules",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="name",
        per_page=500,
    )
    automation_runs = _list_all(
        "support_automation_runs",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-started_at",
        per_page=500,
    )
    issue_events = _list_all(
        "support_issue_events",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-occurred_at",
        per_page=500,
    )
    outbound_messages = _list_all(
        "support_outbound_messages",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-created",
        per_page=500,
    )
    channel_sync_runs = _list_all(
        "support_channel_sync_runs",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-started_at",
        per_page=500,
    )
    channel_webhook_events = _list_all(
        "support_channel_webhook_events",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-received_at",
        per_page=500,
    )
    web_chat_sessions = _list_all(
        "support_web_chat_sessions",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-last_message_at",
        per_page=500,
    )
    delivery_runs = _list_all(
        "support_delivery_runs",
        _delivery_scope_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-started_at",
        per_page=500,
    )
    launch_proof_runs = _list_all(
        "support_launch_proof_runs",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-started_at",
        per_page=10,
    )
    portal_sessions = _list_all(
        "support_customer_portal_sessions",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-created",
        per_page=500,
    )
    csat_feedback = _list_all(
        "support_csat_feedback",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="-received_at",
        per_page=500,
    )
    sla_events = _list_all(
        "support_sla_events",
        _issue_filter(tenant_id=tenant_id, project_id=project_id),
        sort="target_at",
        per_page=500,
    )
    status_counts: dict[str, int] = {}
    priority_counts: dict[str, int] = {}
    channel_counts: dict[str, int] = {}
    queue_counts: dict[str, int] = {}
    assignee_counts: dict[str, int] = {}
    open_queue_breakdown: dict[str, dict[str, Any]] = {}
    open_assignee_breakdown: dict[str, dict[str, Any]] = {}
    open_channel_breakdown: dict[str, dict[str, Any]] = {}
    issue_created_by_id: dict[str, datetime] = {}
    issue_status_by_id: dict[str, str] = {}
    response_summary_by_issue = _message_response_summary_by_issue(
        issues,
        tenant_id=tenant_id,
        project_id=project_id,
    )
    unassigned_issues = 0
    issues_needing_response = 0
    oldest_needs_response_at: datetime | None = None
    open_workload_issues = 0
    active_channels = sum(1 for channel in channels if channel.get("status", "active") == "active")
    backlog_channels_by_initial_surface: dict[str, list[dict[str, Any]]] = {}
    for channel in channels:
        surface_type = _initial_provider_surface_type(channel.get("type"))
        if surface_type not in INITIAL_PROVIDER_SURFACE_TYPES:
            continue
        status = _string_from(channel.get("status") or "active").lower()
        if status != "active" and status not in {"archived", "deleted"}:
            backlog_channels_by_initial_surface.setdefault(surface_type, []).append(channel)
    active_email_channel_ids = {
        _string_from(channel.get("id"))
        for channel in channels
        if channel.get("status", "active") == "active"
        and _string_from(channel.get("id"))
        and _string_from(channel.get("type")).lower() == "email"
    }
    active_web_chat_channel_ids = {
        _string_from(channel.get("id"))
        for channel in channels
        if channel.get("status", "active") == "active"
        and _string_from(channel.get("id"))
        and _string_from(channel.get("type")).lower() in {"chat", "web_chat"}
    }
    active_external_channel_ids = {
        _string_from(channel.get("id"))
        for channel in channels
        if channel.get("status", "active") == "active"
        and _string_from(channel.get("id"))
        and _string_from(channel.get("type")).lower() not in {"email", "chat", "web_chat"}
    }
    active_slack_channel_ids = {
        _string_from(channel.get("id"))
        for channel in channels
        if channel.get("status", "active") == "active"
        and _string_from(channel.get("id"))
        and _string_from(channel.get("type")).lower() == "slack"
    }
    active_external_channels_by_id = {
        _string_from(channel.get("id")): channel
        for channel in channels
        if _string_from(channel.get("id")) in active_external_channel_ids
    }
    channel_backlog_items = [
        {
            "channelId": _string_from(channel.get("id")),
            "channelKey": _string_from(channel.get("channel_key") or channel.get("channelKey")),
            "name": _string_from(channel.get("name")),
            "type": _string_from(channel.get("type")).lower(),
            "status": _string_from(channel.get("status") or "active").lower(),
        }
        for channel in channels
        if _string_from(channel.get("status") or "active").lower()
        not in {"active", "archived", "deleted"}
    ]
    channel_backlog_types = sorted(
        {
            _string_from(item.get("type")).lower()
            for item in channel_backlog_items
            if _string_from(item.get("type"))
        }
    )
    channel_backlog_proof = {
        "total": len(channel_backlog_items),
        "types": channel_backlog_types,
        "items": channel_backlog_items[:25],
    }
    channels_by_id = {
        _string_from(channel.get("id")): channel
        for channel in channels
        if _string_from(channel.get("id"))
    }
    active_support_queues_by_key = {
        key: queue
        for queue in support_queues
        if (
            key := _queue_key_from(queue.get("queue_key") or queue.get("queueKey"))
        )
        and _string_from(queue.get("status") or "active") == "active"
    }
    active_sla_policy = next((policy for policy in sla_policies if bool(policy.get("active", True))), None)
    project_policy_metadata = _parse(
        (active_sla_policy or (sla_policies[0] if sla_policies else {})).get("metadata"),
        dict,
    )

    def _increment_breakdown(target: dict[str, dict[str, Any]], key: str, label: str) -> None:
        existing = target.setdefault(key, {"key": key, "label": label, "count": 0})
        existing["count"] = int(existing["count"]) + 1

    now = datetime.now(timezone.utc)
    for issue in issues:
        issue_id = _string_from(issue.get("id"))
        status = _canonical_status(_string_from(issue.get("status")) or "open")
        if issue_id:
            issue_status_by_id[issue_id] = status
        priority = _string_from(issue.get("priority")) or "normal"
        channel = _string_from(issue.get("channel") or issue.get("source")) or "unknown"
        queue = _string_from(issue.get("queue_name") or issue.get("queue_key")) or "unqueued"
        assignee = _string_from(issue.get("assignee_email")) or "unassigned"
        status_counts[status] = status_counts.get(status, 0) + 1
        priority_counts[priority] = priority_counts.get(priority, 0) + 1
        channel_counts[channel] = channel_counts.get(channel, 0) + 1
        queue_counts[queue] = queue_counts.get(queue, 0) + 1
        assignee_counts[assignee] = assignee_counts.get(assignee, 0) + 1
        if not _string_from(issue.get("assignee_email")):
            unassigned_issues += 1
        if status != "done":
            open_workload_issues += 1
            queue_key = _string_from(issue.get("queue_key")) or "__no_queue__"
            queue_label = _string_from(issue.get("queue_name")) if queue_key != "__no_queue__" else "No queue"
            assignee_value = _string_from(issue.get("assignee_email"))
            assignee_key = assignee_value.lower() if assignee_value else "__unassigned__"
            assignee_label = assignee_value or "Unassigned"
            channel_value = _string_from(issue.get("channel") or issue.get("source"))
            channel_key = channel_value.lower() if channel_value else "__no_channel__"
            channel_label = channel_value or "No channel"
            _increment_breakdown(open_queue_breakdown, queue_key, queue_label)
            _increment_breakdown(open_assignee_breakdown, assignee_key, assignee_label)
            _increment_breakdown(open_channel_breakdown, channel_key, channel_label)
        response_summary = response_summary_by_issue.get(issue_id, {})
        if bool(response_summary.get("needsResponse")):
            issues_needing_response += 1
            latest_customer_at = _parse_iso_datetime(response_summary.get("latestCustomerMessageAt"))
            if latest_customer_at and (
                oldest_needs_response_at is None or latest_customer_at < oldest_needs_response_at
            ):
                oldest_needs_response_at = latest_customer_at
        created_at = _parse_iso_datetime(issue.get("created"))
        if issue_id and created_at:
            issue_created_by_id[issue_id] = created_at
    issues_needing_approval = {
        _string_from(message.get("issue"))
        for message in outbound_messages
        if _reply_needs_approval(message) and _string_from(message.get("issue"))
    }
    issues_needing_approval.update(
        _string_from(execution.get("issue"))
        for execution in action_executions
        if _action_execution_needs_approval(execution) and _string_from(execution.get("issue"))
    )
    queue_owner_capacity_items = _queue_capacity_items(
        support_queues=support_queues,
        issues=issues,
    )
    queue_owners_at_capacity = len(queue_owner_capacity_items)

    due_soon_until = now + timedelta(hours=1)
    overdue = 0
    due_soon = 0
    pending_sla_events = 0
    met_sla_events = 0
    breached_sla_events = 0
    first_response_minutes: list[float] = []
    resolution_hours: list[float] = []
    for event in sla_events:
        status = _string_from(event.get("status")).lower()
        metadata = _parse(event.get("metadata"), dict)
        issue_id = _string_from(event.get("issue"))
        pending_on_done_issue = status == "pending" and issue_id and issue_status_by_id.get(issue_id) == "done"
        if status == "pending" and not pending_on_done_issue:
            pending_sla_events += 1
        if pending_on_done_issue:
            continue
        if status != "pending" or not event.get("target_at"):
            if status == "met":
                met_sla_events += 1
                issue_created = issue_created_by_id.get(_string_from(event.get("issue")))
                occurred_at = _parse_iso_datetime(event.get("occurred_at"))
                if issue_created and occurred_at and occurred_at >= issue_created:
                    elapsed_minutes = (occurred_at - issue_created).total_seconds() / 60
                    if event.get("event_type") == "first_response_due":
                        first_response_minutes.append(elapsed_minutes)
                    if event.get("event_type") == "resolution_due":
                        resolution_hours.append(elapsed_minutes / 60)
            elif status in {"breached", "missed", "failed"}:
                breached_sla_events += 1
            elif status == "pending" and (metadata.get("escalatedAt") or metadata.get("escalated_at")):
                breached_sla_events += 1
            continue
        target = _parse_iso_datetime(event.get("target_at"))
        if target and target < now:
            overdue += 1
            breached_sla_events += 1
        elif target and target <= due_soon_until:
            due_soon += 1
        elif metadata.get("escalatedAt") or metadata.get("escalated_at"):
            breached_sla_events += 1

    def _p90(values: list[float]) -> float:
        if not values:
            return 0
        ordered = sorted(values)
        index = min(len(ordered) - 1, max(0, (9 * len(ordered) + 9) // 10 - 1))
        return round(ordered[index], 1)

    def _is_channel_smoke_run(run: dict[str, Any]) -> bool:
        return _string_from(run.get("source")) in {"admin-smoke-run", "admin-smoke"}

    def _is_outbound_channel_smoke_run(run: dict[str, Any]) -> bool:
        return _string_from(run.get("source")) == "admin-outbound-smoke"

    def _is_lifecycle_channel_smoke_run(run: dict[str, Any]) -> bool:
        return _string_from(run.get("source")) == "admin-lifecycle-smoke"

    def _is_channel_validation_run(run: dict[str, Any]) -> bool:
        return _string_from(run.get("source")) == "admin-validation"

    def _sync_run_failed(run: dict[str, Any]) -> bool:
        status = _string_from(run.get("status")).lower()
        return status in {"failed", "partial", "error"} or int(run.get("failed") or 0) > 0

    def _run_result(run: dict[str, Any]) -> dict[str, Any]:
        return _parse(run.get("result"), dict)

    def _run_remediation_items(run: dict[str, Any]) -> list[dict[str, Any]]:
        return [item for item in _parse(_run_result(run).get("remediation"), list) if isinstance(item, dict)]

    def _result_text(result: dict[str, Any], *keys: str) -> str:
        for key in keys:
            value = _string_from(result.get(key))
            if value:
                return value
        return ""

    def _run_issue_id(run: dict[str, Any]) -> str:
        result = _run_result(run)
        issue_id = _result_text(result, "issueId", "issue_id")
        if issue_id:
            return issue_id
        inbound = _parse(result.get("inbound"), dict)
        issue_id = _result_text(inbound, "issueId", "issue_id")
        if issue_id:
            return issue_id
        for item in _parse(result.get("items"), list):
            if isinstance(item, dict):
                issue_id = _result_text(item, "issueId", "issue_id")
                if issue_id:
                    return issue_id
        return ""

    def _run_reply_id(run: dict[str, Any]) -> str:
        result = _run_result(run)
        reply_id = _result_text(result, "replyId", "reply_id", "outboundMessageId", "outbound_message_id")
        if reply_id:
            return reply_id
        delivery = _parse(result.get("delivery"), dict)
        return _result_text(delivery, "id", "replyId", "reply_id", "outboundMessageId", "outbound_message_id")

    def _run_provider_message_id(run: dict[str, Any]) -> str:
        result = _run_result(run)
        provider_message_id = _result_text(result, "providerMessageId", "provider_message_id")
        if provider_message_id:
            return provider_message_id
        delivery = _parse(result.get("delivery"), dict)
        return _result_text(delivery, "providerMessageId", "provider_message_id")

    def _run_delivery_metadata(run: dict[str, Any]) -> dict[str, Any]:
        result = _run_result(run)
        metadata = _parse(result.get("metadata"), dict)
        delivery = _parse(result.get("delivery"), dict)
        delivery_metadata = _parse(delivery.get("metadata"), dict)
        return {**metadata, **delivery_metadata}

    def _run_delivery_route(run: dict[str, Any]) -> dict[str, Any]:
        result = _run_result(run)
        route = _parse(result.get("deliveryRoute"), dict)
        if route:
            return route
        delivery = _parse(result.get("delivery"), dict)
        route = _parse(delivery.get("deliveryRoute"), dict)
        if route:
            return route
        return _parse(_run_delivery_metadata(run).get("deliveryRoute"), dict)

    def _run_provider_response(run: dict[str, Any]) -> dict[str, Any]:
        result = _run_result(run)
        response = _parse(result.get("providerResponse"), dict)
        if response:
            return response
        delivery = _parse(result.get("delivery"), dict)
        response = _parse(delivery.get("providerResponse"), dict)
        if response:
            return response
        return _parse(_run_delivery_metadata(run).get("providerResponse"), dict)

    def _run_attachment_count(run: dict[str, Any]) -> int:
        result = _run_result(run)
        value = result.get("attachmentCount") or result.get("attachment_count")
        if value is None:
            inbound = _parse(result.get("inbound"), dict)
            value = inbound.get("attachmentCount") or inbound.get("attachment_count")
        try:
            return max(0, int(value or 0))
        except (TypeError, ValueError):
            return 0

    def _run_file_only(run: dict[str, Any]) -> bool:
        result = _run_result(run)
        value = result.get("fileOnly") if "fileOnly" in result else result.get("file_only")
        if value is None:
            inbound = _parse(result.get("inbound"), dict)
            value = inbound.get("fileOnly") if "fileOnly" in inbound else inbound.get("file_only")
        return bool(value)

    def _run_has_attachment_only_proof(run: dict[str, Any]) -> bool:
        return _run_file_only(run) and _run_attachment_count(run) > 0

    def _run_has_provider_delivery_proof(run: dict[str, Any]) -> bool:
        return bool(_run_delivery_route(run)) and bool(_run_provider_response(run))

    def _provider_delivery_proof_detail(run: dict[str, Any]) -> str:
        has_route = bool(_run_delivery_route(run))
        has_response = bool(_run_provider_response(run))
        if not has_route and not has_response:
            return "Provider delivery did not record delivery route and provider response"
        if not has_route:
            return "Provider delivery did not record delivery route"
        if not has_response:
            return "Provider delivery did not record provider response"
        return ""

    def _smoke_run_success(run: dict[str, Any], *, issue_required: bool = False) -> bool:
        result = _parse(run.get("result"), dict)
        ready = result.get("ready")
        if ready is False:
            return False
        if issue_required and not _run_issue_id(run):
            return False
        return (
            _string_from(run.get("status")).lower() == "success"
            and int(run.get("processed") or 0) > 0
            and int(run.get("failed") or 0) == 0
        )

    def _template_secret_names(template: str) -> list[str]:
        names: list[str] = []
        seen: set[str] = set()
        for match in re.finditer(r"\{([A-Z][A-Z0-9_]*)\}", template):
            name = match.group(1)
            if name in seen:
                continue
            seen.add(name)
            names.append(name)
        return names

    def _outbound_webhook_available(config: dict[str, Any]) -> bool:
        webhook_url = _string_from(config.get("outboundWebhookUrl") or config.get("outbound_webhook_url"))
        webhook_url_env = _string_from(config.get("outboundWebhookUrlEnv") or config.get("outbound_webhook_url_env"))
        if webhook_url_env:
            webhook_url = _string_from(runtime_secrets.get(webhook_url_env)) or os.getenv(webhook_url_env, "").strip() or webhook_url
        if webhook_url:
            return True
        template = _string_from(config.get("outboundWebhookUrlTemplate") or config.get("outbound_webhook_url_template"))
        if not template:
            return False
        names = _template_secret_names(template)
        return not names or all(_runtime_secret_present(name) for name in names)

    def _provider_delivery_artifact_required(channel: dict[str, Any]) -> bool:
        channel_type = _string_from(channel.get("type")).lower()
        if channel_type not in {"slack", "teams", "discord", "telegram", "line", "viber", "whatsapp", "messenger", "facebook_messenger", "sms"}:
            return False
        config = _parse(channel.get("config"), dict)
        transport = _string_from(config.get("outboundTransport") or config.get("outbound_transport")).lower()
        if transport in {
            "bot",
            "slack_bot",
            "teams_bot",
            "telegram_bot",
            "discord_bot",
            "line",
            "line_messaging",
            "line_messaging_api",
            "viber",
            "viber_bot",
            "whatsapp_api",
            "messenger",
            "messenger_api",
            "facebook_messenger",
            "facebook_messenger_api",
            "twilio",
            "twilio_sms",
            "sms",
            "bot_api",
            "provider_api",
            "bot_framework",
        }:
            return True
        payload_mode = _string_from(
            config.get("outboundPayloadMode")
            or config.get("outbound_payload_mode")
            or config.get("payloadMode")
            or config.get("payload_mode")
        ).lower()
        if payload_mode in {"provider", channel_type, "line", "viber", "messenger", "facebook_messenger", "twilio"}:
            return True
        if _outbound_webhook_available(config):
            return False
        if channel_type == "slack":
            token_env = (
                _string_from(config.get("slackBotTokenEnv"))
                or _string_from(config.get("slack_bot_token_env"))
                or _string_from(config.get("botTokenEnv"))
                or _string_from(config.get("bot_token_env"))
                or _string_from(config.get("outboundWebhookTokenEnv"))
                or _string_from(config.get("outbound_webhook_token_env"))
                or "SUPPORT_SLACK_BOT_TOKEN"
            )
            return _runtime_secret_present(token_env)
        if channel_type == "teams":
            app_id_env = (
                _string_from(config.get("teamsAppIdEnv"))
                or _string_from(config.get("teams_app_id_env"))
                or "SUPPORT_TEAMS_APP_ID"
            )
            app_password_env = (
                _string_from(config.get("teamsAppPasswordEnv"))
                or _string_from(config.get("teams_app_password_env"))
                or "SUPPORT_TEAMS_APP_PASSWORD"
            )
            return _runtime_secret_present(app_id_env) and _runtime_secret_present(app_password_env)
        if channel_type == "discord":
            token_env = (
                _string_from(config.get("discordBotTokenEnv"))
                or _string_from(config.get("discord_bot_token_env"))
                or _string_from(config.get("botTokenEnv"))
                or _string_from(config.get("bot_token_env"))
                or "SUPPORT_DISCORD_BOT_TOKEN"
            )
            return _runtime_secret_present(token_env)
        if channel_type == "telegram":
            token_env = (
                _string_from(config.get("telegramBotTokenEnv"))
                or _string_from(config.get("telegram_bot_token_env"))
                or _string_from(config.get("botTokenEnv"))
                or _string_from(config.get("bot_token_env"))
                or "SUPPORT_TELEGRAM_BOT_TOKEN"
            )
            return _runtime_secret_present(token_env)
        if channel_type == "line":
            return _runtime_secret_present(_line_channel_access_token_env(config))
        if channel_type == "viber":
            return _runtime_secret_present(_viber_auth_token_env(config))
        if channel_type == "whatsapp":
            return _runtime_secret_present(_whatsapp_access_token_env(config))
        if channel_type in {"messenger", "facebook_messenger"}:
            return _runtime_secret_present(_messenger_page_access_token_env(config))
        if channel_type == "sms":
            account_sid = _runtime_secret_present(_twilio_account_sid_env(config))
            auth_token = _runtime_secret_present(_twilio_auth_token_env(config))
            from_number_env = _twilio_from_number_env(config)
            from_number = (
                _string_from(config.get("twilioFromNumber"))
                or _string_from(config.get("twilio_from_number"))
                or _string_from(config.get("fromNumber"))
                or _string_from(config.get("from_number"))
                or _string_from(runtime_secrets.get(from_number_env))
                or os.getenv(from_number_env, "").strip()
            )
            messaging_service_sid_env = _twilio_messaging_service_sid_env(config)
            messaging_service_sid = (
                _string_from(config.get("twilioMessagingServiceSid"))
                or _string_from(config.get("twilio_messaging_service_sid"))
                or _string_from(config.get("messagingServiceSid"))
                or _string_from(config.get("messaging_service_sid"))
                or (
                    _string_from(runtime_secrets.get(messaging_service_sid_env))
                    or os.getenv(messaging_service_sid_env, "").strip()
                    if messaging_service_sid_env
                    else ""
                )
            )
            return account_sid and auth_token and bool(from_number or messaging_service_sid)
        return False

    def _provider_validation_required(channel: dict[str, Any]) -> bool:
        return _provider_delivery_artifact_required(channel)

    def _live_smoke_target_value(value: str) -> bool:
        clean = value.strip()
        if not clean:
            return False
        normalized = clean.lower()
        if normalized in SMOKE_TARGET_PLACEHOLDERS:
            return False
        if normalized.startswith("admin-smoke"):
            return False
        if normalized.startswith("+1555") or normalized.startswith("1555"):
            return False
        return True

    def _config_text(config: dict[str, Any], *keys: str) -> str:
        for key in keys:
            value = config.get(key)
            if value is not None:
                return _string_from(value)
        return ""

    def _live_smoke_target_configured(channel: dict[str, Any]) -> tuple[bool, str]:
        channel_type = _string_from(channel.get("type")).lower()
        config = _parse(channel.get("config"), dict)

        def has_any(*keys: str) -> bool:
            return any(_live_smoke_target_value(_config_text(config, key)) for key in keys)

        if channel_type == "slack":
            ready = has_any("smokeChannelId", "smoke_channel_id", "channelId", "channel_id")
            return ready, "Set smokeChannelId to a real Slack channel ID before launch proof"
        if channel_type == "teams":
            has_service_url = has_any("smokeServiceUrl", "smoke_service_url", "serviceUrl", "service_url")
            has_conversation = has_any(
                "smokeConversationId",
                "smoke_conversation_id",
                "conversationId",
                "conversation_id",
                "smokeThreadId",
                "smoke_thread_id",
                "smokeChannelId",
                "smoke_channel_id",
                "channelId",
                "channel_id",
            )
            return (
                has_service_url and has_conversation,
                "Set smokeServiceUrl plus a real Teams conversation/channel target before launch proof",
            )
        if channel_type == "discord":
            ready = has_any(
                "smokeChannelId",
                "smoke_channel_id",
                "channelId",
                "channel_id",
                "smokeThreadId",
                "smoke_thread_id",
            )
            return ready, "Set smokeChannelId or smokeThreadId to a real Discord target before launch proof"
        if channel_type == "telegram":
            ready = has_any(
                "smokeChatId",
                "smoke_chat_id",
                "chatId",
                "chat_id",
                "smokeChannelId",
                "smoke_channel_id",
                "channelId",
                "channel_id",
                "smokeToAddress",
                "smoke_to_address",
            )
            return ready, "Set smokeChatId to a real Telegram chat ID before launch proof"
        if channel_type == "line":
            ready = has_any(
                "smokeToAddress",
                "smoke_to_address",
                "smokeConversationId",
                "smoke_conversation_id",
                "lineUserId",
                "line_user_id",
                "userId",
                "user_id",
                "groupId",
                "group_id",
                "roomId",
                "room_id",
                "chatId",
                "chat_id",
            )
            return ready, "Set smokeToAddress to a real LINE user, group, or room ID before launch proof"
        if channel_type == "viber":
            ready = has_any(
                "smokeToAddress",
                "smoke_to_address",
                "smokeConversationId",
                "smoke_conversation_id",
                "viberUserId",
                "viber_user_id",
                "userId",
                "user_id",
                "senderId",
                "sender_id",
                "chatId",
                "chat_id",
            )
            return ready, "Set smokeToAddress to a real Viber subscriber ID before launch proof"
        if channel_type == "whatsapp":
            ready = has_any(
                "smokeToAddress",
                "smoke_to_address",
                "smokeConversationId",
                "smoke_conversation_id",
                "waId",
                "wa_id",
                "senderId",
                "sender_id",
                "chatId",
                "chat_id",
            )
            return ready, "Set smokeToAddress to a real WhatsApp recipient before launch proof"
        if channel_type in {"messenger", "facebook_messenger"}:
            ready = has_any(
                "smokeToAddress",
                "smoke_to_address",
                "smokeConversationId",
                "smoke_conversation_id",
                "senderId",
                "sender_id",
                "psid",
                "chatId",
                "chat_id",
            )
            return ready, "Set smokeToAddress to a real Messenger PSID before launch proof"
        if channel_type in {"sms", "twilio"}:
            ready = has_any(
                "smokeToAddress",
                "smoke_to_address",
                "smokeConversationId",
                "smoke_conversation_id",
                "smokeChannelId",
                "smoke_channel_id",
            )
            return ready, "Set smokeToAddress to a real SMS recipient before launch proof"
        return True, ""

    def _live_target_value(config: dict[str, Any], *keys: str) -> str:
        for key in keys:
            value = _config_text(config, key)
            if _live_smoke_target_value(value):
                return value.strip()
        return ""

