    def _signature_auth_mode_required(channel: dict[str, Any]) -> str:
        config = _parse(channel.get("config"), dict)
        channel_type = _string_from(channel.get("type")).lower()
        generic_signature = bool(
            _string_from(config.get("signatureSecretEnv"))
            or _string_from(config.get("webhookSignatureSecretEnv"))
            or _string_from(config.get("signature_secret_env"))
        )
        if channel_type == "slack":
            slack_signature_env = (
                _string_from(config.get("slackSigningSecretEnv"))
                or _string_from(config.get("slack_signing_secret_env"))
                or _string_from(config.get("signatureSecretEnv"))
                or _string_from(config.get("webhookSignatureSecretEnv"))
                or _string_from(config.get("signature_secret_env"))
                or "SUPPORT_SLACK_SIGNING_SECRET"
            )
            if (
                _string_from(config.get("slackSigningSecretEnv"))
                or _string_from(config.get("slack_signing_secret_env"))
                or generic_signature
                or _runtime_secret_present(slack_signature_env)
            ):
                return "slack_signature"
            return ""
        provider_keys = PROVIDER_SIGNATURE_SECRET_CONFIG_KEYS.get(channel_type, ())
        if channel_type == "telegram":
            if any(_string_from(config.get(key)) for key in provider_keys) or generic_signature:
                return "hmac_signature"
            if _runtime_secret_present(_telegram_secret_token_env(config)):
                return "telegram_secret_token"
            return ""
        if channel_type in {"sms", "twilio"}:
            if _runtime_secret_present(_twilio_auth_token_env(config)):
                return "twilio_signature"
            if any(_string_from(config.get(key)) for key in provider_keys) or generic_signature:
                return "hmac_signature"
            return ""
        if any(_string_from(config.get(key)) for key in provider_keys) or generic_signature:
            return "hmac_signature"
        return ""

    def _run_http_auth(run: dict[str, Any]) -> dict[str, Any]:
        result = _run_result(run)
        http_result = _parse(result.get("http"), dict)
        inbound = _parse(result.get("inbound"), dict)
        inbound_http = _parse(inbound.get("http"), dict)
        for candidate in (
            result.get("auth"),
            http_result.get("auth"),
            inbound_http.get("auth"),
        ):
            if isinstance(candidate, dict):
                return candidate
        return {}

    def _run_has_timestamp_auth(run: dict[str, Any]) -> bool:
        auth = _run_http_auth(run)
        return bool(_string_from(auth.get("timestampHeader") or auth.get("timestamp_header")))

    def _run_auth_mode(run: dict[str, Any]) -> str:
        return _string_from(_run_http_auth(run).get("mode")).lower()

    def _run_has_signature_auth(run: dict[str, Any], required_mode: str) -> bool:
        if not required_mode:
            return True
        return _run_auth_mode(run) == required_mode

    def _required_auth_mode_detail(required_mode: str) -> str:
        if required_mode == "telegram_secret_token":
            return "Smoke run did not record required Telegram secret-token auth"
        if required_mode == "twilio_signature":
            return "Smoke run did not record required Twilio signature auth"
        return "Smoke run did not record required signature auth"

    def _provider_surface_smoke_run_success(
        run: dict[str, Any],
        *,
        signature_auth_mode_required: str = "",
        timestamp_auth_required: bool = False,
    ) -> bool:
        return (
            _smoke_run_success(run, issue_required=True)
            and _smoke_uses_provider_surface(run)
            and _run_has_signature_auth(run, signature_auth_mode_required)
            and (not timestamp_auth_required or _run_has_timestamp_auth(run))
        )

    def _provider_surface_launch_smoke_run_success(
        channel: dict[str, Any],
        run: dict[str, Any],
        *,
        signature_auth_mode_required: str = "",
        timestamp_auth_required: bool = False,
    ) -> bool:
        return (
            _provider_surface_smoke_run_success(
                run,
                signature_auth_mode_required=signature_auth_mode_required,
                timestamp_auth_required=timestamp_auth_required,
            )
            and _live_inbound_smoke_target_run_matches(channel, run)
        )

    def _provider_surface_lifecycle_smoke_run_success(
        run: dict[str, Any],
        *,
        provider_message_required: bool = False,
        provider_delivery_proof_required: bool = False,
        attachment_only_required: bool = False,
        signature_auth_mode_required: str = "",
        timestamp_auth_required: bool = False,
    ) -> bool:
        return (
            _lifecycle_smoke_run_success(
                run,
                provider_message_required=provider_message_required,
                provider_delivery_proof_required=provider_delivery_proof_required,
                attachment_only_required=attachment_only_required,
            )
            and _smoke_uses_provider_surface(run)
            and _run_has_signature_auth(run, signature_auth_mode_required)
            and (not timestamp_auth_required or _run_has_timestamp_auth(run))
        )

    def _outbound_launch_smoke_run_success(channel: dict[str, Any], run: dict[str, Any]) -> bool:
        provider_delivery_required = _provider_delivery_artifact_required(channel)
        return (
            _outbound_smoke_run_success(
                run,
                provider_message_required=provider_delivery_required,
                provider_delivery_proof_required=provider_delivery_required,
            )
            and _live_smoke_target_run_matches(channel, run)
        )

    def _lifecycle_launch_smoke_run_success(
        channel: dict[str, Any],
        run: dict[str, Any],
        *,
        attachment_only_required: bool = False,
    ) -> bool:
        provider_delivery_required = _provider_delivery_artifact_required(channel)
        return (
            _provider_surface_lifecycle_smoke_run_success(
                run,
                provider_message_required=provider_delivery_required,
                provider_delivery_proof_required=provider_delivery_required,
                attachment_only_required=attachment_only_required,
                signature_auth_mode_required=_signature_auth_mode_required(channel),
                timestamp_auth_required=_signature_timestamp_required(channel),
            )
            and _live_smoke_target_run_matches(channel, run)
        )

    def _email_sync_run_success(run: dict[str, Any]) -> bool:
        status = _string_from(run.get("status")).lower()
        return (
            status == "success"
            and int(run.get("processed") or 0) > 0
            and int(run.get("failed") or 0) == 0
            and bool(_run_issue_id(run))
        )

    def _delivery_run_has_email_signal(run: dict[str, Any]) -> bool:
        result = _parse(run.get("result"), dict)
        items = _parse(result.get("items"), list)
        if not items:
            return True
        for item in items:
            if not isinstance(item, dict):
                continue
            channel = _string_from(item.get("channel")).lower()
            provider = _string_from(item.get("provider")).lower()
            if channel == "email" or provider in {"smtp", "email"} or _string_from(item.get("toAddress")):
                return True
        return False

    def _email_delivery_run_success(run: dict[str, Any]) -> bool:
        if not run or not _delivery_run_has_email_signal(run):
            return False
        status = _string_from(run.get("status")).lower()
        return (
            status in {"sent", "success"}
            and int(run.get("sent") or 0) > 0
            and int(run.get("failed") or 0) == 0
        )

    def _web_chat_session_success(session: dict[str, Any]) -> bool:
        if not session:
            return False
        status = _string_from(session.get("status")).lower()
        issue_id = _string_from(session.get("issue") or session.get("issueId"))
        return bool(issue_id) and status not in {"", "failed", "error"}

    def _web_chat_delivery_success(message: dict[str, Any]) -> bool:
        if not message:
            return False
        status = _string_from(message.get("status")).lower()
        provider = _string_from(message.get("provider")).lower()
        provider_message_id = _string_from(message.get("provider_message_id") or message.get("providerMessageId"))
        return status == "sent" and provider == "web_chat_internal" and bool(provider_message_id)

    def _web_chat_delivery_failed(message: dict[str, Any]) -> bool:
        if not message:
            return False
        status = _string_from(message.get("status")).lower()
        return status in {"failed", "error"} or bool(_string_from(message.get("error")))

