    latest_launch_proof_run = (
        _normalize_launch_proof_run(launch_proof_runs[0])
        if launch_proof_runs
        else None
    )
    web_chat_session_by_id: dict[str, dict[str, Any]] = {}
    web_chat_issue_channel_ids: dict[str, str] = {}
    latest_web_chat_session_by_channel: dict[str, dict[str, Any]] = {}
    for session in web_chat_sessions:
        channel_id = _string_from(session.get("channel") or session.get("channelId"))
        if channel_id not in active_web_chat_channel_ids:
            continue
        session_id = _string_from(session.get("id"))
        if session_id:
            web_chat_session_by_id[session_id] = session
        session_metadata = _parse(session.get("metadata"), dict)
        for issue_ref in (
            session.get("issue"),
            session.get("issueId"),
            session_metadata.get("latestIssueId"),
            session_metadata.get("latest_issue_id"),
        ):
            issue_id = _string_from(issue_ref)
            if issue_id:
                web_chat_issue_channel_ids.setdefault(issue_id, channel_id)
        if channel_id not in latest_web_chat_session_by_channel:
            latest_web_chat_session_by_channel[channel_id] = session
    active_web_chat_channels_without_session = sum(
        1 for channel_id in active_web_chat_channel_ids
        if not latest_web_chat_session_by_channel.get(channel_id)
    )
    active_web_chat_channels_with_session = sum(
        1 for channel_id in active_web_chat_channel_ids
        if _web_chat_session_success(latest_web_chat_session_by_channel.get(channel_id, {}))
    )
    active_web_chat_session_failures = sum(
        1 for session in latest_web_chat_session_by_channel.values()
        if not _web_chat_session_success(session)
    )
    latest_web_chat_delivery_by_channel: dict[str, dict[str, Any]] = {}
    latest_successful_web_chat_delivery_by_channel: dict[str, dict[str, Any]] = {}

    def _web_chat_delivery_channel_id(message: dict[str, Any]) -> str:
        channel = _string_from(message.get("channel")).lower()
        provider = _string_from(message.get("provider")).lower()
        metadata = _parse(message.get("metadata"), dict)
        session_id = _string_from(metadata.get("webChatSessionId") or metadata.get("web_chat_session_id"))
        if channel not in {"chat", "web_chat"} and provider != "web_chat_internal" and not session_id:
            return ""
        session = web_chat_session_by_id.get(session_id)
        if session:
            channel_id = _string_from(session.get("channel") or session.get("channelId"))
            if channel_id in active_web_chat_channel_ids:
                return channel_id
        issue_id = _string_from(message.get("issue") or message.get("issueId"))
        return web_chat_issue_channel_ids.get(issue_id, "")

    for message in outbound_messages:
        channel_id = _web_chat_delivery_channel_id(message)
        if channel_id not in active_web_chat_channel_ids:
            continue
        if channel_id not in latest_web_chat_delivery_by_channel:
            latest_web_chat_delivery_by_channel[channel_id] = message
        if (
            channel_id not in latest_successful_web_chat_delivery_by_channel
            and _web_chat_delivery_success(message)
        ):
            latest_successful_web_chat_delivery_by_channel[channel_id] = message
    active_web_chat_channels_without_delivery = sum(
        1 for channel_id in active_web_chat_channel_ids
        if _web_chat_session_success(latest_web_chat_session_by_channel.get(channel_id, {}))
        and not latest_successful_web_chat_delivery_by_channel.get(channel_id)
    )
    active_web_chat_delivery_failures = sum(
        1 for channel_id in active_web_chat_channel_ids
        if _web_chat_delivery_failed(latest_web_chat_delivery_by_channel.get(channel_id, {}))
        and not latest_successful_web_chat_delivery_by_channel.get(channel_id)
    )

    def _run_time(run: dict[str, Any]) -> str:
        return _string_from(
            run.get("startedAt")
            or run.get("started_at")
            or run.get("completedAt")
            or run.get("completed_at")
            or run.get("created")
        )

    def _run_processed(run: dict[str, Any]) -> int:
        try:
            return int(run.get("processed") or 0)
        except (TypeError, ValueError):
            return 0

    def _run_failed_count(run: dict[str, Any]) -> int:
        try:
            return int(run.get("failed") or 0)
        except (TypeError, ValueError):
            return 0

    def _run_sent_count(run: dict[str, Any]) -> int:
        try:
            return int(run.get("sent") or 0)
        except (TypeError, ValueError):
            return 0

    channel_remediation_runs: list[dict[str, Any]] = []
    channel_remediation_item_count = 0
    latest_channel_remediations: list[dict[str, Any]] = []
    for run in channel_sync_runs:
        remediation_items = _run_remediation_items(run)
        if not remediation_items:
            continue
        channel_remediation_runs.append(run)
        channel_remediation_item_count += len(remediation_items)
        channel_id = _string_from(run.get("channel") or run.get("channelId"))
        channel = channels_by_id.get(channel_id, {})
        started_at = _run_time(run)
        for item in remediation_items[:3]:
            latest_channel_remediations.append({
                "channelId": channel_id,
                "channelKey": _string_from(channel.get("channel_key") or channel.get("channelKey")),
                "channelName": (
                    _string_from(channel.get("name"))
                    or _string_from(channel.get("channel_key") or channel.get("channelKey"))
                ),
                "source": _string_from(run.get("source")),
                "status": _string_from(run.get("status")),
                "startedAt": started_at,
                "key": _string_from(item.get("key")),
                "label": _string_from(item.get("label") or item.get("key")),
                "detail": _string_from(item.get("detail")),
                "severity": _string_from(item.get("severity")) or "warning",
                "action": _string_from(item.get("action")),
                "runAction": _string_from(item.get("runAction") or item.get("run_action")),
            })
    latest_channel_remediations = latest_channel_remediations[:10]

    def _proof_check(
        *,
        key: str,
        label: str,
        run: dict[str, Any],
        passed: bool,
        missing_detail: str,
        provider_surface_detail: str = "",
        issue_required: bool = False,
        reply_required: bool = False,
        provider_message_required: bool = False,
        provider_delivery_proof_required: bool = False,
        attachment_only_required: bool = False,
        signature_auth_mode_required: str = "",
        timestamp_auth_required: bool = False,
        target_match_required: bool = False,
        target_match_passed: bool = True,
        target_match_detail: str = "",
    ) -> dict[str, Any]:
        result = _parse(run.get("result"), dict)
        auth = _run_http_auth(run)
        if passed:
            status = "done"
        elif run:
            status = "warning"
        else:
            status = "missing"
        detail = _string_from(run.get("error")) or _string_from(result.get("error"))
        if (
            not detail
            and provider_surface_detail
            and run
            and _run_processed(run) > 0
            and _run_failed_count(run) == 0
            and not _smoke_uses_provider_surface(run)
        ):
            detail = provider_surface_detail
        if not detail and issue_required and run and not _run_issue_id(run):
            detail = "Smoke run did not record a created ticket"
        if not detail and reply_required and run and not _run_reply_id(run):
            detail = "Lifecycle smoke did not record an approved reply"
        if not detail and provider_message_required and run and not _run_provider_message_id(run):
            detail = "Provider delivery did not record a provider message ID"
        if not detail and provider_delivery_proof_required and run and not _run_has_provider_delivery_proof(run):
            detail = _provider_delivery_proof_detail(run)
        if not detail and target_match_required and run and not target_match_passed:
            detail = target_match_detail or "Smoke run target does not match current live proof target"
        if not detail and attachment_only_required and run and not _run_has_attachment_only_proof(run):
            detail = "Lifecycle smoke did not prove an attachment-only inbound message"
        if not detail and run and not _run_has_signature_auth(run, signature_auth_mode_required):
            detail = _required_auth_mode_detail(signature_auth_mode_required)
        if not detail and timestamp_auth_required and run and not _run_has_timestamp_auth(run):
            detail = "Smoke run did not record timestamp-bound HMAC auth"
        if not detail and key == "provider_validation" and run:
            provider_validation = _parse(result.get("providerValidation"), dict)
            detail = _string_from(provider_validation.get("detail"))
        if not detail and run:
            detail = f"{_string_from(run.get('status')) or 'unknown'}: {_run_processed(run)} processed, {_run_failed_count(run)} failed"
        if not detail:
            detail = missing_detail
        return {
            "key": key,
            "label": label,
            "status": status,
            "detail": detail,
            "runId": _string_from(run.get("id")),
            "source": _string_from(run.get("source")),
            "runStatus": _string_from(run.get("status")),
            "processed": _run_processed(run),
            "failed": _run_failed_count(run),
            "sent": _run_sent_count(run),
            "startedAt": _run_time(run),
            "transport": _smoke_transport(run),
            "providerMessageId": _run_provider_message_id(run),
            "deliveryRoute": _run_delivery_route(run),
            "providerResponse": _run_provider_response(run),
            "attachmentCount": _run_attachment_count(run),
            "fileOnly": _run_file_only(run),
            "authMode": _string_from(auth.get("mode")),
            "signatureTimestampHeader": _string_from(auth.get("timestampHeader") or auth.get("timestamp_header")),
            "issueId": _run_issue_id(run),
            "replyId": _run_reply_id(run),
        }

    def _web_chat_session_check(session: dict[str, Any]) -> dict[str, Any]:
        passed = _web_chat_session_success(session)
        if passed:
            status = "done"
        elif session:
            status = "warning"
        else:
            status = "missing"
        issue_id = _string_from(session.get("issue") or session.get("issueId"))
        session_id = _string_from(session.get("id"))
        session_status = _string_from(session.get("status"))
        if passed:
            detail = f"{session_status or 'active'} session linked to ticket {issue_id}"
        elif session:
            detail = "Latest web chat session is missing a linked ticket"
        else:
            detail = "Start hosted or embedded web chat to prove visitor messages create tickets"
        return {
            "key": "web_chat_session",
            "label": "Web chat session created",
            "status": status,
            "detail": detail,
            "runId": session_id,
            "sessionId": session_id,
            "source": "web_chat",
            "runStatus": session_status,
            "processed": 1 if session else 0,
            "failed": 0 if passed or not session else 1,
            "sent": 0,
            "startedAt": _string_from(
                session.get("lastMessageAt")
                or session.get("last_message_at")
                or session.get("created")
            ),
            "issueId": issue_id,
        }

    def _web_chat_delivery_check(message: dict[str, Any], session: dict[str, Any]) -> dict[str, Any]:
        passed = _web_chat_delivery_success(message)
        failed = _web_chat_delivery_failed(message)
        if passed:
            status = "done"
        elif message:
            status = "warning"
        else:
            status = "missing"
        metadata = _parse(message.get("metadata"), dict) if message else {}
        session_id = (
            _string_from(metadata.get("webChatSessionId") or metadata.get("web_chat_session_id"))
            or _string_from(session.get("id"))
        )
        issue_id = _string_from(message.get("issue") or message.get("issueId")) or _string_from(
            session.get("issue") or session.get("issueId")
        )
        message_status = _string_from(message.get("status"))
        provider_message_id = _string_from(message.get("provider_message_id") or message.get("providerMessageId"))
        if passed:
            detail = f"agent reply delivered to ticket {issue_id}"
        elif message:
            detail = _string_from(message.get("error")) or f"{message_status or 'unknown'}: reply not delivered to web chat"
        else:
            detail = "Send an Inbox web chat reply to prove replies reach visitors"
        return {
            "key": "web_chat_delivery",
            "label": "Web chat reply delivered",
            "status": status,
            "detail": detail,
            "runId": _string_from(message.get("id")) if message else "",
            "sessionId": session_id,
            "source": "web_chat",
            "runStatus": message_status,
            "processed": 1 if message else 0,
            "failed": 1 if failed else 0,
            "sent": 1 if passed else 0,
            "startedAt": _string_from(
                message.get("sent_at")
                or message.get("sentAt")
                or message.get("updated")
                or message.get("created")
            ),
            "provider": _string_from(message.get("provider")) if message else "",
            "providerMessageId": provider_message_id,
            "issueId": issue_id,
        }

    def _channel_autopilot_event_for_channel(channel: dict[str, Any]) -> dict[str, Any]:
        channel_id = _string_from(channel.get("id"))
        if channel_id and channel_id in latest_autopilot_by_channel_id:
            return latest_autopilot_by_channel_id[channel_id]
        channel_key = _channel_record_key(channel)
        if channel_key and channel_key in latest_autopilot_by_channel_key:
            return latest_autopilot_by_channel_key[channel_key]
        return {}

    def _channel_autopilot_check(channel: dict[str, Any]) -> dict[str, Any]:
        event = _channel_autopilot_event_for_channel(channel)
        passed = _channel_autopilot_event_success(event)
        if passed:
            status = "done"
        elif event:
            status = "warning"
        else:
            status = "missing"
        reply_id = _channel_autopilot_reply_id(event)
        ai_run_id = _channel_autopilot_ai_run_id(event)
        issue_id = _string_from(event.get("issue") or event.get("issueId"))
        if passed:
            detail = f"Agent prepared triage, fields, and draft {reply_id} for ticket {issue_id or 'unknown'}"
        elif event:
            gaps = _channel_autopilot_package_gaps(event)
            if not (reply_id and ai_run_id):
                detail = "Autopilot event did not record reply and AI run IDs"
            elif not _channel_autopilot_actions(event):
                detail = "Autopilot event did not prove triage, field, and reply prep actions"
            else:
                detail = f"Autopilot prep package incomplete: {', '.join(gaps)}"
        else:
            detail = "Create a ticket through this channel so channel autopilot prepares triage, fields, and an approval draft"
        return {
            "key": "channel_autopilot",
            "label": "Channel autopilot prep proof",
            "status": status,
            "detail": detail,
            "runId": _string_from(event.get("id")),
            "source": "channel_autopilot",
            "runStatus": "prepared" if passed else "missing",
            "processed": 1 if event else 0,
            "failed": 0 if passed else 1,
            "sent": 0,
            "startedAt": _string_from(event.get("occurred_at") or event.get("created")),
            "transport": "",
            "providerMessageId": "",
            "issueId": issue_id,
            "replyId": reply_id,
            "aiRunId": ai_run_id,
        }

    def _channel_webhook_event_result(event: dict[str, Any]) -> dict[str, Any]:
        return _parse(event.get("result"), dict)

    def _channel_webhook_issue_id(event: dict[str, Any]) -> str:
        result = _channel_webhook_event_result(event)
        issue_id = _string_from(result.get("issueId") or result.get("issue_id"))
        if issue_id:
            return issue_id
        for item in _parse(result.get("items"), list):
            if isinstance(item, dict):
                issue_id = _string_from(item.get("issueId") or item.get("issue_id"))
                if issue_id:
                    return issue_id
        return ""

    def _channel_webhook_event_channel_id(event: dict[str, Any]) -> str:
        return _string_from(event.get("channel") or event.get("channelId") or event.get("channel_id"))

    def _channel_webhook_event_for_channel(channel: dict[str, Any]) -> dict[str, Any]:
        channel_id = _string_from(channel.get("id"))
        for event in channel_webhook_events:
            if _channel_webhook_event_channel_id(event) != channel_id:
                continue
            if _string_from(event.get("status")).lower() not in {"processed", "success"}:
                continue
            result = _channel_webhook_event_result(event)
            if _string_from(result.get("kind")) != "inbound_message":
                continue
            if _channel_webhook_issue_id(event):
                return event
        return {}

    def _channel_webhook_provider_message_id(event: dict[str, Any]) -> str:
        return _string_from(event.get("provider_message_id") or event.get("providerMessageId"))

    def _channel_webhook_inbound_check(channel: dict[str, Any]) -> dict[str, Any] | None:
        event = _channel_webhook_event_for_channel(channel)
        if not event:
            return None
        issue_id = _channel_webhook_issue_id(event)
        return {
            "key": "inbound_ticket_event",
            "label": "Provider message created ticket",
            "status": "done",
            "detail": "A provider webhook message created a support ticket",
            "runId": _string_from(event.get("id")),
            "source": "provider-webhook",
            "runStatus": _string_from(event.get("status")),
            "processed": 1,
            "failed": 0,
            "sent": 0,
            "startedAt": _string_from(event.get("received_at") or event.get("receivedAt") or event.get("created")),
            "transport": "webhook",
            "provider": _string_from(event.get("provider")),
            "providerMessageId": _channel_webhook_provider_message_id(event),
            "issueId": issue_id,
            "replyId": "",
        }

    def _real_channel_handoff_check(
        inbound_check: dict[str, Any] | None,
        autopilot_check: dict[str, Any] | None,
    ) -> dict[str, Any] | None:
        if not inbound_check or not autopilot_check:
            return None
        issue_id = _string_from(inbound_check.get("issueId"))
        if (
            not issue_id
            or _string_from(autopilot_check.get("issueId")) != issue_id
            or _string_from(autopilot_check.get("status")) != "done"
            or not _string_from(autopilot_check.get("replyId"))
        ):
            return None
        return {
            "key": "real_channel_handoff",
            "label": "Real channel handoff proof",
            "status": "done",
            "detail": "Real provider message created a ticket and channel autopilot prepared the approval draft",
            "runId": _string_from(autopilot_check.get("runId") or inbound_check.get("runId")),
            "source": "provider-webhook",
            "runStatus": "prepared",
            "processed": 1,
            "failed": 0,
            "sent": 0,
            "startedAt": _string_from(inbound_check.get("startedAt") or autopilot_check.get("startedAt")),
            "transport": _string_from(inbound_check.get("transport")) or "webhook",
            "provider": _string_from(inbound_check.get("provider")),
            "providerMessageId": _string_from(inbound_check.get("providerMessageId")),
            "issueId": issue_id,
            "replyId": _string_from(autopilot_check.get("replyId")),
            "aiRunId": _string_from(autopilot_check.get("aiRunId")),
        }

    def _outbound_message_metadata(message: dict[str, Any]) -> dict[str, Any]:
        return _parse(message.get("metadata"), dict)

    def _outbound_issue_id(message: dict[str, Any]) -> str:
        return _string_from(message.get("issue") or message.get("issueId"))

    def _outbound_message_id(message: dict[str, Any]) -> str:
        return _string_from(message.get("id"))

    def _outbound_provider_message_id(message: dict[str, Any]) -> str:
        metadata = _outbound_message_metadata(message)
        receipt = _parse(metadata.get("deliveryReceipt") or metadata.get("delivery_receipt"), dict)
        return _string_from(
            message.get("provider_message_id")
            or message.get("providerMessageId")
            or metadata.get("providerMessageId")
            or metadata.get("provider_message_id")
            or receipt.get("providerMessageId")
            or receipt.get("provider_message_id")
        )

    def _outbound_delivery_route(message: dict[str, Any]) -> dict[str, Any]:
        metadata = _outbound_message_metadata(message)
        route = metadata.get("deliveryRoute") or metadata.get("delivery_route")
        return route if isinstance(route, dict) else {}

    def _outbound_provider_response(message: dict[str, Any]) -> dict[str, Any]:
        metadata = _outbound_message_metadata(message)
        response = metadata.get("providerResponse") or metadata.get("provider_response")
        return response if isinstance(response, dict) else {}

    def _outbound_reply_approval_event(message: dict[str, Any]) -> dict[str, Any]:
        message_id = _outbound_message_id(message)
        issue_id = _outbound_issue_id(message)
        if not message_id or not issue_id:
            return {}
        for event in issue_events:
            if _string_from(event.get("event_type") or event.get("eventType")) != "reply_approved":
                continue
            if _string_from(event.get("issue") or event.get("issueId")) not in {"", issue_id}:
                continue
            metadata = _parse(event.get("metadata"), dict)
            if _string_from(metadata.get("replyId") or metadata.get("reply_id")) == message_id:
                return event
        return {}

    def _outbound_approval_context(message: dict[str, Any]) -> dict[str, str]:
        metadata = _outbound_message_metadata(message)
        approved_by = _string_from(metadata.get("approvedBy") or metadata.get("approved_by"))
        approved_at = _string_from(metadata.get("approvedAt") or metadata.get("approved_at"))
        review_status = _string_from(metadata.get("reviewStatus") or metadata.get("review_status")).lower()
        metadata_approved = metadata.get("approved") is True or review_status == "approved"
        metadata_human_approved = (
            metadata.get("humanApproved") is True
            or metadata.get("human_approved") is True
            or _string_from(metadata.get("approvalSource") or metadata.get("approval_source")) == "human_review"
        )
        if metadata_approved and metadata_human_approved and approved_by:
            return {
                "approvedBy": approved_by,
                "approvedAt": approved_at,
                "approvalSource": _string_from(metadata.get("approvalSource") or metadata.get("approval_source")) or "reply_metadata",
                "approvalEventId": "",
            }
        event = _outbound_reply_approval_event(message)
        if not event:
            return {}
        event_metadata = _parse(event.get("metadata"), dict)
        event_approved_by = _string_from(
            event_metadata.get("approvedBy")
            or event_metadata.get("approved_by")
            or event.get("actor_email")
            or event.get("actorEmail")
        )
        if not event_approved_by:
            return {}
        return {
            "approvedBy": event_approved_by,
            "approvedAt": _string_from(
                event_metadata.get("approvedAt")
                or event_metadata.get("approved_at")
                or event.get("occurred_at")
                or event.get("occurredAt")
                or event.get("created")
            ),
            "approvalSource": "reply_approved_event",
            "approvalEventId": _string_from(event.get("id")),
        }

    def _outbound_channel_key(message: dict[str, Any]) -> str:
        metadata = _outbound_message_metadata(message)
        return _reply_channel_key_from_source(
            metadata.get("channelKey")
            or metadata.get("channel_key")
            or metadata.get("issueSource")
            or metadata.get("issue_source")
        )

    def _outbound_channel_matches(channel: dict[str, Any], message: dict[str, Any]) -> bool:
        channel_type = _string_from(channel.get("type")).lower()
        channel_key = _channel_record_key(channel)
        message_channel = _string_from(message.get("channel")).lower()
        message_channel_key = _outbound_channel_key(message)
        if channel_type and message_channel == channel_type:
            return True
        if channel_key and message_channel_key == channel_key:
            return True
        if channel_type and message_channel_key == channel_type:
            return True
        route = _outbound_delivery_route(message)
        route_channel = _string_from(route.get("channel")).lower()
        route_provider = _string_from(route.get("provider")).lower()
        return bool(channel_type and channel_type in {route_channel, route_provider})

    def _real_channel_reply_message(channel: dict[str, Any], issue_id: str) -> dict[str, Any]:
        if not issue_id:
            return {}
        for message in outbound_messages:
            if _outbound_issue_id(message) != issue_id:
                continue
            if _string_from(message.get("status")).lower() != "sent":
                continue
            if not _outbound_provider_message_id(message):
                continue
            if not _outbound_channel_matches(channel, message):
                continue
            return message
        return {}

    def _real_channel_human_approved_reply_message(channel: dict[str, Any], issue_id: str) -> dict[str, Any]:
        if not issue_id:
            return {}
        for message in outbound_messages:
            if _outbound_issue_id(message) != issue_id:
                continue
            if _string_from(message.get("status")).lower() != "sent":
                continue
            if not _outbound_provider_message_id(message):
                continue
            if not _outbound_channel_matches(channel, message):
                continue
            if not _outbound_approval_context(message):
                continue
            return message
        return {}

    def _real_channel_reply_check(
        channel: dict[str, Any],
        inbound_check: dict[str, Any] | None,
        autopilot_check: dict[str, Any] | None,
    ) -> dict[str, Any] | None:
        if not inbound_check:
            return None
        issue_id = _string_from(inbound_check.get("issueId"))
        message = _real_channel_reply_message(channel, issue_id)
        if not message:
            return None
        delivery_route = _outbound_delivery_route(message)
        return {
            "key": "real_channel_reply",
            "label": "Real app reply delivered",
            "status": "done",
            "detail": "Real provider ticket was answered from the app through channel delivery",
            "runId": _outbound_message_id(message),
            "source": "app-reply",
            "runStatus": "sent",
            "processed": 1,
            "failed": 0,
            "sent": 1,
            "startedAt": _string_from(
                message.get("sent_at")
                or message.get("sentAt")
                or message.get("updated")
                or message.get("created")
            ),
            "transport": _string_from(delivery_route.get("transport")),
            "provider": _string_from(message.get("provider")),
            "providerMessageId": _outbound_provider_message_id(message),
            "inboundProviderMessageId": _string_from(inbound_check.get("providerMessageId")),
            "deliveryRoute": delivery_route,
            "providerResponse": _outbound_provider_response(message),
            "issueId": issue_id,
            "replyId": _outbound_message_id(message),
            "aiRunId": (
                _string_from(autopilot_check.get("aiRunId"))
                if autopilot_check and _string_from(autopilot_check.get("issueId")) == issue_id
                else ""
            ),
        }

    def _human_approved_real_channel_reply_check(
        channel: dict[str, Any],
        inbound_check: dict[str, Any] | None,
        autopilot_check: dict[str, Any] | None,
    ) -> dict[str, Any] | None:
        if not inbound_check:
            return None
        issue_id = _string_from(inbound_check.get("issueId"))
        message = _real_channel_human_approved_reply_message(channel, issue_id)
        if not message:
            return None
        approval = _outbound_approval_context(message)
        if not approval:
            return None
        delivery_route = _outbound_delivery_route(message)
        ai_run_id = (
            _string_from(autopilot_check.get("aiRunId"))
            if autopilot_check and _string_from(autopilot_check.get("issueId")) == issue_id
            else ""
        )
        return {
            "key": "human_approved_real_channel_reply",
            "label": "Human-approved channel reply",
            "status": "done",
            "detail": "Agent draft was approved by a human and delivered through the real provider channel",
            "runId": _outbound_message_id(message),
            "source": "human-approval",
            "runStatus": "sent",
            "processed": 1,
            "failed": 0,
            "sent": 1,
            "startedAt": _string_from(
                message.get("sent_at")
                or message.get("sentAt")
                or message.get("updated")
                or message.get("created")
            ),
            "transport": _string_from(delivery_route.get("transport")),
            "provider": _string_from(message.get("provider")),
            "providerMessageId": _outbound_provider_message_id(message),
            "inboundProviderMessageId": _string_from(inbound_check.get("providerMessageId")),
            "deliveryRoute": delivery_route,
            "providerResponse": _outbound_provider_response(message),
            "issueId": issue_id,
            "replyId": _outbound_message_id(message),
            "aiRunId": ai_run_id,
            "approvedBy": approval.get("approvedBy", ""),
            "approvedAt": approval.get("approvedAt", ""),
            "approvalSource": approval.get("approvalSource", ""),
            "approvalEventId": approval.get("approvalEventId", ""),
        }

    def _real_channel_evidence_checks(channel: dict[str, Any]) -> list[dict[str, Any]]:
        inbound_check = _channel_webhook_inbound_check(channel)
        autopilot_check = _channel_autopilot_check(channel) if _channel_auto_prepare_enabled(channel) else None
        human_approved_reply_check = _human_approved_real_channel_reply_check(channel, inbound_check, autopilot_check)
        handoff_check = _real_channel_handoff_check(inbound_check, autopilot_check)
        reply_check = _real_channel_reply_check(channel, inbound_check, autopilot_check)
        return [item for item in (human_approved_reply_check, reply_check, handoff_check, inbound_check) if item]

